-- Schema for Domain: security | Business: Sports Entertainment | Version: v1_ecm
-- Generated on: 2026-05-09 01:42:58

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `sports_entertainment_ecm`.`security` COMMENT 'Event security and physical safety operations domain managing credentialing, access control zones, surveillance systems, crowd management protocols, emergency response plans, and law enforcement coordination for all Sports Entertainment venues and events.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`credential` (
    `credential_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for each security credential record. Primary key for the credential master table — SSOT for credential identity across all access control operations.',
    `production_id` BIGINT COMMENT 'Foreign key linking to broadcast.production. Business justification: Media credentials are issued to broadcast production personnel (OB crews, commentators, camera operators) for specific productions. Accreditation workflows in sports broadcasting require linking each ',
    `contingent_worker_id` BIGINT COMMENT 'Foreign key linking to workforce.contingent_worker. Business justification: Broadcast crew, event staff, and vendor workers are contingent workers who receive venue credentials. The credential table already links to employee via holder_employee_id but has no FK for contingent',
    `credential_employee_id` BIGINT COMMENT 'Reference to the internal system user (security administrator or credentialing officer) who issued this credential. Supports chain-of-custody audit trail and accountability for credential issuance.',
    `credential_holder_employee_id` BIGINT COMMENT 'Reference to the person record (workforce member, athlete, contractor, media representative, or VIP guest) to whom this credential is issued. Links credential to the holders identity in the relevant party master.',
    `credential_revoked_by_user_employee_id` BIGINT COMMENT 'Reference to the internal system user (security administrator) who executed the revocation action. Supports chain-of-custody audit trail. Null if credential has not been revoked.',
    `eligibility_status_id` BIGINT COMMENT 'Foreign key linking to athlete.eligibility_status. Business justification: Athlete credential issuance requires eligibility verification — a suspended or ineligible athlete must not receive a valid game-day credential. This link enables automated eligibility checks during cr',
    `employee_certification_id` BIGINT COMMENT 'Foreign key linking to workforce.employee_certification. Business justification: Credential issuance in sports venues requires verifying the holders underlying certification (e.g., security license, first-aid cert). Accreditation teams must confirm employee_certification before i',
    `employee_id` BIGINT COMMENT 'Reference to the person record (workforce member, athlete, contractor, media representative, or VIP guest) to whom this credential is issued. Links credential to the holders identity in the relevant party master.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the specific event for which this credential is valid, if the credential is event-scoped rather than season- or venue-scoped. Null for standing/permanent credentials valid across all events at a venue.',
    `fixture_id` BIGINT COMMENT 'Reference to the specific event for which this credential is valid, if the credential is event-scoped rather than season- or venue-scoped. Null for standing/permanent credentials valid across all events at a venue.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Credentials are issued to franchise staff, team personnel, and media. Franchise-level credential issuance audits, access control compliance reporting, and league credentialing reviews require linking ',
    `hospitality_entitlement_id` BIGINT COMMENT 'Foreign key linking to sponsorship.hospitality_entitlement. Business justification: Sponsor hospitality entitlements (VIP suite, field-level passes) are fulfilled by issuing security credentials to sponsor guests. Security staff verify credentials against the authorizing entitlement ',
    `issued_by_user_employee_id` BIGINT COMMENT 'Reference to the internal system user (security administrator or credentialing officer) who issued this credential. Supports chain-of-custody audit trail and accountability for credential issuance.',
    `revoked_by_user_employee_id` BIGINT COMMENT 'Reference to the internal system user (security administrator) who executed the revocation action. Supports chain-of-custody audit trail. Null if credential has not been revoked.',
    `season_id` BIGINT COMMENT 'Reference to the league season or tournament for which this credential is valid when multi_event_flag is True. Null for single-event credentials.',
    `venue_id` BIGINT COMMENT 'Reference to the venue at which this credential grants access. For multi-venue credentials, this references the primary or home venue; access to additional venues is managed via the access zone configuration.',
    `reissued_from_credential_id` BIGINT COMMENT 'Self-referencing FK on credential (reissued_from_credential_id)',
    `access_tier` STRING COMMENT 'Hierarchical access level granted by this credential, defining which physical zones the holder may enter. Values: field_level (playing surface and sidelines), locker_room (team areas), press_box (media and broadcast areas), general_operations (back-of-house operations), vip_suite (premium hospitality areas), restricted_zone (security command, broadcast infrastructure). [ENUM-REF-CANDIDATE: field_level|locker_room|press_box|general_operations|vip_suite|restricted_zone|medical_area|broadcast_compound — promote to reference product]. Valid values are `field_level|locker_room|press_box|general_operations|vip_suite|restricted_zone`',
    `access_zone_list` STRING COMMENT 'Comma-delimited list of specific zone codes within the venue that this credential authorizes entry to (e.g., Z01,Z04,Z07,Z12). Complements access_tier with granular zone-level control as configured in the access control system.',
    `accreditation_body` STRING COMMENT 'Name of the external governing body or league office that accredited this credential (e.g., FIFA Accreditation Centre, NFL League Office, IOC Media Accreditation). Relevant for media passes and law enforcement credentials requiring external validation.',
    `accreditation_reference` STRING COMMENT 'External reference number or accreditation ID assigned by the governing body or league office (e.g., FIFA accreditation number, IOC media pass number). Used for cross-referencing with external accreditation systems.',
    `background_check_date` DATE COMMENT 'Date on which the background check for this credential holder was completed and a determination was made. Used to assess recency of screening and trigger renewal workflows.',
    `background_check_status` STRING COMMENT 'Status of the background screening conducted on the credential holder prior to issuance. Classified as confidential business-sensitive data. Values: cleared (passed), pending (in progress), failed (did not pass), waived (exempted by policy), not_required (credential type exempt).. Valid values are `cleared|pending|failed|waived|not_required`',
    `barcode_value` DECIMAL(18,2) COMMENT 'Encoded barcode string (1D or 2D/QR) printed on or embedded in the credential, scanned at access control checkpoints. Classified as confidential as it is the operational key for physical access. Managed in alignment with Ticketmaster/AXS access control systems.',
    `biometric_linked` BOOLEAN COMMENT 'Indicates whether this credential has been linked to a biometric profile (e.g., fingerprint, facial recognition) for enhanced identity verification at high-security access points. True = biometric data is enrolled and active for this credential.',
    `biometric_type` STRING COMMENT 'Type of biometric modality enrolled for this credential when biometric_linked is True. Classified as restricted PII/biometric per GDPR Article 9 and CCPA. Values: fingerprint, facial_recognition, iris_scan, palm_vein, none.. Valid values are `fingerprint|facial_recognition|iris_scan|palm_vein|none`',
    `color_code` STRING COMMENT 'Hex color code representing the physical color of the credential lanyard or card stock, used for rapid visual identification of access tier by security staff at checkpoints (e.g., #FF0000 for red = restricted zone, #00FF00 for green = general operations).. Valid values are `^#[0-9A-Fa-f]{6}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this credential record was first created in the system. Supports audit trail, chain-of-custody tracking, and compliance reporting. Conforms to ISO 8601 format yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `credential_number` STRING COMMENT 'Externally visible, human-readable credential identifier printed on the physical badge or encoded in the digital pass (e.g., CRED-STAFF-000123). Used by security personnel and access control systems to reference a specific credential without exposing the internal surrogate key.. Valid values are `^CRED-[A-Z]{2,6}-[0-9]{6,10}$`',
    `credential_status` STRING COMMENT 'Current lifecycle state of the credential. active: valid and in use; suspended: temporarily deactivated (e.g., investigation); revoked: permanently cancelled; expired: past validity end date; pending_activation: issued but not yet activated; lost_stolen: reported missing and deactivated for security.. Valid values are `active|suspended|revoked|expired|pending_activation|lost_stolen`',
    `credential_type` STRING COMMENT 'Classification of the credential by the category of holder and access purpose. Drives access tier rules and issuance workflows. Values: staff_badge (venue/event staff), media_pass (accredited press/broadcast), vip_access_card (VIP guests and sponsors), contractor_id (third-party contractors), law_enforcement (police/security agencies), athlete_team (players, coaches, team officials).. Valid values are `staff_badge|media_pass|vip_access_card|contractor_id|law_enforcement|athlete_team`',
    `emergency_contact_name` STRING COMMENT 'Full name of the emergency contact person for the credential holder, used by venue medical and security staff in the event of an incident. Classified as restricted PII per GDPR and CCPA.',
    `emergency_contact_phone` STRING COMMENT 'Phone number of the emergency contact person for the credential holder. Classified as restricted PII per GDPR and CCPA. Used by venue medical and security staff in emergency situations.. Valid values are `^+?[0-9s-().]{7,20}$`',
    `escort_required` BOOLEAN COMMENT 'Indicates whether the credential holder must be accompanied by an authorized escort when accessing certain zones. True = escort is mandatory. Used for contractor and visitor credentials in high-security areas.',
    `holder_name` STRING COMMENT 'Full legal name of the individual to whom the credential is issued, as printed on the physical credential. Retained for operational verification by security personnel at access points. Classified as restricted PII per GDPR and CCPA.',
    `holder_organization` STRING COMMENT 'Name of the organization, team, media outlet, agency, or employer that the credential holder represents (e.g., ESPN, Dallas Cowboys, ABC Security Services). Used for affiliation-based access grouping and sponsor/partner credential management.',
    `holder_role` STRING COMMENT 'Functional role or job title of the credential holder within the event or venue context (e.g., Head Coach, Camera Operator, Paramedic, Venue Director). Informs access tier assignment and is displayed on the physical credential.',
    `issued_date` DATE COMMENT 'Calendar date on which the credential was physically produced and issued to the holder. Distinct from valid_from (when access begins) — a credential may be issued days before it becomes active.',
    `issuing_authority` STRING COMMENT 'Name of the organizational unit or external body responsible for issuing and authorizing this credential (e.g., NFL Security Office, FIFA Accreditation Centre, Venue Security Manager). Establishes chain-of-custody accountability.',
    `issuing_authority_code` STRING COMMENT 'Standardized short code identifying the issuing authority (e.g., NFL_SEC, FIFA_ACC, VENUE_MGR). Used for system-level filtering and reporting across multi-league or multi-event deployments.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency represented by the credential holder (e.g., NYPD, FBI, US Secret Service). Populated only for credential_type = law_enforcement. Used for coordination with venue security command.',
    `law_enforcement_badge_number` STRING COMMENT 'Official badge or shield number of the law enforcement officer, used to verify identity against agency records. Classified as confidential. Populated only for credential_type = law_enforcement.',
    `multi_event_flag` BOOLEAN COMMENT 'Indicates whether this credential is valid across multiple events (e.g., a season-long staff badge or a tournament-wide media pass) rather than a single event. True = valid for multiple events within the validity period.',
    `photo_url` STRING COMMENT 'Secure URL pointing to the credential holders photograph stored in the Digital Asset Management (DAM) system, used for visual identity verification by security personnel. Classified as restricted biometric PII per GDPR Article 9.',
    `print_template_code` STRING COMMENT 'Code referencing the physical credential print template used for this credential type (e.g., TMPL-MEDIA-2024, TMPL-STAFF-VIP). Determines layout, branding, and security features printed on the badge.',
    `revocation_date` DATE COMMENT 'Date on which the credential was revoked or suspended. Populated only when credential_status is revoked, suspended, or lost_stolen. Part of the chain-of-custody audit trail.',
    `revocation_reason` STRING COMMENT 'Reason code explaining why the credential was revoked or suspended. Supports security incident analysis and compliance reporting. Values: lost, stolen, employment_terminated, event_concluded, policy_violation, voluntary_surrender, duplicate_issued. [ENUM-REF-CANDIDATE: lost|stolen|employment_terminated|event_concluded|policy_violation|voluntary_surrender|duplicate_issued — 7 candidates stripped; promote to reference product]',
    `rfid_tag_code` STRING COMMENT 'Unique identifier of the RFID chip embedded in the credential card or wristband, used for contactless access control scanning. Classified as confidential as it is a physical access key. Null if the credential does not use RFID technology.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this credential record originated (e.g., TICKETMASTER_AXS for access control credentials, ARCHTICS for venue-managed credentials, MANUAL_ENTRY for credentials issued outside automated systems). Supports data lineage in the Databricks Silver Layer.. Valid values are `TICKETMASTER_AXS|ARCHTICS|SALESFORCE_CRM|SAP_S4HANA|MANUAL_ENTRY`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this credential record. Used for change tracking, audit trail, and incremental data pipeline processing in the Databricks Silver Layer.',
    `valid_until` DATE COMMENT 'Date on which the credential expires and access is automatically revoked. For event credentials, typically the day after the event concludes. For season credentials, the last day of the season. Null indicates an open-ended standing credential subject to manual review.',
    `vehicle_access_flag` BOOLEAN COMMENT 'Indicates whether this credential also grants vehicle access to restricted parking or loading dock areas at the venue. True = vehicle access is authorized in addition to pedestrian access.',
    `vehicle_plate_number` STRING COMMENT 'License plate number of the vehicle authorized for venue access under this credential when vehicle_access_flag is True. Classified as confidential. Null if vehicle access is not granted.',
    `valid_from` DATE COMMENT 'Date from which the credential becomes active and grants access. For event credentials, typically the event setup/load-in date. For season credentials, the first day of the season.',
    CONSTRAINT pk_credential PRIMARY KEY(`credential_id`)
) COMMENT 'Master record for all security credentials issued to personnel operating at Sports Entertainment venues and events — staff badges, media passes, VIP access cards, contractor IDs, law enforcement credentials, and athlete/team credentials. Captures credential type, holder identity reference, issuing authority, validity period, access tier, biometric linkage flag, barcode/RFID identifier, revocation status, and chain-of-custody audit fields. SSOT for credential identity across all access control operations.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`access_zone` (
    `access_zone_id` BIGINT COMMENT 'Unique surrogate identifier for each physical access control zone record within the Sports Entertainment security master catalog.',
    `facility_id` BIGINT COMMENT 'FK to venue.facility.facility_id — Security zones must be linked to their physical venue facility for operational deployment planning and zone-to-venue mapping.',
    `venue_id` BIGINT COMMENT 'Reference to the parent venue where this access zone is physically located. Used to scope zone records to a specific Sports Entertainment facility.',
    `parent_access_zone_id` BIGINT COMMENT 'Self-referencing FK on access_zone (parent_access_zone_id)',
    `access_close_time` TIMESTAMP COMMENT 'Standard time of day (HH:MM, 24-hour format) at which access to this zone closes relative to event day operations (e.g., 23:59 for post-event lockdown). Used for access control system scheduling and security staffing deployment.',
    `access_control_system` STRING COMMENT 'Name or type of the electronic access control system managing entry/exit to this zone (e.g., Ticketmaster/AXS turnstile, Lenel, C-Cure, Genetec, Honeywell, manual staffed checkpoint, or none). Determines integration points for real-time access event logging. [ENUM-REF-CANDIDATE: ticketmaster_axs|lenel|ccure|genetec|honeywell|manual|none — 7 candidates stripped; promote to reference product]',
    `access_open_time` TIMESTAMP COMMENT 'Standard time of day (HH:MM, 24-hour format) at which access to this zone opens relative to event day operations (e.g., 06:00 for early crew access). Used for access control system scheduling and security staffing deployment.',
    `ada_accessible_flag` BOOLEAN COMMENT 'Indicates whether the access zone meets ADA accessibility requirements including wheelchair access, accessible entry/exit points, and compliant pathways (True = ADA compliant, False = not compliant or not assessed). Required for ADA regulatory reporting.',
    `adjacent_zone_codes` STRING COMMENT 'Comma-separated list of zone_codes for physically adjacent access zones sharing a boundary or transition point with this zone. Used for crowd flow modeling, spillover risk assessment, and emergency egress path analysis. Note: a dedicated zone_adjacency junction product should be used for full relational modeling.',
    `alcohol_permitted_flag` BOOLEAN COMMENT 'Indicates whether alcohol consumption and/or service is permitted within this zone (True = permitted, False = not permitted). Used for concession operations planning, liquor licensing compliance, and fan experience management.',
    `broadcast_zone_flag` BOOLEAN COMMENT 'Indicates whether this zone is designated as a broadcast or media production area (True = broadcast zone, False = non-broadcast). Triggers media credential requirements and coordination with broadcast operations teams and OB (Outside Broadcast) units.',
    `camera_count` STRING COMMENT 'Number of surveillance cameras installed and actively monitoring the access zone. Used for security audit compliance, coverage gap analysis, and incident response planning.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this access zone record was first created in the system. Used for audit trail, data lineage, and compliance with SOX and GDPR record-keeping requirements.',
    `credential_type_required` STRING COMMENT 'Type of credential required for access to this zone (e.g., event_ticket, staff_badge, media_credential, vip_wristband, law_enforcement_id, biometric, all_access_pass). Drives credentialing issuance rules in Ticketmaster/AXS and physical security systems. [ENUM-REF-CANDIDATE: event_ticket|staff_badge|media_credential|vip_wristband|law_enforcement_id|biometric|all_access_pass|none — promote to reference product]',
    `effective_from_date` DATE COMMENT 'Date from which this access zone definition became operationally active and enforceable. Used for historical zone configuration tracking, audit trails, and compliance with venue certification requirements.',
    `effective_until_date` DATE COMMENT 'Date on which this access zone definition expires or is superseded. Null indicates the zone definition is currently open-ended and active. Used for zone lifecycle management and historical configuration auditing.',
    `emergency_assembly_point_flag` BOOLEAN COMMENT 'Indicates whether this zone serves as a designated emergency assembly or muster point during evacuation scenarios (True = designated assembly point, False = not designated). Used in emergency response plans and evacuation drills.',
    `entry_point_count` STRING COMMENT 'Number of physical entry points (gates, turnstiles, doors, checkpoints) providing access into this zone. Used for crowd flow throughput modeling, staffing calculations, and emergency egress planning.',
    `evacuation_route_code` STRING COMMENT 'Code identifying the primary designated evacuation route assigned to this zone in the venue emergency response plan. Used by security command center and first responders during emergency scenarios.. Valid values are `^[A-Z0-9_-]{1,15}$`',
    `exit_point_count` STRING COMMENT 'Number of physical exit points from this zone. Used for emergency evacuation planning, egress compliance with fire safety codes, and crowd flow modeling.',
    `floor_area_sqm` DECIMAL(18,2) COMMENT 'Physical floor area of the access zone measured in square metres. Used to calculate occupancy density ratios, crowd flow modeling, and compliance with safety regulations requiring minimum space per person.',
    `hvac_zone_reference` STRING COMMENT 'Reference code linking this access zone to the corresponding HVAC zone in the Building Management System (BMS). Used for environmental control coordination during events and emergency ventilation management.',
    `last_safety_inspection_date` DATE COMMENT 'Date of the most recent physical safety inspection conducted for this access zone by internal safety officers or external regulatory inspectors. Used for OSHA compliance tracking and venue certification renewals.',
    `law_enforcement_required_flag` BOOLEAN COMMENT 'Indicates whether sworn law enforcement officers are required to be stationed at or within this zone during events (True = required, False = not required). Used for event security planning, law enforcement coordination, and regulatory compliance.',
    `level_number` STRING COMMENT 'Numeric floor or level within the venue where the zone is located (e.g., 0 = ground/field level, 1 = concourse level, 2 = upper deck, -1 = sub-ground). Used for wayfinding, evacuation routing, and zone adjacency mapping.',
    `map_coordinates` STRING COMMENT 'Geographic or venue-relative coordinate string (e.g., GeoJSON polygon or venue grid reference) defining the physical boundary of the zone on the venue floor plan. Used for digital venue mapping, crowd flow modeling, and real-time occupancy visualization.',
    `max_occupancy` STRING COMMENT 'Maximum number of persons permitted within the zone simultaneously as defined by fire safety codes, venue engineering assessments, and regulatory approvals. Used for crowd flow modeling, real-time occupancy monitoring, and ADA compliance reporting.',
    `min_security_staff_count` STRING COMMENT 'Minimum number of security personnel required to be deployed in this zone during an active event. Used for event staffing plans, security contractor scheduling, and compliance with venue safety regulations.',
    `next_safety_inspection_date` DATE COMMENT 'Scheduled date for the next mandatory safety inspection of this access zone. Used for compliance calendar management and proactive safety governance.',
    `notes` STRING COMMENT 'Free-text field for operational notes, special instructions, or temporary conditions relevant to this access zone (e.g., Temporary barrier installed for renovation, Law enforcement post required for playoff events). Used by security operations staff.',
    `re_entry_permitted_flag` BOOLEAN COMMENT 'Indicates whether credential holders who have exited this zone are permitted to re-enter during the same event (True = re-entry allowed, False = no re-entry). Drives access control system configuration in Ticketmaster/AXS.',
    `screening_protocol` STRING COMMENT 'Security screening method applied at entry points to this zone: none, visual_check, metal_detector, magnetometer, pat_down, full_search, or biometric_scan. Determines staffing requirements and equipment deployment for event security operations. [ENUM-REF-CANDIDATE: none|visual_check|metal_detector|magnetometer|pat_down|full_search|biometric_scan — 7 candidates stripped; promote to reference product]',
    `section_reference` STRING COMMENT 'Venue section or block designation within which the access zone falls (e.g., North Stand, Section 112, East Wing). Aligns with Archtics seating inventory and venue map coordinates for operational cross-referencing.',
    `smoking_permitted_flag` BOOLEAN COMMENT 'Indicates whether smoking is permitted within this zone (True = permitted, False = not permitted). Used for venue policy enforcement, health and safety compliance, and fan experience communications.',
    `surveillance_coverage_flag` BOOLEAN COMMENT 'Indicates whether the access zone is covered by CCTV or other surveillance systems (True = covered, False = not covered). Critical for security planning, incident investigation, and compliance with venue safety regulations.',
    `time_restricted_flag` BOOLEAN COMMENT 'Indicates whether access to this zone is restricted to specific time windows during an event (True = time-restricted, False = open throughout event). When True, access_open_time and access_close_time define the permitted window.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this access zone record was most recently modified. Used for change tracking, audit trail, and data freshness monitoring in the Databricks Silver Layer.',
    `vip_flag` BOOLEAN COMMENT 'Indicates whether this zone is designated as a VIP hospitality or premium access area (True = VIP zone, False = standard zone). Drives premium credentialing rules, enhanced security protocols, and sponsor/partner access management.',
    `zone_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the access zone within a venue (e.g., FIELD-01, PRESS-BOX-A, VIP-SUITE-N). Used on credentials, wristbands, and access control hardware programming.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `zone_color_code` STRING COMMENT 'Hexadecimal color code used to visually represent this zone on venue maps, security dashboards, and credentialing systems (e.g., #FF0000 for red restricted zones, #00FF00 for public green zones). Standardizes visual communication across security operations.. Valid values are `^#[0-9A-Fa-f]{6}$`',
    `zone_description` STRING COMMENT 'Free-text narrative description of the access zone including its physical characteristics, operational purpose, notable features, and any special access conditions not captured in structured fields. Used for security briefings and operational documentation.',
    `zone_name` STRING COMMENT 'Human-readable descriptive name of the access zone (e.g., Field Level / Pitch Side, Home Team Locker Room, Broadcast Compound, VIP Hospitality Suite North). Used in operational reports and credentialing systems.',
    `zone_status` STRING COMMENT 'Current operational lifecycle status of the access zone: active (in normal use), inactive (temporarily disabled), under_maintenance (physical works in progress), decommissioned (permanently retired), temporary (event-specific pop-up zone). Drives whether the zone is enforced in access control systems.. Valid values are `active|inactive|under_maintenance|decommissioned|temporary`',
    `zone_tier` STRING COMMENT 'Security classification tier of the zone defining the baseline access control level: public (general admission concourse), restricted (credentialed staff/media), secured (law enforcement / command), sterile (field/pitch/locker room — highest protection). Drives credentialing rules and screening protocols.. Valid values are `public|restricted|secured|sterile`',
    `zone_type` STRING COMMENT 'Functional category of the zone describing its operational purpose: field_pitch, locker_room, press_box, broadcast_compound, vip_hospitality, back_of_house, command_center, parking_compound, public_concourse, medical, production_truck_bay, merchandise_storage. [ENUM-REF-CANDIDATE: field_pitch|locker_room|press_box|broadcast_compound|vip_hospitality|back_of_house|command_center|parking_compound|public_concourse|medical|production_truck_bay|merchandise_storage — promote to reference product]',
    CONSTRAINT pk_access_zone PRIMARY KEY(`access_zone_id`)
) COMMENT 'Master catalog of all defined physical access control zones within Sports Entertainment venues — field/pitch level, locker rooms, press box, broadcast compound, VIP hospitality, back-of-house, command center, parking compounds, and public concourse zones. Captures zone code, zone name, venue reference, zone tier (public/restricted/secured/sterile), maximum occupancy, surveillance coverage flag, and zone adjacency metadata used for crowd flow modeling.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`credential_assignment` (
    `credential_assignment_id` BIGINT COMMENT 'Unique system-generated identifier for each credential assignment record. Primary key for the credential_assignment data product in the security domain.',
    `access_zone_id` BIGINT COMMENT 'Reference to the primary access control zone or area that this credential assignment grants entry to. Supports zone-based access management within the venue.',
    `assigned_by_officer_employee_id` BIGINT COMMENT 'Reference to the security officer or credentialing authority who authorized and issued this credential assignment. Used for accountability and audit trail purposes.',
    `contingent_worker_id` BIGINT COMMENT 'Foreign key linking to workforce.contingent_worker. Business justification: Credential assignments are issued to both employees and contingent workers (broadcast crew, vendor staff). The existing holder_employee_id covers staff employees. A separate contingent_worker_id FK is',
    `creator_profile_id` BIGINT COMMENT 'Foreign key linking to content.creator_profile. Business justification: Credential assignments for event-day access must track which content creator holds a given credential at a specific fixture. This supports media zone access control, post-event content rights audits (',
    `credential_id` BIGINT COMMENT 'Reference to the specific credential (badge, pass, wristband, RFID card) being assigned to the holder. Links to the credential master record.',
    `employee_id` BIGINT COMMENT 'Reference to the individual (staff, media, contractor, law enforcement, athlete, sponsor representative) to whom the credential is assigned. Links to the person or party master record.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the specific sports or entertainment event for which this credential assignment is valid. Null if the assignment is venue-wide or period-based rather than event-specific.',
    `fixture_id` BIGINT COMMENT 'Reference to the specific sports or entertainment event for which this credential assignment is valid. Null if the assignment is venue-wide or period-based rather than event-specific.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Credential assignments for franchise staff and media require franchise attribution for franchise-level access control audits, league credentialing compliance reporting, and franchise-specific access z',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped credential assignments support league-wide access control audits, franchise credential compliance reviews, and CBA-mandated media/staff access protocol reporting across the full season.',
    `primary_credential_holder_employee_id` BIGINT COMMENT 'Reference to the individual (staff, media, contractor, law enforcement, athlete, sponsor representative) to whom the credential is assigned. Links to the person or party master record.',
    `venue_id` BIGINT COMMENT 'Reference to the venue or facility where this credential assignment is valid. Supports venue-wide credentialing independent of a specific event.',
    `superseded_credential_assignment_id` BIGINT COMMENT 'Self-referencing FK on credential_assignment (superseded_credential_assignment_id)',
    `access_level` STRING COMMENT 'Categorical access tier granted by this credential assignment, defining the scope of areas the holder may enter within the venue. Drives access control system enforcement at entry points. [ENUM-REF-CANDIDATE: field|locker_room|press_box|backstage|general|restricted|all_access|vip|production — promote to reference product]',
    `assignment_date` DATE COMMENT 'Calendar date on which the credential was formally assigned to the holder by the credentialing authority. Represents the principal business event date for this transaction.',
    `assignment_number` STRING COMMENT 'Externally-known human-readable business identifier for the credential assignment, used in credentialing workflows, printed on assignment receipts, and referenced in post-event reconciliation reports. Format: CA-{YYYY}-{NNNNNN}.. Valid values are `^CA-[0-9]{4}-[0-9]{6}$`',
    `assignment_status` STRING COMMENT 'Current lifecycle state of the credential assignment. Drives operational workflows including pickup confirmation, access control enforcement, and post-event reconciliation. [ENUM-REF-CANDIDATE: pending|issued|active|suspended|revoked|returned|expired|lost|stolen — promote to reference product]',
    `assignment_timestamp` TIMESTAMP COMMENT 'Precise date and time at which the credential assignment was created in the system, capturing the exact moment of authorization. Used for audit trail and security incident investigation.',
    `background_check_date` DATE COMMENT 'Date on which the background check for the credential holder was completed or last updated. Used to determine if a background check is current and valid for the assignment period.',
    `background_check_status` STRING COMMENT 'Status of the background screening conducted on the credential holder prior to credential issuance. Cleared status is required for access to restricted zones such as locker rooms and field areas.. Valid values are `pending|cleared|failed|waived|not_required`',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this credential assignment record was first created in the data platform. Used for audit trail, data lineage, and compliance reporting.',
    `credential_scope` STRING COMMENT 'Defines the temporal and event scope of the credential assignment — whether it is valid for a single event, multiple events, an entire season, or the venue broadly. Drives validity period enforcement and renewal workflows.. Valid values are `single_event|multi_event|season|venue_wide|tournament`',
    `credential_type` STRING COMMENT 'Physical or digital form factor of the credential being assigned. Determines issuance workflow, pickup process, and return reconciliation procedures.. Valid values are `badge|wristband|rfid_card|lanyard_pass|vehicle_pass|digital_pass`',
    `escort_required` BOOLEAN COMMENT 'Indicates whether the credential holder must be accompanied by an authorized escort when accessing credentialed areas. True when escort is mandatory; False when holder may access independently.',
    `event_day_number` STRING COMMENT 'For multi-day events (tournaments, festivals, conventions), the specific day number within the event for which this credential is valid. Null for single-day events or season-wide credentials.',
    `holder_full_name` STRING COMMENT 'Full legal name of the individual to whom the credential is assigned. Captured at time of assignment for identity verification and printed on the credential. Subject to GDPR and CCPA data protection requirements.',
    `holder_id_number` STRING COMMENT 'Government-issued or organizational identification number (e.g., employee ID, press pass number, law enforcement badge number) used to verify the identity of the credential holder at time of issuance.',
    `holder_organization` STRING COMMENT 'Name of the organization, employer, or entity that the credential holder represents (e.g., ESPN, ABC Security Services, NFL Players Association). Used for credentialing workflow routing and sponsor/media tracking.',
    `holder_photo_url` STRING COMMENT 'Secure URL reference to the credential holders photo image stored in the Digital Asset Management (DAM) system. Used for visual identity verification at access control points. Subject to biometric data protection regulations.',
    `holder_type` STRING COMMENT 'Classification of the individual receiving the credential, defining their role and relationship to the event or venue. Drives access zone eligibility and credentialing workflow routing. [ENUM-REF-CANDIDATE: staff|media|contractor|law_enforcement|athlete|sponsor|vip|volunteer|official|vendor — promote to reference product]. Valid values are `staff|media|contractor|law_enforcement|athlete|sponsor`',
    `issued_timestamp` TIMESTAMP COMMENT 'Date and time at which the physical or digital credential was formally issued and activated in the access control system. Distinct from assignment_timestamp (when the record was created) and pickup_timestamp (when the holder collected it).',
    `last_updated_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this credential assignment record was most recently modified. Used for change tracking, audit trail, and incremental data pipeline processing.',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency represented by the credential holder, applicable when holder_type is law_enforcement (e.g., NYPD, FBI, US Secret Service). Used for law enforcement coordination and post-event reporting.',
    `meal_entitlement` BOOLEAN COMMENT 'Indicates whether the credential assignment includes meal or catering entitlement in designated hospitality areas (e.g., press dining, staff cafeteria). Used for catering planning and cost allocation.',
    `multi_zone_access` BOOLEAN COMMENT 'Indicates whether this credential assignment grants access to multiple zones beyond the primary access zone. True when the holder is authorized for more than one zone; False for single-zone access.',
    `parking_zone` STRING COMMENT 'Designated parking zone or lot assigned to the credential holder when vehicle access is granted (e.g., Lot A - Media, Field Level - Broadcast, VIP Garage). Null when vehicle_access is False.',
    `pickup_confirmed` BOOLEAN COMMENT 'Indicates whether the credential holder has physically collected the credential from the credentialing desk. True when pickup has been confirmed; False when credential is still awaiting collection.',
    `pickup_location` STRING COMMENT 'Name or designation of the credentialing desk, gate, or location where the credential was or is to be collected by the holder (e.g., Media Gate North, VIP Credentialing Desk Level 2).',
    `pickup_timestamp` TIMESTAMP COMMENT 'Date and time at which the credential holder physically collected the credential from the credentialing desk. Null if credential has not yet been picked up.',
    `return_confirmed` BOOLEAN COMMENT 'Indicates whether the credential has been returned to the credentialing authority after the event or assignment period. True when return is confirmed; False when credential is still outstanding. Critical for post-event reconciliation.',
    `return_timestamp` TIMESTAMP COMMENT 'Date and time at which the credential was returned to the credentialing authority. Null if credential has not yet been returned. Used in post-event reconciliation to identify unreturned credentials.',
    `revocation_reason` STRING COMMENT 'Free-text description of the reason a credential assignment was revoked or suspended before its natural expiry (e.g., Security incident, Holder no longer authorized, Lost credential reported). Null when assignment has not been revoked.',
    `revocation_timestamp` TIMESTAMP COMMENT 'Date and time at which the credential assignment was revoked or suspended. Null when assignment has not been revoked. Used for security incident investigation and access control audit trails.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this credential assignment record originated (e.g., Ticketmaster/AXS access control, Archtics venue seating and inventory, manual credentialing desk entry). Supports data lineage and reconciliation.. Valid values are `ticketmaster_axs|archtics|manual|salesforce_crm|sap_s4hana`',
    `special_access_notes` STRING COMMENT 'Free-text field capturing any special access permissions, restrictions, or annotations associated with this credential assignment (e.g., Authorized for post-game press conference only, Escort required at all times). Supports non-standard credentialing scenarios.',
    `valid_until` TIMESTAMP COMMENT 'Date and time at which the credential assignment expires and access is no longer granted. Null for open-ended assignments. Critical for post-event reconciliation and access revocation.',
    `vehicle_access` BOOLEAN COMMENT 'Indicates whether this credential assignment includes authorization for vehicle access to restricted venue areas such as loading docks, field-level parking, or broadcast compound. True when vehicle access is granted.',
    `valid_from` TIMESTAMP COMMENT 'Date and time from which the credential assignment becomes active and grants access. Supports time-bounded credentialing for multi-day events or seasonal venue access.',
    CONSTRAINT pk_credential_assignment PRIMARY KEY(`credential_assignment_id`)
) COMMENT 'Transactional record linking a specific credential to an authorized holder for a defined event or period. Captures credential ID, holder type (staff, media, contractor, law enforcement, athlete, sponsor), event or venue scope, assignment date, assigned-by officer, pickup confirmation, return confirmation, and any special access annotations. Enables per-event credentialing workflows and post-event reconciliation.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`access_event` (
    `access_event_id` BIGINT COMMENT 'Unique surrogate identifier for each physical access control scan event record in the Silver layer lakehouse. Primary key for this table.',
    `access_zone_id` BIGINT COMMENT 'Reference to the access control zone (e.g., field level, media area, backstage, VIP suite corridor) that the credential holder attempted to enter.',
    `calendar_id` BIGINT COMMENT 'Reference to the scheduled sports or entertainment event during which this access scan occurred. Links the access record to the event context for occupancy and security reporting.',
    `contingent_worker_id` BIGINT COMMENT 'Foreign key linking to workforce.contingent_worker. Business justification: Contingent workers (broadcast crew, vendor staff) scan in/out of venue zones via access control readers. The access_event.employee_id covers staff only. Linking to contingent_worker enables zone-acces',
    `credential_id` BIGINT COMMENT 'Reference to the credential (badge, card, biometric token, or digital pass) that was presented at the reader. Distinct from a fan ticket — covers staff, media, VIP, and operational credentials.',
    `employee_id` BIGINT COMMENT 'Reference to the security officer or staff member who performed a manual override or was stationed at the checkpoint. Null when no officer interaction occurred.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the scheduled sports or entertainment event during which this access scan occurred. Links the access record to the event context for occupancy and security reporting.',
    `fan_profile_id` BIGINT COMMENT 'Foreign key linking to fan.fan_profile. Business justification: Fan entry audit trails, loyalty point earning on gate entry, and security incident correlation all require linking access events to fan profiles. Standard sports venue access-control and CRM integrati',
    `fixture_id` BIGINT COMMENT 'FK to event.fixture.fixture_id — Event-correlated access control — security operations must correlate access scans to specific events for crowd management, capacity monitoring, and incident investigation.',
    `officer_employee_id` BIGINT COMMENT 'Reference to the security officer or staff member who performed a manual override or was stationed at the checkpoint. Null when no officer interaction occurred.',
    `security_incident_id` BIGINT COMMENT 'Reference to a security incident record if this access event triggered or was associated with a security incident. Null when no incident was raised. Supports post-event forensic review and incident management workflows.',
    `venue_id` BIGINT COMMENT 'Reference to the venue where the access event occurred. Used to associate the scan event with a specific Sports Entertainment facility.',
    `override_of_access_event_id` BIGINT COMMENT 'Self-referencing FK on access_event (override_of_access_event_id)',
    `access_direction` STRING COMMENT 'Direction of movement at the checkpoint: entry = entering the zone or venue, exit = leaving the zone or venue, internal = movement between internal zones. Used for real-time occupancy tracking and crowd flow analysis.. Valid values are `entry|exit|internal`',
    `ada_accommodation_flag` BOOLEAN COMMENT 'Indicates whether the credential holder required an ADA (Americans with Disabilities Act) accommodation at this access point (e.g., accessible gate routing). True = ADA accommodation applied; False = standard access.',
    `anti_passback_zone` STRING COMMENT 'Identifier of the anti-passback zone group assigned to this checkpoint. Anti-passback rules prevent a credential from being used to enter a zone it has not exited. Used for tailgating detection and occupancy integrity.',
    `biometric_verified_flag` BOOLEAN COMMENT 'Indicates whether biometric verification (e.g., facial recognition, fingerprint) was used as part of the credential authentication for this scan event. True = biometric match confirmed; False = biometric not used or not matched.',
    `checkpoint_name` STRING COMMENT 'Human-readable name or label of the physical access checkpoint (e.g., Gate A – North Entrance, Field Level Door 3, Media Tunnel). Supports operational reporting and post-event forensic review without requiring a zone lookup.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this access event record was first written to the Silver layer lakehouse. Distinct from scan_timestamp (the real-world event time). Used for data pipeline audit trails and SLA monitoring.',
    `credential_holder_category` STRING COMMENT 'Broad category of the person holding the credential. Distinct from credential_type (which describes the credential itself); this describes the persons role. Used for access pattern analytics and compliance reporting. [ENUM-REF-CANDIDATE: athlete|staff|media|vip|vendor|law_enforcement|official — 7 candidates stripped; promote to reference product]',
    `credential_token` STRING COMMENT 'Tokenized or masked representation of the physical credential identifier (e.g., RFID card number, barcode, NFC token) as presented to the reader. Stored in tokenized form to comply with PCI-DSS and GDPR. Not the raw credential number.',
    `credential_type` STRING COMMENT 'Classification of the credential presented at the reader. Distinguishes between staff, media, VIP, vendor, law enforcement, athlete, and digital mobile credentials. [ENUM-REF-CANDIDATE: staff_badge|media_pass|vip_credential|vendor_pass|law_enforcement|athlete_credential|digital_mobile — promote to reference product]',
    `data_retention_expiry_date` DATE COMMENT 'Date on which this access event record is scheduled for deletion or anonymization per applicable data retention policies (GDPR, CCPA). Supports automated data lifecycle management in the lakehouse.',
    `denial_reason_code` STRING COMMENT 'Standardized code indicating why access was denied or flagged. Null when scan_result is granted or override_granted. [ENUM-REF-CANDIDATE: INVALID_CREDENTIAL|EXPIRED_CREDENTIAL|ZONE_NOT_AUTHORIZED|BLACKLISTED|DUPLICATE_SCAN|CAPACITY_EXCEEDED|SYSTEM_ERROR — promote to reference product]',
    `duplicate_scan_flag` BOOLEAN COMMENT 'Indicates whether this scan event was detected as a duplicate presentation of the same credential within a short time window (anti-passback detection). True = duplicate detected; False = unique scan.',
    `emergency_evacuation_flag` BOOLEAN COMMENT 'Indicates whether this scan event occurred during an active emergency evacuation protocol. True = evacuation mode active at time of scan; False = normal operations. Critical for post-incident headcount reconciliation.',
    `event_phase` STRING COMMENT 'Operational phase of the event at the time of the scan. Used to segment access patterns by event lifecycle stage for crowd management analytics and post-event review.. Valid values are `pre_event|doors_open|in_progress|halftime|post_event|emergency`',
    `gdpr_data_subject_flag` BOOLEAN COMMENT 'Indicates whether the credential holder associated with this scan event is a data subject under GDPR jurisdiction (e.g., EU resident). True = GDPR data subject protections apply; False = not subject to GDPR. Drives data retention and erasure workflows.',
    `law_enforcement_notified_flag` BOOLEAN COMMENT 'Indicates whether law enforcement was notified as a result of this access event (e.g., blacklisted credential, flagged individual). True = law enforcement notification triggered; False = no notification.',
    `network_zone` STRING COMMENT 'Network segment or VLAN identifier of the reader device that processed this scan. Used for cybersecurity segmentation audits and forensic network analysis in the event of a security breach.',
    `occupancy_count_at_scan` STRING COMMENT 'Snapshot of the current occupancy count for the zone at the moment this scan event was processed. Captured at scan time to support real-time occupancy tracking and capacity compliance reporting.',
    `officer_override_flag` BOOLEAN COMMENT 'Indicates whether a security officer manually overrode the systems access decision for this event. True = officer override applied; False = system decision was final. Critical for post-event forensic review and accountability audits.',
    `override_justification` STRING COMMENT 'Free-text or coded reason provided by the officer when performing a manual override. Required when officer_override_flag is True. Supports accountability and compliance audit trails.',
    `reader_device_code` BIGINT COMMENT 'Reference to the physical access control reader or scanner device that captured this scan event. Used for device-level diagnostics, tamper detection, and post-event forensic review.',
    `reader_firmware_version` STRING COMMENT 'Firmware version of the access control reader device at the time of the scan. Captured for forensic integrity, device audit trails, and vulnerability management compliance.',
    `reader_location_code` STRING COMMENT 'Alphanumeric code identifying the physical location of the reader device within the venue (e.g., NE-G1-R04). Supports device-level forensic analysis and maintenance tracking.',
    `scan_duration_ms` STRING COMMENT 'Time in milliseconds taken for the reader to process the credential and return a result. Used for throughput analysis, reader performance monitoring, and identifying bottlenecks at high-traffic checkpoints.',
    `scan_result` STRING COMMENT 'Outcome of the credential scan at the access point. granted = access permitted; denied = access refused; flagged = access held for secondary review; override_granted = officer manually permitted entry; timeout = reader did not receive a valid response. Core field for real-time occupancy tracking and compliance audit trails.. Valid values are `granted|denied|flagged|override_granted|timeout`',
    `scan_timestamp` TIMESTAMP COMMENT 'Precise date and time (with timezone offset) when the credential was presented to the reader. The principal real-world event time for this access event. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `secondary_screening_flag` BOOLEAN COMMENT 'Indicates whether the credential holder was referred for secondary security screening (e.g., bag check, wand scan) at this access event. True = secondary screening triggered; False = standard throughput.',
    `source_event_reference` STRING COMMENT 'The original event transaction ID or record key from the source access control system (e.g., Ticketmaster/AXS transaction ID). Enables traceability back to the operational system of record for audit and reconciliation.',
    `source_system_code` STRING COMMENT 'Code identifying the access control system that originated this scan event record (e.g., AXS, Ticketmaster, Lenel, C-Cure, Genetec). Supports multi-system venue environments and data lineage tracking in the Silver layer.. Valid values are `AXS|TICKETMASTER|LENEL|CCURE|GENETEC|CUSTOM`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this access event record was last modified in the Silver layer (e.g., enrichment, correction, incident linkage). Supports data lineage and audit trail requirements.',
    `watchlist_match_flag` BOOLEAN COMMENT 'Indicates whether the credential or credential holder matched an entry on a security watchlist at the time of the scan. True = watchlist match detected; False = no match. Triggers escalation workflows.',
    `zone_capacity` STRING COMMENT 'Maximum permitted occupancy for the zone at the time of the scan event, as configured in the access control system. Used alongside occupancy_count_at_scan to determine capacity compliance status.',
    `zone_level` STRING COMMENT 'Security classification level of the zone being accessed at the time of the scan. Captures the sensitivity of the zone for risk-tiered reporting and compliance. Values: public, restricted, highly_restricted, field_level, backstage.. Valid values are `public|restricted|highly_restricted|field_level|backstage`',
    CONSTRAINT pk_access_event PRIMARY KEY(`access_event_id`)
) COMMENT 'High-volume transactional record of every physical access control scan event at venue entry and internal zone checkpoints — credential presented, zone accessed, timestamp, scan result (granted/denied/flagged), reader device ID, officer override flag, and denial reason code. Feeds real-time occupancy tracking, post-event forensic review, and compliance audit trails. Distinct from ticketing.gate_scan which covers fan ticket entitlement scanning.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`screening_checkpoint` (
    `screening_checkpoint_id` BIGINT COMMENT 'Unique surrogate identifier for each physical security screening checkpoint record in the Sports Entertainment venue security master. Primary key for the screening_checkpoint data product.',
    `access_zone_id` BIGINT COMMENT 'Foreign key linking to security.access_zone. Business justification: A screening checkpoint controls physical entry into a specific access zone — it is the gateway to that zone. The existing access_zone_level (STRING) is a denormalized attribute describing the zone tie',
    `surveillance_camera_id` BIGINT COMMENT 'Identifier of the primary CCTV surveillance camera covering this checkpoint, as registered in the venues video management system. Enables rapid retrieval of footage for incident investigation and compliance audits.',
    `venue_id` BIGINT COMMENT 'Reference to the Sports Entertainment venue where this screening checkpoint is physically deployed. Links to the venue master record.',
    `parent_screening_checkpoint_id` BIGINT COMMENT 'Self-referencing FK on screening_checkpoint (parent_screening_checkpoint_id)',
    `activation_end_time` TIMESTAMP COMMENT 'Standard time of day (HH:MM, 24-hour format) at which this checkpoint ceases screening operations and is deactivated. Used for egress planning and post-event security stand-down scheduling.',
    `activation_schedule_type` STRING COMMENT 'Defines the operational activation pattern for this checkpoint — whether it is staffed only on event days, permanently active, activated seasonally, or deployed on-demand for high-security events. Drives resource planning and cost allocation.. Valid values are `event_day_only|permanent|seasonal|on_demand`',
    `activation_start_time` TIMESTAMP COMMENT 'Standard time of day (HH:MM, 24-hour format) at which this checkpoint is activated and begins screening operations relative to event start. Used for gate opening schedules and ingress management planning.',
    `ada_lane_count` STRING COMMENT 'Number of ADA (Americans with Disabilities Act) compliant accessible screening lanes available at this checkpoint. Distinct from the total lane count — used for ADA compliance reporting and accessibility planning.',
    `checkpoint_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the screening checkpoint, used in operational communications, staffing assignments, and incident reporting (e.g., GATE-A-MAG-01, VIP-BAG-03). Unique within a venue.. Valid values are `^[A-Z0-9]{2,20}$`',
    `checkpoint_name` STRING COMMENT 'Human-readable descriptive name for the screening checkpoint as displayed on operational maps, staff briefings, and incident reports (e.g., North Gate Magnetometer Lane 2, VIP Credentialing Desk East).',
    `checkpoint_status` STRING COMMENT 'Current operational lifecycle status of the screening checkpoint. Drives activation scheduling, staffing allocation, and security coverage gap analysis.. Valid values are `active|inactive|standby|decommissioned|under_maintenance`',
    `checkpoint_type` STRING COMMENT 'Classification of the physical security screening checkpoint by its primary function and method of screening. Drives staffing requirements, equipment deployment, and throughput planning. [ENUM-REF-CANDIDATE: magnetometer_lane|bag_check_station|pat_down_area|vehicle_inspection|credentialing_desk|explosive_trace_detection — promote to reference product if additional types are added]. Valid values are `magnetometer_lane|bag_check_station|pat_down_area|vehicle_inspection|credentialing_desk|explosive_trace_detection`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this screening checkpoint master record was first created in the system. Supports data lineage, audit trail requirements, and Silver layer ingestion tracking.',
    `credential_type_accepted` STRING COMMENT 'Type(s) of credentials or access passes accepted at this checkpoint for entry authorization (e.g., event_ticket, media_credential, staff_badge, law_enforcement_id). Drives access control configuration in Ticketmaster/AXS. [ENUM-REF-CANDIDATE: event_ticket|media_credential|staff_badge|law_enforcement_id|vip_pass|vendor_pass|athlete_credential — promote to reference product]',
    `effective_from_date` DATE COMMENT 'Date from which this screening checkpoint record is operationally valid and available for deployment. Supports checkpoint lifecycle management and historical security configuration auditing.',
    `effective_until_date` DATE COMMENT 'Date after which this screening checkpoint record is no longer operationally valid (e.g., due to decommissioning, venue renovation, or permanent closure). Nullable for indefinitely active checkpoints.',
    `emergency_response_zone` STRING COMMENT 'Designated emergency response zone code to which this checkpoint belongs for incident command and evacuation coordination. Aligns with the venue emergency response plan and law enforcement sector assignments.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `equipment_asset_tag` STRING COMMENT 'Physical asset tag or serial number of the primary screening equipment unit deployed at this checkpoint. Used for maintenance tracking, calibration scheduling, and asset lifecycle management in the facilities management system.. Valid values are `^[A-Z0-9-]{4,30}$`',
    `equipment_last_calibration_date` DATE COMMENT 'Date on which the primary screening equipment at this checkpoint was most recently calibrated and certified for operational use. Required for regulatory compliance and safety audits.',
    `equipment_next_calibration_date` DATE COMMENT 'Scheduled date for the next mandatory calibration of the primary screening equipment at this checkpoint. Triggers maintenance work orders and ensures continuous compliance with security equipment standards.',
    `event_type_applicability` STRING COMMENT 'Specifies the category of events for which this checkpoint is activated (e.g., all_events, sports_only, concerts_only, ppv_events, high_profile_only). Supports dynamic checkpoint activation planning across the event calendar. [ENUM-REF-CANDIDATE: all_events|sports_only|concerts_only|ppv_events|high_profile_only|private_events — promote to reference product]',
    `floor_level` STRING COMMENT 'Floor or level designation within the venue where this checkpoint is located (e.g., Ground, Level 1, Concourse, Basement). Used for emergency evacuation planning and facility management.',
    `gate_number` STRING COMMENT 'Physical gate or entrance number associated with this screening checkpoint as labeled on venue maps and patron-facing signage (e.g., Gate 1, Gate C, Loading Dock 3). Used for wayfinding and incident location reporting.',
    `is_ada_accessible` BOOLEAN COMMENT 'Indicates whether this screening checkpoint includes an ADA (Americans with Disabilities Act) compliant accessible lane for patrons with mobility impairments, wheelchairs, or other accessibility needs. Mandatory for venue ADA compliance reporting.',
    `is_express_lane` BOOLEAN COMMENT 'Indicates whether this checkpoint operates as an expedited screening lane for credentialed personnel, season ticket holders, VIP (Very Important Person) guests, or pre-screened patrons with reduced wait times.',
    `is_vehicle_checkpoint` BOOLEAN COMMENT 'Indicates whether this checkpoint is designated for vehicle inspection rather than pedestrian screening. Drives different equipment, staffing, and protocol requirements for parking lot and loading dock security.',
    `lane_count` STRING COMMENT 'Number of parallel screening lanes available at this checkpoint. A single checkpoint may have multiple lanes operating simultaneously to increase throughput capacity during peak ingress periods.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent formal safety and compliance inspection of this checkpoint by internal security management or an external regulatory authority. Supports OSHA compliance tracking and audit readiness.',
    `law_enforcement_post` BOOLEAN COMMENT 'Indicates whether this checkpoint requires a dedicated law enforcement officer (LEO) post as part of the security deployment plan. Drives coordination with local police, sheriff, or federal law enforcement agencies.',
    `max_queue_length_meters` DECIMAL(18,2) COMMENT 'Maximum physical queue length in meters that can be accommodated at this checkpoint before crowd management protocols are triggered. Used for ingress modeling and crowd density safety planning.',
    `min_staff_required` STRING COMMENT 'Minimum number of security personnel required to operate this checkpoint at baseline capacity. Used for staffing plans, shift scheduling, and SLA (Service Level Agreement) compliance with law enforcement partners.',
    `next_inspection_date` DATE COMMENT 'Scheduled date for the next mandatory safety and compliance inspection of this checkpoint. Triggers inspection work orders and ensures continuous regulatory compliance.',
    `notes` STRING COMMENT 'Free-text operational notes or special instructions for this checkpoint, such as known physical constraints, special event configurations, or temporary modifications. Used by security supervisors during event briefings.',
    `operating_sop_reference` STRING COMMENT 'Document reference number or URL for the Standard Operating Procedure (SOP) governing operations at this checkpoint type. Ensures staff follow approved protocols and supports compliance audits.',
    `optimal_staff_count` STRING COMMENT 'Recommended number of security personnel for this checkpoint to achieve rated throughput capacity. Distinct from minimum staffing — represents the target headcount for peak event operations.',
    `physical_location_description` STRING COMMENT 'Narrative description of the precise physical location of this checkpoint within the venue (e.g., North concourse, adjacent to Section 101 entrance, ground level). Supports emergency response coordination and incident reporting.',
    `primary_equipment_type` STRING COMMENT 'Primary security screening equipment deployed at this checkpoint. WTMD (Walk-Through Metal Detector), X-ray (baggage X-ray scanner), ETD (Explosive Trace Detection). Drives maintenance scheduling, calibration records, and procurement planning. [ENUM-REF-CANDIDATE: WTMD|X-ray|ETD|handheld_wand|visual_inspection|CCTV|vehicle_barrier — 7 candidates stripped; promote to reference product]',
    `prohibited_items_list_version` STRING COMMENT 'Version identifier of the prohibited items policy document governing what items are screened and confiscated at this checkpoint (e.g., v2.3). Ensures staff are operating under the current approved policy and supports audit traceability.. Valid values are `^vd+.d+$`',
    `secondary_equipment_type` STRING COMMENT 'Secondary or supplemental screening equipment deployed at this checkpoint in addition to the primary equipment (e.g., handheld wand alongside WTMD, ETD alongside X-ray). Nullable when only primary equipment is deployed.',
    `security_level` STRING COMMENT 'Operational security threat level assigned to this checkpoint, which determines screening intensity, staffing multipliers, and equipment deployment. Aligns with DHS threat level frameworks and league-specific security mandates.. Valid values are `standard|elevated|high|critical`',
    `throughput_capacity_per_hour` STRING COMMENT 'Rated maximum number of persons that can be screened through this checkpoint per hour under normal operating conditions. Used for crowd management planning, staffing optimization, and event ingress modeling.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this screening checkpoint master record was most recently modified. Supports change tracking, audit compliance, and incremental data pipeline processing in the Databricks Silver layer.',
    `venue_zone_code` STRING COMMENT 'Alphanumeric code identifying the specific security zone or sector within the venue where this checkpoint is located (e.g., ZONE-A, CONCOURSE-2, FIELD-LEVEL). Aligns with venue access control zone mapping.',
    CONSTRAINT pk_screening_checkpoint PRIMARY KEY(`screening_checkpoint_id`)
) COMMENT 'Master record for all physical security screening checkpoints deployed at Sports Entertainment venues — magnetometer lanes, bag check stations, pat-down areas, vehicle inspection points, and credentialing desks. Captures checkpoint code, venue zone assignment, checkpoint type, equipment deployed (WTMD, X-ray, ETD), staffing requirement, throughput capacity (persons/hour), activation schedule, and ADA-accessible lane flag.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`screening_event` (
    `screening_event_id` BIGINT COMMENT 'Unique surrogate identifier for each individual screening interaction record at a security checkpoint. Primary key for the screening_event data product in the Databricks Silver Layer.',
    `access_zone_id` BIGINT COMMENT 'Foreign key linking to security.access_zone. Business justification: A screening event occurs at a checkpoint that controls entry to a specific access zone. The existing access_zone_code (STRING) is a denormalized text reference to the zone; replacing it with a proper ',
    `ada_accommodation_id` BIGINT COMMENT 'Foreign key linking to compliance.ada_accommodation. Business justification: When a fan with a disability passes through a security screening checkpoint, the screening event must reference the pre-approved ADA accommodation record to apply correct screening protocols and docum',
    `contingent_worker_id` BIGINT COMMENT 'Foreign key linking to workforce.contingent_worker. Business justification: Contracted security screeners (contingent workers) conduct the majority of fan screening at large venues. The existing employee_id covers staff only. Linking to contingent_worker enables throughput pe',
    `employee_id` BIGINT COMMENT 'Reference to the security officer or personnel who conducted or oversaw this screening interaction. Used for officer performance tracking and incident accountability.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the sports or entertainment event during which this screening interaction took place. Enables post-event security review and cross-event trend analysis.',
    `fan_profile_id` BIGINT COMMENT 'Reference to the fan, staff member, or credentialed personnel who was screened. May be null for anonymous general admission screenings where identity is not captured.',
    `fixture_id` BIGINT COMMENT 'Reference to the sports or entertainment event during which this screening interaction took place. Enables post-event security review and cross-event trend analysis.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Screening events at franchise home games must be franchise-attributed for league fan safety compliance reporting, franchise-level throughput benchmarking, and CBA-mandated safety protocol audits requi',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-level screening aggregation is required for league annual safety compliance submissions, prohibited items trend analysis, and CBA player/fan safety reviews covering all franchise home games.',
    `membership_id` BIGINT COMMENT 'Foreign key linking to fan.membership. Business justification: VIP and season-ticket members use express/priority screening lanes. Linking screening events to membership records validates lane entitlement, audits express-lane usage compliance, and supports member',
    `primary_screening_employee_id` BIGINT COMMENT 'Reference to the security officer or personnel who conducted or oversaw this screening interaction. Used for officer performance tracking and incident accountability.',
    `screened_person_fan_profile_id` BIGINT COMMENT 'Reference to the fan, staff member, or credentialed personnel who was screened. May be null for anonymous general admission screenings where identity is not captured.',
    `screening_checkpoint_id` BIGINT COMMENT 'Reference to the specific security checkpoint location where this screening interaction occurred. Used to analyze throughput and incident rates by checkpoint.',
    `security_incident_id` BIGINT COMMENT 'Foreign key linking to security.security_incident. Business justification: A screening event may trigger a security incident when a prohibited item is found, an individual is denied entry and becomes aggressive, or law enforcement is notified. The existing incident_report_nu',
    `shift_assignment_id` BIGINT COMMENT 'Reference to the security staffing shift during which this screening interaction occurred. Enables shift-level performance analysis, staffing optimization, and labor compliance reporting.',
    `shift_shift_assignment_id` BIGINT COMMENT 'Reference to the security staffing shift during which this screening interaction occurred. Enables shift-level performance analysis, staffing optimization, and labor compliance reporting.',
    `supervisor_employee_id` BIGINT COMMENT 'Reference to the security supervisor who reviewed or authorized actions taken during an escalated screening interaction. Null for non-escalated screenings. Supports supervisory accountability and escalation audit trails.',
    `venue_id` BIGINT COMMENT 'Reference to the venue facility where the screening occurred. Supports venue-level security performance benchmarking and ADA/OSHA compliance reporting.',
    `secondary_of_screening_event_id` BIGINT COMMENT 'Self-referencing FK on screening_event (secondary_of_screening_event_id)',
    `ada_accommodation_required_flag` BOOLEAN COMMENT 'Indicates whether the screened individual required an ADA accommodation during the screening process (e.g., wheelchair user, medical device wearer). Supports ADA compliance reporting and accessibility audit requirements.',
    `alarm_resolution` STRING COMMENT 'The resolution or explanation for an equipment alarm triggered during screening. Null when no alarm was triggered. Supports false-positive rate analysis and equipment calibration review.. Valid values are `false_positive|prohibited_item_found|medical_device|cleared_pat_down|unresolved`',
    `confiscation_receipt_number` STRING COMMENT 'Reference number issued to the individual when a prohibited item is confiscated, enabling item retrieval after the event if applicable. Null when no item was confiscated. Supports chain-of-custody documentation.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this screening event record was first created in the system. Used for audit trail, data lineage, and Silver Layer ingestion tracking.',
    `credential_number` STRING COMMENT 'The unique identifier printed on or encoded within the access credential presented at screening (e.g., ticket barcode, badge number). Used for access validation and post-event audit trail. Classified confidential as it can be used to trace individual access patterns.',
    `credential_type` STRING COMMENT 'The type of access credential presented by the individual at the checkpoint (e.g., event ticket, staff badge, media credential). Used to validate authorized access and support post-event credentialing audits. [ENUM-REF-CANDIDATE: ticket|season_pass|staff_badge|media_credential|vendor_pass|vip_wristband — promote to reference product]. Valid values are `ticket|season_pass|staff_badge|media_credential|vendor_pass|vip_wristband`',
    `crowd_density_level` STRING COMMENT 'Operational assessment of crowd density at the checkpoint at the time of this screening interaction. Supports crowd management protocol activation analysis and post-event safety review.. Valid values are `low|moderate|high|critical`',
    `data_source_system` STRING COMMENT 'The operational system of record from which this screening event record was ingested into the Databricks Silver Layer (e.g., Ticketmaster/AXS, venue_access_control_system). Supports data lineage and audit trail requirements.',
    `entry_denied_reason` STRING COMMENT 'Free-text or coded reason why entry was denied to the screened individual. Null when entry was not denied. Supports denied-entry trend analysis and policy enforcement review.',
    `equipment_alarm_triggered_flag` BOOLEAN COMMENT 'Indicates whether the screening equipment (e.g., magnetometer, X-ray) triggered an alarm during this interaction. Distinguishes equipment-initiated alerts from officer-initiated secondary screenings.',
    `equipment_code` STRING COMMENT 'Identifier of the specific screening equipment unit used (e.g., magnetometer unit serial number, X-ray machine ID). Supports equipment maintenance tracking, calibration compliance, and fault correlation analysis.',
    `escalation_flag` BOOLEAN COMMENT 'Indicates whether this screening interaction was escalated beyond the initial checkpoint officer, such as to a supervisor, law enforcement, or medical personnel. Key field for post-event security review and incident management reporting.',
    `escalation_type` STRING COMMENT 'The type of escalation triggered by this screening interaction. Null or none when no escalation occurred. Used to categorize escalation patterns and resource deployment analysis.. Valid values are `supervisor|law_enforcement|medical|secondary_screening_team|none`',
    `gate_number` STRING COMMENT 'The physical gate or entry point identifier at the venue where the screening checkpoint is located. Used for throughput analysis and crowd flow management.',
    `item_confiscated_flag` BOOLEAN COMMENT 'Indicates whether the detected prohibited item was physically confiscated from the individual. Distinct from denied_entry outcome — an item may be confiscated while the individual is still permitted entry. Supports confiscation log and chain-of-custody tracking.',
    `lane_number` STRING COMMENT 'The specific screening lane within a checkpoint where the interaction occurred. Multiple lanes may operate at a single gate or checkpoint. Used for lane-level throughput and staffing analysis.',
    `law_enforcement_case_number` STRING COMMENT 'The official case or incident number assigned by law enforcement when they were notified or took action related to this screening event. Null when law enforcement was not involved. Enables cross-referencing with law enforcement records.',
    `law_enforcement_notified_flag` BOOLEAN COMMENT 'Indicates whether local or venue law enforcement was formally notified as part of this screening interaction. Supports law enforcement coordination reporting and incident documentation.',
    `notes` STRING COMMENT 'Free-text field for the screening officer to record additional observations, context, or details about the screening interaction not captured in structured fields. Used for incident documentation and post-event review.',
    `prohibited_item_category` STRING COMMENT 'High-level category of the prohibited item detected during screening. Null when no prohibited item was found. Supports trend analysis and policy review. [ENUM-REF-CANDIDATE: weapon_firearm|weapon_edged|weapon_blunt|explosive|controlled_substance|alcohol|oversized_bag|laser_device|other — promote to reference product]',
    `prohibited_item_description` STRING COMMENT 'Free-text description of the specific prohibited item detected (e.g., folding knife, 3-inch blade, half-pint whiskey flask). Null when no prohibited item was found. Used for detailed incident documentation and law enforcement reporting.',
    `prohibited_item_flag` BOOLEAN COMMENT 'Indicates whether a prohibited item was detected during this screening interaction. True when any prohibited item was found, regardless of whether it was confiscated or the individual was denied entry. Key driver for prohibited item trend analysis.',
    `queue_wait_time_seconds` STRING COMMENT 'The estimated or measured time in seconds the individual waited in the queue before reaching the screening checkpoint. Supports fan experience analysis, crowd management planning, and SLA reporting for entry operations.',
    `screened_person_type` STRING COMMENT 'Classification of the individual being screened, distinguishing fans from credentialed personnel, VIP guests, media, athletes, and law enforcement. Supports segmented security analytics and credentialing compliance. [ENUM-REF-CANDIDATE: fan|staff|vendor|media|vip|athlete|law_enforcement — promote to reference product]',
    `screening_duration_seconds` STRING COMMENT 'The elapsed time in seconds from the start to the completion of the screening interaction. Used for checkpoint throughput analysis, staffing optimization, and identifying bottlenecks in the fan entry process.',
    `screening_method` STRING COMMENT 'The physical or technological method used to conduct the screening. Supports equipment utilization analysis and compliance with venue security protocols. [ENUM-REF-CANDIDATE: walk_through_magnetometer|hand_wand|pat_down|bag_x_ray|visual_inspection|explosive_trace_detection — promote to reference product]. Valid values are `walk_through_magnetometer|hand_wand|pat_down|bag_x_ray|visual_inspection|explosive_trace_detection`',
    `screening_outcome` STRING COMMENT 'The result of the screening interaction indicating the disposition of the screened individual. Drives escalation workflows, prohibited item trend analysis, and checkpoint throughput reporting. [ENUM-REF-CANDIDATE: cleared|secondary_screening|denied_entry|prohibited_item_confiscated|medical_referral|law_enforcement_referral — promote to reference product]. Valid values are `cleared|secondary_screening|denied_entry|prohibited_item_confiscated|medical_referral|law_enforcement_referral`',
    `screening_reference_number` STRING COMMENT 'Externally-visible alphanumeric reference code assigned to this screening interaction, used for incident reporting, law enforcement coordination, and audit trail purposes. Format: SCR-{YEAR}-{EVENTID}-{SEQUENCE}.. Valid values are `^SCR-[0-9]{4}-[0-9]{8}-[A-Z0-9]{6}$`',
    `screening_timestamp` TIMESTAMP COMMENT 'The precise date and time when the screening interaction occurred at the checkpoint. Principal business event timestamp used for throughput analysis, timeline reconstruction, and post-event security review.',
    `secondary_screening_outcome` STRING COMMENT 'The final disposition of a secondary screening interaction when the initial screening outcome was secondary_screening. Null for interactions that did not require secondary screening. Completes the full screening lifecycle record.. Valid values are `cleared|denied_entry|law_enforcement_referral|medical_referral`',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this screening event record was last modified, such as when an escalation outcome was updated or an incident report number was added. Supports audit trail and data quality monitoring.',
    CONSTRAINT pk_screening_event PRIMARY KEY(`screening_event_id`)
) COMMENT 'Transactional record of individual fan or personnel screening interactions at security checkpoints — capturing checkpoint ID, timestamp, screening outcome (cleared/secondary screening/denied entry/prohibited item confiscated), prohibited item type if applicable, officer ID, and escalation flag. Supports post-event security review, prohibited item trend analysis, and checkpoint throughput reporting.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`post` (
    `post_id` BIGINT COMMENT 'Unique surrogate identifier for each defined security officer post or patrol assignment within a Sports Entertainment venue. Primary key for the security_post master record.',
    `access_zone_id` BIGINT COMMENT 'Foreign key linking to security.access_zone. Business justification: A security post is physically located within a defined access zone — the post guards or monitors that zone. The existing access_zone_level (STRING) is a denormalized attribute that describes the zone ',
    `event_fixture_id` BIGINT COMMENT 'Reference to the specific event for which this post assignment is activated. Null for standing/permanent posts that exist independent of a single event.',
    `fixture_id` BIGINT COMMENT 'Reference to the specific event for which this post assignment is activated. Null for standing/permanent posts that exist independent of a single event.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Security posts at franchise home games are franchise-attributed for staffing cost allocation, league safety compliance audits, and franchise-level post coverage reporting required by league operations',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped security post records support league annual safety staffing compliance submissions and franchise-level post deployment trend analysis required by league operations and governing bodies.',
    `position_id` BIGINT COMMENT 'Foreign key linking to workforce.position. Business justification: Each security post requires a specific workforce position (e.g., Security Officer II, Crowd Control Supervisor). Linking security_post to the workforce position enables headcount budget alignment, pay',
    `supervising_post_id` BIGINT COMMENT 'Self-referencing identifier of the supervisory post responsible for overseeing this post. Enables hierarchical post management and chain-of-command reporting within the security deployment structure.',
    `surveillance_camera_id` BIGINT COMMENT 'Identifier of the primary surveillance camera or camera cluster covering this post location. Used to correlate physical post assignments with video surveillance assets for incident review.',
    `venue_id` BIGINT COMMENT 'Reference to the venue at which this security post is defined. Links the post to the physical facility for deployment planning and venue-level coverage gap analysis.',
    `parent_post_id` BIGINT COMMENT 'Self-referencing FK on post (parent_post_id)',
    `ada_accessible_post` BOOLEAN COMMENT 'Indicates whether this post is positioned to provide ADA-compliant assistance and access support to guests with disabilities. Required for ADA compliance reporting and venue accessibility audits.',
    `armed_post` BOOLEAN COMMENT 'Indicates whether officers assigned to this post are required to be armed. Drives staffing qualification requirements, insurance compliance, and regulatory reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this security post record was first created in the system. Supports audit trail requirements and data lineage tracking on the Databricks Silver Layer.',
    `credential_type_required` STRING COMMENT 'Type of credential or badge required for personnel assigned to this post (e.g., EVENT_STAFF, LAW_ENFORCEMENT, SUPERVISOR, ARMED_OFFICER). Drives credentialing and access control workflows. [ENUM-REF-CANDIDATE: event_staff|law_enforcement|supervisor|armed_officer|contractor|volunteer — promote to reference product]',
    `crowd_capacity_threshold` STRING COMMENT 'Maximum crowd count in the posts zone before escalation protocols are triggered. Used in crowd management planning and real-time operational monitoring to prevent overcrowding incidents.',
    `effective_date` DATE COMMENT 'Date from which this security post definition becomes operationally active and available for staffing deployment. Supports versioning of post configurations across seasons and venue renovations.',
    `emergency_response_role` STRING COMMENT 'Designated emergency response function assigned to this post in the venue emergency response plan. Drives emergency drill assignments and incident command structure. [ENUM-REF-CANDIDATE: first_responder|evacuation_coordinator|crowd_control|medical_support|command_liaison|none — promote to reference product]. Valid values are `first_responder|evacuation_coordinator|crowd_control|medical_support|command_liaison|none`',
    `equipment_required` STRING COMMENT 'Comma-separated list or description of equipment required at this post (e.g., handheld_scanner, radio, baton, first_aid_kit). Used for pre-event equipment staging and inventory management.',
    `expiry_date` DATE COMMENT 'Date after which this security post definition is no longer active. Null for permanent posts with no planned end date. Supports lifecycle management and historical post coverage analysis.',
    `indoor_outdoor` STRING COMMENT 'Indicates whether the post is located indoors, outdoors, or spans both environments. Affects equipment requirements (weather gear, shelter), officer welfare planning, and OSHA compliance.. Valid values are `indoor|outdoor|both`',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate of the posts physical location within or around the venue. Enables GIS-based security coverage mapping and mobile deployment tracking.',
    `law_enforcement_required` BOOLEAN COMMENT 'Indicates whether sworn law enforcement officers (police, sheriff, federal agents) are required at this post, as opposed to private security personnel. Drives law enforcement coordination and contract requirements.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate of the posts physical location within or around the venue. Used alongside post_latitude for GIS-based security coverage mapping.',
    `minimum_staff_count` STRING COMMENT 'Absolute minimum number of security officers needed to maintain acceptable coverage at this post. If staffing falls below this threshold, the post is flagged as critically understaffed in gap analysis reporting.',
    `notes` STRING COMMENT 'Free-text field for operational notes, special instructions, or contextual information relevant to this post (e.g., Coordinate with LAPD liaison, VIP tunnel — no fan access, Elevated risk during derby matches).',
    `patrol_cycle_minutes` STRING COMMENT 'Expected duration in minutes for one complete patrol cycle for roving or mobile response posts. Used to calculate patrol frequency and identify coverage gaps during event operations.',
    `patrol_route_description` STRING COMMENT 'Narrative description of the patrol route or coverage area for roving and mobile response posts. Defines the geographic path, checkpoints, and frequency of patrol cycles. Applicable only to non-fixed post types.',
    `post_code` STRING COMMENT 'Alphanumeric business identifier for the security post, used operationally on event-day deployment sheets, radio logs, and staffing rosters. Unique within a venue (e.g., GT-01, FP-NW, CMD-01).. Valid values are `^[A-Z0-9]{2,20}$`',
    `post_name` STRING COMMENT 'Human-readable descriptive name of the security post as used in operational briefings and staffing plans (e.g., North Gate Entry, Field Perimeter West, Command Center Alpha).',
    `post_status` STRING COMMENT 'Current lifecycle status of the security post record. Active posts are available for staffing deployment; inactive posts are temporarily not in use; suspended posts are under review; decommissioned posts have been permanently retired.. Valid values are `active|inactive|suspended|decommissioned`',
    `post_type` STRING COMMENT 'Operational classification of the post defining its deployment mode. Fixed posts remain stationary (gates, tunnels, field perimeter); roving patrol posts cover a defined zone on foot or vehicle; mobile response posts are rapid-reaction positions; command center posts coordinate overall security operations. [ENUM-REF-CANDIDATE: fixed|roving_patrol|mobile_response|command_center|perimeter|access_control — promote to reference product]. Valid values are `fixed|roving_patrol|mobile_response|command_center|perimeter|access_control`',
    `priority_tier` STRING COMMENT 'Operational priority classification of the post indicating its criticality to overall venue security. Critical posts (e.g., field access, command center) must be staffed before lower-tier posts during resource constraints. Used in post coverage gap analysis.. Valid values are `critical|high|medium|low`',
    `radio_channel` STRING COMMENT 'Designated radio communications channel assigned to this post for coordination with the security command center and other posts. Critical for real-time incident response and law enforcement coordination (e.g., CH-1, TAC-3, CMD-MAIN).. Valid values are `^[A-Z0-9-]{1,20}$`',
    `required_staff_count` STRING COMMENT 'Minimum number of security officers required to be assigned to this post during an active shift. Used for event-day staffing deployment planning and post coverage gap analysis.',
    `shift_end_time` TIMESTAMP COMMENT 'Scheduled end timestamp of the security post shift window. Defines when officers are released from post. Used alongside shift_start_time to calculate total post coverage duration.',
    `shift_start_time` TIMESTAMP COMMENT 'Scheduled start timestamp of the security post shift window. Defines when officers must be in position. Used for event-day deployment scheduling and SAP SuccessFactors workforce scheduling integration.',
    `shift_type` STRING COMMENT 'Classification of the shift window relative to the event lifecycle. Pre-event shifts cover setup and ingress; event-day shifts cover active event operations; post-event shifts cover egress and venue clearance; overnight shifts cover facility security between events.. Valid values are `pre_event|event_day|post_event|overnight|full_day`',
    `source_system` STRING COMMENT 'Operational system of record from which this security post record originated. Supports data lineage and Silver Layer provenance tracking. Primary sources include Ticketmaster/AXS access control and SAP SuccessFactors workforce management.. Valid values are `ticketmaster_axs|sap_successfactors|manual|archtics|other`',
    `supervisor_post` BOOLEAN COMMENT 'Indicates whether this post is designated as a supervisory position responsible for overseeing a cluster of adjacent posts. Drives supervisory staffing requirements and chain-of-command reporting.',
    `surveillance_coverage` BOOLEAN COMMENT 'Indicates whether this post is supported by fixed CCTV or surveillance camera coverage, supplementing the physical officer presence. Used in security operations planning and incident investigation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this security post record. Used for change tracking, incremental data pipeline processing, and audit compliance on the Databricks Silver Layer.',
    `venue_zone` STRING COMMENT 'Designated physical zone or section of the venue where this post is located or patrols (e.g., Gate A, Lower Bowl, Field Level, Concourse 2, Parking Lot C). Aligns with Archtics venue seating and inventory zone definitions.',
    CONSTRAINT pk_post PRIMARY KEY(`post_id`)
) COMMENT 'Master record for all defined security officer posts and patrol assignments within Sports Entertainment venues — fixed posts (gate, tunnel, field perimeter, command center), roving patrol zones, and mobile response positions. Captures post code, venue zone, post type, required staffing level, shift window, post priority tier, and radio channel assignment. Used for event-day staffing deployment and post coverage gap analysis.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`post_assignment` (
    `post_assignment_id` BIGINT COMMENT 'Unique system-generated identifier for each security post assignment record. Primary key for the post_assignment data product.',
    `calendar_id` BIGINT COMMENT 'Reference to the sports or entertainment event for which this post assignment is created. Links to the event master record.',
    `employee_id` BIGINT COMMENT 'Reference to the security personnel (workforce member) assigned to this post. Sourced from SAP SuccessFactors Human Capital Management workforce records.',
    `fixture_id` BIGINT COMMENT 'Reference to the sports or entertainment event for which this post assignment is created. Links to the event master record.',
    `incident_report_id` BIGINT COMMENT 'Reference to the primary security incident report filed in connection with this post assignment. Null if no incident was reported. Supports post-event investigation and compliance reporting.',
    `post_id` BIGINT COMMENT 'Reference to the specific security post (physical location or zone) to which the officer is assigned. Links to the security post master record.',
    `primary_post_employee_id` BIGINT COMMENT 'Reference to the security personnel (workforce member) assigned to this post. Sourced from SAP SuccessFactors Human Capital Management workforce records.',
    `relief_officer_employee_id` BIGINT COMMENT 'Reference to the secondary security officer designated to relieve the primary assigned officer during the shift. Nullable when no relief is scheduled.',
    `staff_plan_id` BIGINT COMMENT 'Reference to the venue where the security post assignment is active. Enables venue-level staffing analysis and compliance reporting.',
    `supervisor_employee_id` BIGINT COMMENT 'Reference to the security supervisor responsible for overseeing this post assignment. Used for escalation routing and post-event accountability reporting.',
    `tertiary_post_supervisor_employee_id` BIGINT COMMENT 'Reference to the security supervisor responsible for overseeing this post assignment. Used for escalation routing and post-event accountability reporting.',
    `venue_id` BIGINT COMMENT 'Reference to the venue where the security post assignment is active. Enables venue-level staffing analysis and compliance reporting.',
    `relieved_post_assignment_id` BIGINT COMMENT 'Self-referencing FK on post_assignment (relieved_post_assignment_id)',
    `actual_duration_minutes` STRING COMMENT 'Actual number of minutes the officer was on post, calculated from confirmed check-in and check-out times. Used for payroll reconciliation and SLA compliance verification.',
    `ada_post` BOOLEAN COMMENT 'Indicates whether this post assignment is designated to support Americans with Disabilities Act (ADA) accessibility compliance, including assisting guests with disabilities in accessible seating or entry zones.',
    `assignment_number` STRING COMMENT 'Externally-known alphanumeric business identifier for this post assignment, used in operational communications, briefing sheets, and post-event reconciliation reports. Format: PA-{YYYY}-{NNNNNN}.. Valid values are `^PA-[0-9]{4}-[0-9]{6}$`',
    `assignment_source` STRING COMMENT 'Indicates how the post assignment was created or modified. manual = entered by scheduling staff; automated = generated by workforce management system; supervisor_override = changed by on-site supervisor; emergency_redeployment = reassigned due to incident.. Valid values are `manual|automated|supervisor_override|emergency_redeployment`',
    `assignment_status` STRING COMMENT 'Current lifecycle state of the post assignment. scheduled = confirmed but shift not started; active = officer currently on post; completed = shift ended and checked out; cancelled = assignment voided before shift; no_show = officer did not report; reassigned = officer replaced mid-shift.. Valid values are `scheduled|active|completed|cancelled|no_show|reassigned`',
    `assignment_type` STRING COMMENT 'Classification of the post assignment by operational function. Drives briefing requirements, equipment allocation, and staffing tier. [ENUM-REF-CANDIDATE: standard|vip|perimeter|access_control|crowd_management|emergency_response|surveillance|law_enforcement_liaison — promote to reference product]. Valid values are `standard|vip|perimeter|access_control|crowd_management|emergency_response`',
    `briefing_acknowledged` BOOLEAN COMMENT 'Indicates whether the assigned officer has formally acknowledged receipt and understanding of the post briefing notes. True = acknowledged; False = not yet acknowledged. Required for compliance audit trails.',
    `briefing_acknowledged_time` TIMESTAMP COMMENT 'Date and time the assigned officer formally acknowledged the post briefing. Null if briefing has not yet been acknowledged. Supports compliance and incident investigation audit trails.',
    `briefing_notes` STRING COMMENT 'Free-text field capturing post-specific operational instructions, threat advisories, VIP movement schedules, crowd management directives, or special protocols communicated to the officer prior to the shift.',
    `cancellation_reason` STRING COMMENT 'Reason code explaining why a post assignment was cancelled. Populated only when assignment_status = cancelled. Used for workforce planning analysis and post-event staffing review.. Valid values are `officer_unavailable|event_cancelled|post_eliminated|budget_reduction|duplicate_assignment`',
    `check_in_confirmed` BOOLEAN COMMENT 'Indicates whether the officers check-in at the post has been formally confirmed by a supervisor or access control system. True = confirmed; False = not yet confirmed or disputed.',
    `check_in_time` TIMESTAMP COMMENT 'Actual date and time the assigned security officer confirmed their presence at the post. Captured via access control system or supervisor confirmation. Null if officer has not yet checked in.',
    `check_out_confirmed` BOOLEAN COMMENT 'Indicates whether the officers check-out from the post has been formally confirmed by a supervisor or access control system. True = confirmed; False = not yet confirmed or disputed.',
    `check_out_time` TIMESTAMP COMMENT 'Actual date and time the assigned security officer departed or was relieved from the post. Null if officer has not yet checked out. Used for post-event staffing reconciliation.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time the post assignment record was first created in the system. Supports audit trail, data lineage, and compliance reporting requirements.',
    `credential_level` STRING COMMENT 'Required credential or clearance level for the assigned post, indicating the minimum qualification tier the officer must hold. Ensures regulatory and venue compliance for sensitive access zones.. Valid values are `level_1|level_2|level_3|level_4|law_enforcement`',
    `credential_verified` BOOLEAN COMMENT 'Indicates whether the assigned officers credentials have been verified as meeting the required credential level for this post prior to shift commencement. True = verified; False = pending or failed.',
    `crowd_density_zone` STRING COMMENT 'Expected crowd density classification for the post location at the time of assignment. Used to calibrate staffing ratios and crowd management protocols per venue safety plans.. Valid values are `low|medium|high|critical`',
    `emergency_response_role` STRING COMMENT 'Designated emergency response role for the officer at this post during a critical incident or evacuation. none = standard post with no special emergency designation.. Valid values are `none|first_responder|evacuation_lead|medical_liaison|command_post`',
    `equipment_issued` STRING COMMENT 'Comma-separated list or description of security equipment issued to the officer for this post assignment (e.g., radio, wand, body camera, access card). Supports equipment accountability and post-event inventory reconciliation.',
    `incident_reported` BOOLEAN COMMENT 'Indicates whether a security incident was reported by the officer at this post during the assigned shift. True = at least one incident report filed. Enables rapid post-event incident aggregation.',
    `law_enforcement_coordinated` BOOLEAN COMMENT 'Indicates whether this post assignment involves coordination with external law enforcement agencies (e.g., local police, federal agents). True = law enforcement coordination required or active.',
    `overtime_flag` BOOLEAN COMMENT 'Indicates whether this post assignment constitutes overtime hours for the assigned officer based on applicable labor agreements or Collective Bargaining Agreement (CBA) thresholds. True = overtime applies.',
    `pay_rate_code` STRING COMMENT 'Code referencing the applicable pay rate tier for this post assignment, used for payroll processing in SAP S/4HANA. Confidential as it relates to compensation structure.',
    `post_coverage_gap_minutes` STRING COMMENT 'Number of minutes the post was uncovered due to late check-in, early check-out, no-show, or relief delay. A value of 0 indicates continuous coverage. Critical KPI for post-event security audit.',
    `radio_channel` STRING COMMENT 'Designated radio channel or frequency assigned to this post for inter-team communications during the event. Critical for emergency response coordination and crowd management.',
    `relief_start_time` TIMESTAMP COMMENT 'Scheduled or actual time the relief officer takes over coverage of the post from the primary assigned officer. Null if no relief is scheduled.',
    `shift_date` DATE COMMENT 'Calendar date of the security shift. Used for day-level scheduling, reporting, and reconciliation independent of precise timestamps.',
    `shift_duration_minutes` STRING COMMENT 'Planned duration of the security shift in minutes, derived from scheduled start and end times. Used for payroll calculation inputs and staffing hour reporting.',
    `shift_end_time` TIMESTAMP COMMENT 'Scheduled date and time the security officer is expected to conclude coverage at the assigned post. Used for shift planning and staffing reconciliation.',
    `shift_start_time` TIMESTAMP COMMENT 'Scheduled date and time the security officer is expected to begin coverage at the assigned post. Used for shift planning and real-time post coverage visibility.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time the post assignment record was most recently modified. Tracks changes to scheduling, status, or briefing notes for audit and reconciliation purposes.',
    `vip_post` BOOLEAN COMMENT 'Indicates whether this post assignment is designated as a Very Important Person (VIP) security post, requiring enhanced protocols, elevated credential levels, and heightened situational awareness.',
    `zone_code` STRING COMMENT 'Alphanumeric code identifying the access control zone within the venue where the post is located (e.g., GA-FLOOR, VIP-SUITE, BACKSTAGE, PERIMETER-NORTH). Aligns with venue zone taxonomy in Archtics.',
    CONSTRAINT pk_post_assignment PRIMARY KEY(`post_assignment_id`)
) COMMENT 'Transactional record linking security personnel to specific security posts for a given event or shift. Captures post ID, assigned officer (workforce reference), event reference, shift start/end times, check-in confirmation, check-out confirmation, relief officer reference, and any post-specific briefing notes. Enables real-time post coverage visibility and post-event staffing reconciliation.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`security_incident` (
    `security_incident_id` BIGINT COMMENT 'Unique surrogate identifier for each security incident record in the Sports Entertainment security management system. Primary key for the security_incident data product.',
    `contingent_worker_id` BIGINT COMMENT 'Foreign key linking to workforce.contingent_worker. Business justification: Contingent security officers and vendor staff can be involved parties in security incidents (as responders or subjects). The existing employee_id covers staff employees only. Linking to contingent_wor',
    `employee_id` BIGINT COMMENT 'Reference to the primary security officer or staff member who responded to and documented the incident. Links to the workforce/employee master record in SAP SuccessFactors.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the specific Sports Entertainment event (game, concert, match) during which the security incident occurred. Enables event-level incident density analysis and post-event security debriefs.',
    `fan_fan_profile_id` BIGINT COMMENT 'Reference to the registered fan profile in the CRM system (Salesforce CRM / Adobe Experience Platform) if the involved party is an identified fan. Enables cross-referencing with ticketing history, ban records, and loyalty status.',
    `fan_profile_id` BIGINT COMMENT 'Reference to the registered fan profile in the CRM system (Salesforce CRM / Adobe Experience Platform) if the involved party is an identified fan. Enables cross-referencing with ticketing history, ban records, and loyalty status.',
    `fixture_id` BIGINT COMMENT 'Reference to the specific Sports Entertainment event (game, concert, match) during which the security incident occurred. Enables event-level incident density analysis and post-event security debriefs.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Security incidents at games are franchise-attributed for league disciplinary review, insurance claims, and competitive integrity reporting. League annual safety compliance reports aggregate incidents ',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-level incident aggregation is required for league safety compliance reporting, CBA player/fan safety provision reviews, and year-over-year trend analysis submitted to league governing bodies an',
    `membership_id` BIGINT COMMENT 'Foreign key linking to fan.membership. Business justification: League incident reporting and insurance claims require membership tier context at time of incident. VIP/season-ticket incidents trigger escalated CRM and legal protocols. Direct FK avoids multi-join t',
    `primary_security_employee_id` BIGINT COMMENT 'Reference to the primary security officer or staff member who responded to and documented the incident. Links to the workforce/employee master record in SAP SuccessFactors.',
    `retail_location_id` BIGINT COMMENT 'Foreign key linking to merchandise.retail_location. Business justification: Theft, fraud, and counterfeit-goods incidents occur at specific retail locations inside venues. Loss prevention reporting, insurance claims, and shrinkage analysis require attributing security inciden',
    `supervisor_employee_id` BIGINT COMMENT 'Reference to the security supervisor or duty manager who reviewed and approved the incident report. Required for escalation chain documentation and compliance sign-off.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to content.asset. Business justification: Security incident investigations require linking to the DAM asset containing the surveillance footage clip. Post-incident review, insurance claims, and law enforcement handoff processes all depend on ',
    `venue_id` BIGINT COMMENT 'Reference to the Sports Entertainment venue where the security incident occurred. Links to the venue master record for facility-level reporting and ADA/OSHA compliance tracking.',
    `escalated_from_security_incident_id` BIGINT COMMENT 'Self-referencing FK on security_incident (escalated_from_security_incident_id)',
    `ban_duration_days` STRING COMMENT 'Duration in days of the venue ban issued to the involved party. A value of -1 or null indicates a permanent ban. Populated when ban_issued is True.',
    `ban_issued` BOOLEAN COMMENT 'Indicates whether a venue ban or trespass notice was issued to the involved party as a result of this incident. Triggers downstream ban enforcement processes in Ticketmaster/AXS access control.',
    `closed_at` TIMESTAMP COMMENT 'Date and time the security incident case was formally closed following completion of all required actions, investigations, and documentation. Null if the incident remains open or under review.',
    `closure_notes` STRING COMMENT 'Free-text notes recorded at the time of case closure, summarizing final outcomes, follow-up actions completed, and any lessons learned for security operations improvement.',
    `created_at` TIMESTAMP COMMENT 'System-generated timestamp when the security incident record was first created in the data platform. Used for audit trail and data lineage purposes.',
    `credential_type_violated` STRING COMMENT 'Type of access credential involved in a credentialing violation incident (e.g., forged media pass, unauthorized field access badge). Populated when incident_type is credentialing_violation. [ENUM-REF-CANDIDATE: media|staff|vip|field_access|broadcast|vendor|athlete — 7 candidates stripped; promote to reference product]',
    `crowd_density_level` STRING COMMENT 'Estimated crowd density level in the incident zone at the time of the event. SRO (Standing Room Only) indicates maximum capacity. Used for crowd management protocol analysis and venue safety planning.. Valid values are `low|moderate|high|at_capacity|sro`',
    `disposition` STRING COMMENT 'Final outcome or action taken as a result of the security incident. Drives downstream processes including ban enforcement, medical referral, and law enforcement handoff. [ENUM-REF-CANDIDATE: ejected|arrested|warned|banned|referred_medical|no_action|trespass_notice|cited — promote to reference product]',
    `emergency_response_plan_activated` BOOLEAN COMMENT 'Indicates whether the venues formal Emergency Response Plan (ERP) was activated in response to this incident. Required for post-incident compliance review and insurance documentation.',
    `evacuation_triggered` BOOLEAN COMMENT 'Indicates whether the incident triggered a partial or full venue evacuation protocol. Drives post-incident emergency response plan review and regulatory reporting obligations.',
    `gate_identifier` STRING COMMENT 'Identifier of the entry/exit gate associated with the incident location, relevant for access control violations, prohibited item seizures, and credentialing breaches detected at ingress/egress points.',
    `incident_status` STRING COMMENT 'Current lifecycle state of the security incident case, tracking progression from initial report through investigation to final disposition and closure.. Valid values are `open|under_review|escalated|closed|voided`',
    `incident_type` STRING COMMENT 'Categorical classification of the security incident describing the nature of the event. [ENUM-REF-CANDIDATE: fan_altercation|ejection|prohibited_item_seizure|field_invasion|credentialing_violation|threat|suspicious_package|law_enforcement_intervention|trespassing|vandalism|theft|harassment — promote to reference product]',
    `insurance_claim_filed` BOOLEAN COMMENT 'Indicates whether an insurance claim was filed in connection with this security incident. Triggers financial reporting obligations and coordination with the Finance domain.',
    `insurance_claim_reference` STRING COMMENT 'Reference number for the insurance claim filed in connection with this incident. Confidential business data used for financial reconciliation in SAP S/4HANA. Populated when insurance_claim_filed is True.',
    `involved_party_id_number` STRING COMMENT 'Government-issued or venue-issued identification number (e.g., drivers license, passport, fan membership ID) for the primary involved party. Restricted PII used for law enforcement coordination and ban enforcement.',
    `involved_party_name` STRING COMMENT 'Full name of the primary individual involved in the security incident (subject, suspect, or victim). Classified as restricted PII under GDPR and CCPA. Required for law enforcement reporting and case management.',
    `involved_party_type` STRING COMMENT 'Classification of the primary party involved in or subject to the security incident. Determines applicable regulatory obligations (e.g., GDPR for fan data, CBA provisions for athlete incidents). [ENUM-REF-CANDIDATE: fan|athlete|staff|vendor|media|vip_guest|unknown — 7 candidates stripped; promote to reference product]',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency notified or involved in the incident response (e.g., NYPD, FBI Field Office, State Police). Populated when law_enforcement_notified is True.',
    `law_enforcement_case_number` STRING COMMENT 'Official case or report number assigned by the responding law enforcement agency. Used for cross-referencing with external law enforcement records and legal proceedings.',
    `law_enforcement_notified` BOOLEAN COMMENT 'Indicates whether local law enforcement (police, FBI, or other agency) was notified of the security incident. Required for regulatory reporting and incident severity escalation tracking.',
    `league_governing_body_reported` BOOLEAN COMMENT 'Indicates whether the incident was reported to the relevant league governing body (e.g., NFL, NBA, FIFA, NHL) per league security reporting obligations. Required for compliance with league security protocols and CBA provisions.',
    `medical_referral_required` BOOLEAN COMMENT 'Indicates whether the incident required a medical referral or emergency medical services (EMS) response. Triggers coordination with venue.safety_incident domain for OSHA recordkeeping when True.',
    `narrative` STRING COMMENT 'Free-text detailed description of the security incident as recorded by the responding officer, including sequence of events, actions taken, and any relevant contextual observations. Primary source for legal and insurance documentation.',
    `number_of_persons_involved` STRING COMMENT 'Total count of individuals directly involved in the security incident (subjects, victims, and witnesses). Used for incident severity assessment and resource deployment analysis.',
    `occurred_at` TIMESTAMP COMMENT 'The precise date and time the security incident occurred or was first observed, representing the principal real-world event time. Distinct from the record creation timestamp. Critical for timeline reconstruction and law enforcement reporting.',
    `prohibited_item_description` STRING COMMENT 'Free-text description of the specific prohibited item seized, including make, model, quantity, or other identifying characteristics. Supports chain-of-custody documentation and law enforcement handoff.',
    `prohibited_item_type` STRING COMMENT 'Classification of the prohibited item seized during the incident, applicable when incident_type is prohibited_item_seizure (e.g., weapon, alcohol, pyrotechnic, laser pointer, drone). [ENUM-REF-CANDIDATE: weapon|alcohol|pyrotechnic|laser_pointer|drone|controlled_substance|recording_device|other — promote to reference product]',
    `reference_number` STRING COMMENT 'Externally-known alphanumeric case number assigned at the time of incident creation, used for cross-system tracking, law enforcement reporting, and insurance claims. Format: SEC-YYYY-NNNNNN.. Valid values are `^SEC-[0-9]{4}-[0-9]{6}$`',
    `reported_at` TIMESTAMP COMMENT 'Date and time the incident was formally reported to the security operations center or duty manager, which may differ from the occurrence time. Used to measure reporting lag and response readiness.',
    `response_time_minutes` STRING COMMENT 'Elapsed time in minutes between the incident occurrence timestamp and the arrival of the first responding security officer. Key performance indicator (KPI) for security operations SLA compliance and staffing adequacy reviews.',
    `section_identifier` STRING COMMENT 'Specific section, block, or area designation within the venue zone where the incident took place (e.g., Section 112, Row G, Gate 4 Entry). Sourced from Archtics seating inventory for precise location mapping.',
    `severity_tier` STRING COMMENT 'Standardized severity classification assigned to the incident at time of reporting, used to prioritize response resources and escalation protocols. Tier 1 Critical requires immediate law enforcement; Tier 4 Low is handled by venue security staff.. Valid values are `tier_1_critical|tier_2_high|tier_3_medium|tier_4_low`',
    `surveillance_footage_available` BOOLEAN COMMENT 'Indicates whether CCTV or surveillance camera footage is available and has been preserved for this incident. Critical for evidence management, legal proceedings, and post-incident review.',
    `surveillance_footage_reference` STRING COMMENT 'Reference identifier or storage path for the associated surveillance footage clip in the Digital Asset Management (DAM) system (Dalet Galaxy). Populated when surveillance_footage_available is True.',
    `updated_at` TIMESTAMP COMMENT 'System-generated timestamp of the most recent modification to the security incident record, supporting audit trail requirements and change tracking.',
    `zone_code` STRING COMMENT 'Alphanumeric code identifying the access control zone within the venue where the incident occurred (e.g., GA-FLOOR, VIP-SUITE, FIELD-LEVEL, CONCOURSE-A). Aligns with Archtics venue seating and zone inventory definitions.',
    CONSTRAINT pk_security_incident PRIMARY KEY(`security_incident_id`)
) COMMENT 'Core transactional record for all security incidents occurring at Sports Entertainment venues and events — fan altercations, ejections, prohibited item seizures, field invasions, credentialing violations, threats, suspicious packages, and law enforcement interventions. Captures incident type, severity tier, location (zone/section/gate), involved parties, responding officers, law enforcement notification flag, medical referral flag, narrative, disposition, and case closure status. Distinct from venue.safety_incident which covers physical safety/OSHA events.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`ejection_record` (
    `ejection_record_id` BIGINT COMMENT 'Unique system-generated identifier for each ejection record. Primary key for the ejection_record data product within the security domain.',
    `calendar_id` BIGINT COMMENT 'Reference to the Sports Entertainment event during which the ejection occurred. Used to correlate ejection volume with event type, attendance, and security staffing levels.',
    `contingent_worker_id` BIGINT COMMENT 'Foreign key linking to workforce.contingent_worker. Business justification: Contracted security officers (contingent workers) perform fan ejections at events. The ejection_record.employee_id covers staff employees only. Tracking which contingent officer performed an ejection ',
    `employee_id` BIGINT COMMENT 'Reference to the security officer or staff member who executed the ejection, as recorded in SAP SuccessFactors workforce records. Used for officer performance review, training needs analysis, and legal accountability.',
    `account_id` BIGINT COMMENT 'Reference to the fans CRM account record in Salesforce CRM, used to link the ejection to the fans profile for ban enforcement, repeat offender tracking, and communication history.',
    `fan_profile_id` BIGINT COMMENT 'Foreign key linking to fan.fan_profile. Business justification: Ejection history must be surfaced in the fan CRM profile for repeat-offender tracking, ban enforcement, and league regulatory reporting. The existing account link is insufficient for identity resoluti',
    `fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event during which the ejection occurred. Used to correlate ejection volume with event type, attendance, and security staffing levels.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Ejection records must be franchise-attributed for league disciplinary review, franchise-level fan conduct reporting, and CBA compliance covering fan safety provisions. League operations tracks ejectio',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped ejection aggregation is required for league annual fan conduct reports, franchise compliance reviews, and year-over-year safety trend analysis submitted to league governing bodies.',
    `litigation_case_id` BIGINT COMMENT 'Foreign key linking to legal.litigation_case. Business justification: Ejection records are central evidence in wrongful ejection, assault, and civil rights litigation. Legal teams defending ejection decisions require this link to retrieve the ejection record during disc',
    `primary_ejection_employee_id` BIGINT COMMENT 'Reference to the security officer or staff member who executed the ejection, as recorded in SAP SuccessFactors workforce records. Used for officer performance review, training needs analysis, and legal accountability.',
    `security_incident_id` BIGINT COMMENT 'Reference to the originating security incident record that triggered this ejection. Links the ejection to the broader incident context including initial report, escalation chain, and responding officers.',
    `service_case_id` BIGINT COMMENT 'Foreign key linking to fan.service_case. Business justification: Ejection appeals, wrongful-ejection complaints, and fan compensation requests generate CRM service cases directly tied to the ejection record. Direct FK enables case managers to retrieve ejection deta',
    `staff_plan_id` BIGINT COMMENT 'Reference to the venue where the ejection took place. Supports venue-level security analytics, staffing benchmarks, and ADA/OSHA compliance reporting.',
    `supervisor_employee_id` BIGINT COMMENT 'Reference to the security supervisor who authorized or oversaw the ejection. Required for escalated ejections involving law enforcement handoff or ban recommendations, ensuring chain-of-command accountability.',
    `venue_id` BIGINT COMMENT 'Reference to the venue where the ejection took place. Supports venue-level security analytics, staffing benchmarks, and ADA/OSHA compliance reporting.',
    `related_ejection_record_id` BIGINT COMMENT 'Self-referencing FK on ejection_record (related_ejection_record_id)',
    `appeal_filed_flag` BOOLEAN COMMENT 'Indicates whether the ejected individual has formally filed an appeal against the ejection decision. True = appeal filed; False = no appeal filed. Triggers the ejection review workflow and updates ejection_status to appealed.',
    `appeal_resolution_date` DATE COMMENT 'The date on which the formal appeal of the ejection was resolved. Populated when ejection_status transitions to upheld or overturned. Used for SLA (Service Level Agreement) tracking of the appeals process.',
    `arrest_made_flag` BOOLEAN COMMENT 'Indicates whether the ejected individual was formally arrested by law enforcement at or following the ejection. True = arrest was made; False = no arrest. Relevant for legal proceedings, insurance claims, and ban severity determination.',
    `ban_recommendation_flag` BOOLEAN COMMENT 'Indicates whether the ejecting officer or supervisor has recommended a venue ban for the ejected individual. True = ban recommended; False = no ban recommended. Feeds the venue ban registry workflow for formal ban issuance.',
    `ban_registry_reference` BIGINT COMMENT 'Reference to the formal ban record created in the venue ban registry as a result of this ejection. Populated after the ban is formally issued following the recommendation workflow. Null if no ban was issued.',
    `ban_type` STRING COMMENT 'Classification of the recommended or issued ban scope. Populated when ban_recommendation_flag is True. Drives the ban registry entry type and enforcement duration. [ENUM-REF-CANDIDATE: single_event|season|multi_season|lifetime|league_wide — promote to reference product]. Valid values are `single_event|season|multi_season|lifetime|league_wide`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this ejection record was first created in the system. Represents the audit trail creation time, distinct from the ejection_timestamp which captures the real-world event time. Required for data lineage and compliance audit trails.',
    `crowd_density_level` STRING COMMENT 'Assessed crowd density level in the ejection zone at the time of the incident. Used for crowd management analysis, security staffing optimization, and post-event safety reviews. Aligns with ISO 20121 event sustainability and safety management standards.. Valid values are `low|moderate|high|critical`',
    `data_source_system` STRING COMMENT 'Identifies the operational system of record from which this ejection record originated or was primarily sourced. Supports data lineage tracking and Silver Layer reconciliation in the Databricks Lakehouse.. Valid values are `ticketmaster_axs|salesforce_crm|manual_entry|archtics|adobe_experience_platform`',
    `ejected_party_id_number` STRING COMMENT 'The identification document number (e.g., drivers license number, passport number) of the ejected individual as recorded for ban enforcement and law enforcement handoff. Stored in compliance with GDPR and CCPA data minimization principles.',
    `ejected_party_id_type` STRING COMMENT 'Type of identification document presented or used to identify the ejected individual at the time of ejection. Supports identity verification for ban enforcement and law enforcement handoff.. Valid values are `drivers_license|passport|national_id|fan_membership_card|employee_badge|none_presented`',
    `ejected_party_name` STRING COMMENT 'Full name of the individual who was ejected, as recorded at the time of ejection from identification documents or ticketing records. Required for ban enforcement, law enforcement handoff documentation, and legal proceedings.',
    `ejected_party_type` STRING COMMENT 'Classification of the type of individual who was ejected. Determines the applicable code of conduct, ban enforcement pathway, and reporting requirements. VIP (Very Important Person) guests and media personnel follow distinct escalation protocols.. Valid values are `fan|staff|media|vendor|athlete|vip_guest`',
    `ejecting_officer_badge` STRING COMMENT 'The badge or credential number of the security officer who performed the ejection. Serves as the operational identifier used in field documentation, law enforcement handoff forms, and incident reports independent of the internal workforce system ID.. Valid values are `^[A-Z]{2}-[0-9]{4,6}$`',
    `ejection_reason_code` STRING COMMENT 'Standardized reason code classifying the primary cause of the ejection. Drives ban recommendation logic, repeat offender scoring, and regulatory reporting. [ENUM-REF-CANDIDATE: intoxication|fighting|field_invasion|harassment|prohibited_item|threatening_behavior|racial_abuse|ticket_fraud — promote to reference product]',
    `ejection_reason_description` STRING COMMENT 'Free-text narrative description of the specific circumstances leading to the ejection, as recorded by the ejecting security officer. Supplements the standardized reason code with contextual detail for incident review and legal proceedings.',
    `ejection_reference_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to this ejection at the time of occurrence, used in law enforcement handoff documentation, ban notices, and fan appeals. Format: EJ-{YYYY}-{NNNNNN}.. Valid values are `^EJ-[0-9]{4}-[0-9]{6}$`',
    `ejection_status` STRING COMMENT 'Current lifecycle state of the ejection record. pending indicates the ejection is being processed; confirmed means the ejection is finalized; appealed means the ejected party has filed a formal appeal; overturned means the ejection was reversed upon review; upheld means the ejection was sustained after appeal.. Valid values are `pending|confirmed|appealed|overturned|upheld`',
    `ejection_timestamp` TIMESTAMP COMMENT 'The precise date and time at which the ejection was executed — i.e., when the individual physically exited or was removed from the venue. This is the principal real-world business event time, distinct from when the record was created in the system.',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency to which the ejected individual was handed off (e.g., NYPD, LAPD, Stadium Authority Police). Populated only when law_enforcement_handoff_flag is True.',
    `law_enforcement_case_number` STRING COMMENT 'The official case or report number assigned by the receiving law enforcement agency at the time of handoff. Used for cross-referencing with police records and legal proceedings.',
    `law_enforcement_handoff_flag` BOOLEAN COMMENT 'Indicates whether the ejected individual was handed off to law enforcement (police, stadium security authority) at the time of ejection. True = law enforcement was involved; False = internal security handled the ejection without law enforcement transfer.',
    `medical_assistance_required_flag` BOOLEAN COMMENT 'Indicates whether medical assistance was required for the ejected individual or any other party involved in the incident (e.g., intoxication requiring EMT response, injury from altercation). True = medical assistance was provided or requested; False = no medical assistance needed.',
    `prior_ejection_count` STRING COMMENT 'The number of prior ejections on record for this individual at the time of this ejection event. Used to determine escalation thresholds for ban recommendations and repeat offender classification. Sourced from the ejection history at time of record creation.',
    `prohibited_item_description` STRING COMMENT 'Description of any prohibited item(s) found on or associated with the ejected individual. Populated when ejection_reason_code is prohibited_item. Includes item type, quantity, and disposition (confiscated, surrendered, etc.).',
    `repeat_offender_flag` BOOLEAN COMMENT 'Indicates whether the ejected individual has a prior ejection record within the Sports Entertainment system at the time of this ejection. True = prior ejection(s) on record; False = first-time ejection. Drives escalated ban recommendations and repeat offender tracking workflows.',
    `seat_number` STRING COMMENT 'The specific seat number assigned to the ejected individual within their row and section. Enables precise location correlation with ticketing records for ban enforcement and refund processing.',
    `seat_row` STRING COMMENT 'The row identifier within the seating section where the ejected individual was located. Used in conjunction with seat_section and seat_number for precise location tracking and witness identification.',
    `seat_section` STRING COMMENT 'The seating section identifier (e.g., 114, GA, SRO) where the ejected individual was located at the time of the incident, as recorded in Archtics or Ticketmaster/AXS access control systems.',
    `surveillance_clip_reference` STRING COMMENT 'Digital Asset Management (DAM) reference identifier for the surveillance footage clip associated with this ejection, stored in the Dalet Galaxy media asset management system. Populated when surveillance_footage_available_flag is True.',
    `surveillance_footage_available_flag` BOOLEAN COMMENT 'Indicates whether surveillance camera footage of the ejection incident is available and has been flagged for retention. True = footage available and retained; False = no footage available. Supports legal proceedings, appeals, and security system audits.',
    `ticket_barcode` STRING COMMENT 'The barcode or digital token from the ejected individuals ticket as scanned at entry or at the point of ejection via Ticketmaster/AXS access control. Links the ejection to the specific ticket transaction for ban enforcement and refund eligibility determination.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this ejection record was most recently modified. Tracks updates to ejection status, ban recommendations, appeal outcomes, and law enforcement case numbers. Required for data lineage and Silver Layer change tracking.',
    `venue_zone_code` STRING COMMENT 'Alphanumeric code identifying the specific zone or section of the venue where the ejection incident originated, as defined in the Archtics venue seating and inventory management system (e.g., SEC-114, FIELD-LEVEL, CONCOURSE-B). Used for crowd management hotspot analysis.',
    `venue_zone_type` STRING COMMENT 'Classification of the venue zone where the ejection occurred. Supports access control analysis and security resource allocation by zone category. [ENUM-REF-CANDIDATE: seating_bowl|field_level|concourse|vip_suite|media_zone|backstage|parking|entry_gate — promote to reference product]',
    CONSTRAINT pk_ejection_record PRIMARY KEY(`ejection_record_id`)
) COMMENT 'Transactional record of every fan or personnel ejection from a Sports Entertainment venue or event. Captures ejection date/time, venue zone, reason code (intoxication, fighting, field invasion, harassment, prohibited item), ejecting officer, law enforcement handoff flag, ban recommendation flag, originating security incident reference, and fan account reference for ban enforcement. Feeds the venue ban registry and repeat offender tracking.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`venue_ban` (
    `venue_ban_id` BIGINT COMMENT 'Unique system-generated identifier for each venue ban or trespass order record. Primary key for the venue_ban data product.',
    `doping_violation_id` BIGINT COMMENT 'Foreign key linking to compliance.doping_violation. Business justification: Athletes subject to doping bans are prohibited from participating in or attending sanctioned events. Security venue ban records must reference the doping violation that triggered the ban to enforce ac',
    `ejection_record_id` BIGINT COMMENT 'Reference to the originating ejection or security incident record that triggered the issuance of this venue ban. Links ban enforcement to the root cause event.',
    `account_id` BIGINT COMMENT 'Reference to the Sports Entertainment fan account associated with the banned individual, if the individual is a registered fan. Null when the banned individual has no fan account on record.',
    `fan_profile_id` BIGINT COMMENT 'Foreign key linking to fan.fan_profile. Business justification: Ban enforcement at entry points, watchlist screening, and GDPR right-to-erasure processing all operate against the canonical fan_profile identity record. The existing fan_account link is insufficient ',
    `fixture_id` BIGINT COMMENT 'Reference to the specific event to which an event-specific ban applies. Populated only when ban_type is event_specific or enforcement_scope is event_specific. Null for season, multi-season, or permanent bans.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Venue bans restrict access to specific franchise home games. Franchise-level ban enforcement, league disciplinary reporting, and CBA fan conduct compliance all require linking bans to the issuing fran',
    `venue_id` BIGINT COMMENT 'Reference to the venue that issued this ban. Determines the primary enforcement jurisdiction and the venue whose access control systems must enforce the ban.',
    `league_id` BIGINT COMMENT 'Reference to the league or competition governing body under whose jurisdiction this ban was issued. Relevant for league-wide bans coordinated with governing bodies such as the NFL, NBA, MLB, NHL, or MLS.',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped venue bans support league annual fan conduct compliance reporting, franchise ban enforcement tracking, and CBA fan safety provision reviews. ban_season is a denormalized text field repla',
    `litigation_case_id` BIGINT COMMENT 'Foreign key linking to legal.litigation_case. Business justification: Venue bans are challenged through litigation (wrongful ban, civil rights claims). Legal teams defending ban decisions need to link the ban record to the active litigation case for discovery management',
    `sanction_id` BIGINT COMMENT 'Foreign key linking to compliance.sanction. Business justification: Governing body sanctions (e.g., FIFA, NFL disciplinary sanctions against fans or officials) result in venue bans that security must enforce at access control points. Security operations need to refere',
    `security_incident_id` BIGINT COMMENT 'Reference to the originating ejection or security incident record that triggered the issuance of this venue ban. Links ban enforcement to the root cause event.',
    `service_case_id` BIGINT COMMENT 'Reference identifier for the associated case record in Salesforce CRM, where fan communications, appeal correspondence, and case notes related to this ban are managed.',
    `settlement_agreement_id` BIGINT COMMENT 'Foreign key linking to legal.settlement_agreement. Business justification: Venue bans are frequently issued as non-monetary terms in settlement agreements resolving fan assault or ejection litigation. Legal compliance monitoring requires linking the ban record to the settlem',
    `specific_event_fixture_id` BIGINT COMMENT 'Reference to the specific event to which an event-specific ban applies. Populated only when ban_type is event_specific or enforcement_scope is event_specific. Null for season, multi-season, or permanent bans.',
    `suspension_record_id` BIGINT COMMENT 'Foreign key linking to athlete.suspension_record. Business justification: When a league suspension triggers a venue ban, security operations must enforce credential denial at access control points. Linking venue_ban to the originating suspension_record enables security staf',
    `extended_venue_ban_id` BIGINT COMMENT 'Self-referencing FK on venue_ban (extended_venue_ban_id)',
    `appeal_lodged_date` DATE COMMENT 'Date on which the banned individual formally lodged an appeal against this venue ban. Null when no appeal has been submitted.',
    `appeal_resolved_date` DATE COMMENT 'Date on which the appeal was formally resolved and a decision communicated to the banned individual. Null when appeal is still pending.',
    `appeal_status` STRING COMMENT 'Current status of any formal appeal lodged by the banned individual against this venue ban. Tracks the appeal lifecycle from submission through resolution.. Valid values are `not_appealed|appeal_pending|appeal_upheld|appeal_denied|appeal_withdrawn`',
    `ban_end_date` DATE COMMENT 'The calendar date on which the venue ban expires and enforcement ceases. Null for permanent bans with no defined expiry date.',
    `ban_issued_timestamp` TIMESTAMP COMMENT 'The precise date and time at which the venue ban was formally issued and recorded in the system. Represents the principal business event timestamp for this transaction.',
    `ban_reason_category` STRING COMMENT 'Standardised category classifying the primary reason for the venue ban. Used for reporting, trend analysis, and compliance with league conduct governance. [ENUM-REF-CANDIDATE: violence|harassment|intoxication|trespass|prohibited_item|fraud|racism_discrimination|other — promote to reference product]',
    `ban_reason_description` STRING COMMENT 'Free-text narrative describing the specific circumstances and conduct that led to the issuance of this venue ban. Supplements the standardised reason category with case-specific detail for legal and operational review.',
    `ban_reference_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to this ban record, used in correspondence with law enforcement, legal counsel, and the banned individual. Format: BAN-YYYY-NNNNNN.. Valid values are `^BAN-[0-9]{4}-[0-9]{6}$`',
    `ban_start_date` DATE COMMENT 'The calendar date on which the venue ban becomes effective and enforcement begins across all applicable access control systems.',
    `ban_status` STRING COMMENT 'Current lifecycle state of the venue ban. Active bans are enforced at all applicable access control points. Suspended bans are temporarily paused pending appeal or legal review. Expired bans have passed their end date. Reinstated bans were previously lifted but re-activated. Appealed bans are under formal review. Cancelled bans were rescinded.. Valid values are `active|suspended|expired|reinstated|appealed|cancelled`',
    `ban_type` STRING COMMENT 'Classification of the ban scope and duration. Event-specific bans apply to a single event; season bans cover an entire competition season; multi-season bans span multiple seasons; permanent bans have no expiry; conditional bans are contingent on specific behavioural conditions being met.. Valid values are `event_specific|season|multi_season|permanent|conditional`',
    `ban_violation_count` STRING COMMENT 'Number of recorded instances where the banned individual has attempted to or successfully gained access to a venue in violation of this ban. Used to escalate enforcement actions and support prosecution.',
    `banned_person_date_of_birth` DATE COMMENT 'Date of birth of the banned individual, used for positive identity verification at venue access control points and in law enforcement trespass order documentation.',
    `banned_person_full_name` STRING COMMENT 'Full legal name of the banned individual. Required for identity verification at access control points and for law enforcement trespass order documentation. Applies to both registered fan account holders and external individuals with no fan account.',
    `banned_person_id_number` STRING COMMENT 'Government-issued identification number (e.g., drivers licence, passport, national ID) of the banned individual, used for positive identity verification and law enforcement coordination. Stored in compliance with applicable data minimisation requirements.',
    `banned_person_id_type` STRING COMMENT 'Type of government-issued identification document provided for the banned individual. Used alongside the ID number for identity verification at access control points.. Valid values are `drivers_licence|passport|national_id|state_id|other`',
    `data_retention_expiry_date` DATE COMMENT 'Date on which this ban record is scheduled for review or deletion in accordance with applicable data retention policies. Ensures compliance with GDPR data minimisation and storage limitation principles, particularly for expired or cancelled bans.',
    `enforcement_scope` STRING COMMENT 'Defines the geographic and operational scope of the ban enforcement. Single-venue bans apply only to the issuing venue; all-venues bans apply across all Sports Entertainment venues; league-wide bans are coordinated with the governing league body; event-specific bans apply only to a designated event.. Valid values are `single_venue|all_venues|league_wide|event_specific`',
    `internal_notes` STRING COMMENT 'Confidential free-text field for internal security team notes regarding this ban, including risk assessments, escalation history, and coordination details with law enforcement. Not shared externally.',
    `issuing_authority_name` STRING COMMENT 'Name of the Sports Entertainment official, security manager, or authorised representative who issued and signed off on this venue ban. Provides accountability and audit trail for ban issuance.',
    `issuing_authority_title` STRING COMMENT 'Job title or role of the Sports Entertainment official who issued this venue ban (e.g., Head of Security, Venue Operations Manager). Supports governance and escalation workflows.',
    `last_violation_date` DATE COMMENT 'Date of the most recent recorded violation of this venue ban. Null when no violations have been recorded. Used to trigger escalation workflows and law enforcement referrals.',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency that issued or co-signed the trespass order associated with this ban. Used for coordination and escalation in the event of a ban violation.',
    `notification_method` STRING COMMENT 'Channel through which the formal ban notification was delivered to the banned individual. Certified mail and in-person delivery provide stronger legal proof of receipt.. Valid values are `email|postal_mail|in_person|certified_mail|other`',
    `notification_sent` BOOLEAN COMMENT 'Indicates whether formal written notification of the venue ban has been dispatched to the banned individual. Required for due process compliance and legal enforceability of the ban.',
    `notification_sent_date` DATE COMMENT 'Date on which the formal ban notification was dispatched to the banned individual. Null when notification has not yet been sent.',
    `photo_id_on_file` BOOLEAN COMMENT 'Indicates whether a photograph of the banned individual has been captured and stored in the security system to support visual identification at access control points.',
    `record_created_timestamp` TIMESTAMP COMMENT 'The date and time when this venue ban record was first created in the data platform. Used for audit trail and data lineage purposes.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this venue ban record was most recently modified. Tracks changes to ban status, reinstatement eligibility, or other mutable fields.',
    `reinstatement_conditions` STRING COMMENT 'Free-text description of the specific conditions the banned individual must satisfy to be eligible for reinstatement (e.g., completion of anger management programme, payment of fines, written apology). Populated when reinstatement_eligible is True.',
    `reinstatement_eligible` BOOLEAN COMMENT 'Indicates whether the banned individual is eligible to apply for reinstatement and lifting of the ban upon meeting defined conditions. False for permanent bans or bans where reinstatement has been explicitly denied.',
    `reinstatement_review_date` DATE COMMENT 'Scheduled date on which the ban is due for reinstatement eligibility review. Enables proactive case management and ensures timely processing of reinstatement applications.',
    `ticketing_account_suspended` BOOLEAN COMMENT 'Indicates whether the banned individuals ticketing account has been suspended in Ticketmaster/AXS as part of ban enforcement, preventing future ticket purchases and access credential generation.',
    `trespass_order_number` STRING COMMENT 'Official trespass order or notice number issued by law enforcement authorities in conjunction with this venue ban. Enables cross-referencing with police records and supports prosecution if the banned individual violates the order.',
    CONSTRAINT pk_venue_ban PRIMARY KEY(`venue_ban_id`)
) COMMENT 'Master record of all active and historical venue bans and trespass orders issued against individuals by Sports Entertainment. Captures banned individual identity (fan account or external person reference), ban type (event-specific, season, permanent), issuing venue, ban start/end dates, reason, originating ejection or incident reference, law enforcement trespass order number, reinstatement eligibility flag, and ban status. SSOT for ban enforcement across all venue access control operations.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`crowd_management_plan` (
    `crowd_management_plan_id` BIGINT COMMENT 'Unique surrogate identifier for the crowd management plan record. Primary key for this entity.',
    `calendar_id` BIGINT COMMENT 'Reference to the specific event for which this crowd management plan was developed. Links the plan to the event scheduling and ticketing context.',
    `fixture_id` BIGINT COMMENT 'Reference to the specific event for which this crowd management plan was developed. Links the plan to the event scheduling and ticketing context.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Crowd management plans are developed per franchise home game context. Franchise linkage enables franchise-specific plan versioning, league-mandated plan review cycles, and franchise safety compliance ',
    `governing_body_id` BIGINT COMMENT 'Foreign key linking to compliance.governing_body. Business justification: League and sports governing bodies (NFL, UEFA, FIFA) mandate specific crowd management standards and must approve crowd management plans before events. The plan already tracks submitted_to_authority_d',
    `kpi_definition_id` BIGINT COMMENT 'Foreign key linking to analytics.kpi_definition. Business justification: Crowd Safety KPI Governance process: crowd management plans are measured against approved KPIs (evacuation time target, occupancy threshold compliance, ingress rate). Linking to kpi_definition enables',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped crowd management plans are required for league annual safety compliance submissions and CBA-mandated player/fan safety reviews. Season tagging enables plan lifecycle management aligned t',
    `regulatory_license_id` BIGINT COMMENT 'Foreign key linking to legal.regulatory_license. Business justification: Crowd management plans are a mandatory condition of venue operating licenses and event permits issued by local authorities and fire marshals. Legal teams verify plan compliance against license conditi',
    `staff_plan_id` BIGINT COMMENT 'Reference to the venue at which this crowd management plan applies. Determines the physical layout, zone configuration, and egress infrastructure.',
    `venue_id` BIGINT COMMENT 'Reference to the venue at which this crowd management plan applies. Determines the physical layout, zone configuration, and egress infrastructure.',
    `superseded_crowd_management_plan_id` BIGINT COMMENT 'Self-referencing FK on crowd_management_plan (superseded_crowd_management_plan_id)',
    `alcohol_cutoff_time` TIMESTAMP COMMENT 'Scheduled timestamp at which alcohol sales and service must cease during the event, as mandated by local licensing conditions or league policy. Null when alcohol service is not permitted.',
    `alcohol_service_permitted` BOOLEAN COMMENT 'Indicates whether alcohol service is permitted at this event under this plan. Alcohol service status directly influences crowd behavior risk assessment, staffing ratios, and incident response protocols.',
    `approval_timestamp` TIMESTAMP COMMENT 'Date and time at which the venue security director formally approved this version of the crowd management plan. Establishes the audit trail for regulatory compliance and event licensing submissions.',
    `approved_by` STRING COMMENT 'Full name of the venue security director or authorized delegate who provided formal sign-off approval for this crowd management plan version. Required for regulatory compliance and event licensing.',
    `authority_approval_date` DATE COMMENT 'Date on which the local authority, fire marshal, or governing body granted formal approval of this crowd management plan. Null if approval is pending or not required.',
    `bag_policy_type` STRING COMMENT 'Bag screening policy in effect for this event. Clear_bag_only requires transparent bags meeting size specifications; no_bag prohibits all bags; standard_search allows bags subject to manual inspection; no_restriction applies no bag limitations.. Valid values are `clear_bag_only|no_bag|standard_search|no_restriction`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp at which this crowd management plan record was first created in the system. Supports audit trail, data lineage, and compliance reporting requirements.',
    `crowd_flow_strategy` STRING COMMENT 'Operational strategy governing how attendees are directed through the venue during ingress and egress. Zoned entry assigns gates by seating section; timed entry staggers arrival windows; general admission (GA) is open flow; VIP priority provides dedicated lanes; staggered release controls post-event exit sequencing; hybrid combines multiple approaches.. Valid values are `zoned_entry|timed_entry|general_admission|vip_priority|staggered_release|hybrid`',
    `effective_date` DATE COMMENT 'Calendar date on which this crowd management plan version becomes operationally binding. Typically aligned with the event date or the start of a multi-day event series.',
    `emergency_contact_name` STRING COMMENT 'Full name of the primary emergency operations contact responsible for activating the emergency response plan during the event. Confidential operational information restricted to security command staff.',
    `emergency_contact_phone` STRING COMMENT 'Direct phone number for the primary emergency operations contact. Restricted to security command staff and used exclusively for emergency activation communications.. Valid values are `^+?[0-9s-().]{7,20}$`',
    `evacuation_route_description` STRING COMMENT 'Narrative description of the primary and secondary emergency evacuation routes for the venue under this plan, including designated assembly points, exit sequencing by zone, and any route modifications due to venue configuration or construction. Supports compliance with OSHA emergency action plan requirements.',
    `evacuation_time_target_minutes` STRING COMMENT 'Target maximum time in minutes to fully evacuate the venue under emergency conditions, as established by the venue security director and validated against fire marshal requirements. Benchmark for drill performance and plan adequacy reviews.',
    `expected_attendance` STRING COMMENT 'Projected total number of attendees for the event based on ticket sales data from Ticketmaster/AXS, historical attendance patterns, and pre-event demand signals. Used to calibrate staffing levels, gate activation, and ingress timing.',
    `expiry_date` DATE COMMENT 'Calendar date after which this crowd management plan is no longer valid. For single-event plans this is typically the event end date; for venue standing plans this may be an annual renewal date.',
    `gate_close_time` TIMESTAMP COMMENT 'Scheduled timestamp at which entry gates are closed to new arrivals. After this time, late arrivals may be directed to designated late-entry points per the plan.',
    `gate_open_time` TIMESTAMP COMMENT 'Scheduled timestamp at which venue entry gates open to the public. Typically set 90-120 minutes before event start time to distribute ingress load and reduce peak crowding.',
    `gates_activated_count` STRING COMMENT 'Total number of entry gates scheduled to be open and staffed during peak ingress as defined in the gate activation schedule. Determines throughput capacity and is calibrated against expected attendance.',
    `high_risk_flag` BOOLEAN COMMENT 'Indicates whether this event has been classified as high-risk based on threat intelligence, historical incident data, rivalry classification, or law enforcement advisories. When True, elevated security protocols, additional staffing, and enhanced surveillance are mandated.',
    `last_drill_date` DATE COMMENT 'Date of the most recent evacuation or emergency response drill conducted against this plan. Used to verify plan currency and compliance with regulatory drill frequency requirements.',
    `law_enforcement_agency` STRING COMMENT 'Name of the primary law enforcement agency coordinating with venue security for this event (e.g., local police department, state police, federal agency). Establishes the command structure for public safety incidents.',
    `law_enforcement_contact` STRING COMMENT 'Name and contact details of the designated law enforcement liaison officer for this event. Confidential operational information used by venue security director and event command staff.',
    `magnetometer_screening` BOOLEAN COMMENT 'Indicates whether walk-through magnetometer or wand screening is deployed at entry gates for this event. Drives gate throughput calculations and staffing requirements for security screening lanes.',
    `max_safe_occupancy` STRING COMMENT 'Total maximum number of persons permitted inside the venue at any one time as determined by fire code, structural engineering assessments, and local authority licensing. This is the hard ceiling for ticket sales and access control enforcement.',
    `medical_staff_count` STRING COMMENT 'Number of on-site medical personnel (paramedics, EMTs, first-aiders) deployed under this plan. Determined by expected attendance, event risk classification, and local authority licensing requirements.',
    `peak_ingress_end_time` TIMESTAMP COMMENT 'Expected timestamp at which the peak ingress volume subsides to normal flow levels. Defines the window during which maximum gate staffing and crowd control resources must be deployed.',
    `peak_ingress_start_time` TIMESTAMP COMMENT 'Expected timestamp at which the highest volume of attendee arrivals begins, based on historical gate scan data and event start time. Used to schedule peak staffing deployment and activate maximum gate capacity.',
    `plan_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the crowd management plan, used in operational communications, regulatory submissions, and cross-system references. Format: CMP- followed by 4-12 alphanumeric characters.. Valid values are `^CMP-[A-Z0-9]{4,12}$`',
    `plan_name` STRING COMMENT 'Human-readable descriptive name for the crowd management plan, typically referencing the event name, venue, and season or date for easy identification by operations staff.',
    `plan_notes` STRING COMMENT 'Free-text field for operational notes, special instructions, or event-specific considerations not captured in structured fields. May include weather contingency notes, VIP movement protocols, or coordination notes with law enforcement.',
    `plan_status` STRING COMMENT 'Current lifecycle state of the crowd management plan. Draft indicates initial authoring; under_review indicates pending security director sign-off; approved indicates authorized for use; active indicates currently in force on event day; superseded indicates replaced by a newer version; archived indicates retired.. Valid values are `draft|under_review|approved|active|superseded|archived`',
    `plan_type` STRING COMMENT 'Classification of the crowd management plan by event category, determining the baseline protocol template and regulatory scrutiny level applied. [ENUM-REF-CANDIDATE: standard|high_risk|vip_event|concert|sporting_event|multi_day — promote to reference product]. Valid values are `standard|high_risk|vip_event|concert|sporting_event|multi_day`',
    `plan_version` STRING COMMENT 'Version number of the crowd management plan in major.minor format, tracking iterative revisions as event details, venue configurations, or regulatory requirements change prior to event day.. Valid values are `^[0-9]+.[0-9]+$`',
    `prohibited_items_list` STRING COMMENT 'Comma-separated list of items prohibited from entry under this crowd management plan (e.g., large bags, glass containers, laser pointers, professional cameras). Drives security screening protocols and public-facing communications.',
    `security_staffing_count` STRING COMMENT 'Total number of security personnel (including contracted and in-house staff) scheduled to be deployed for this event under this crowd management plan. Used for workforce planning and compliance with venue licensing conditions.',
    `submitted_to_authority_date` DATE COMMENT 'Date on which this crowd management plan was formally submitted to the relevant local authority, fire marshal, or governing body for review and licensing approval. Required for regulatory compliance tracking.',
    `surveillance_camera_count` STRING COMMENT 'Total number of CCTV and surveillance cameras active and covering the venue under this crowd management plan. Used to verify adequate coverage density per zone and compliance with venue licensing conditions.',
    `surveillance_system_active` BOOLEAN COMMENT 'Indicates whether the venue CCTV and surveillance system is confirmed active and operational for this event under this plan. A value of True confirms surveillance coverage is in place as required by the plan.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp at which this crowd management plan record was most recently modified. Tracks plan revisions and supports version control audit trails for regulatory compliance.',
    `venue_configuration_code` STRING COMMENT 'Code identifying the specific seating and floor layout configuration of the venue for this event, as defined in the Archtics venue seating and inventory management system. Different configurations (e.g., end-stage, center-stage, full-capacity, reduced-capacity) drive different crowd flow strategies.',
    `zone_occupancy_thresholds` STRING COMMENT 'Structured description of maximum safe occupancy thresholds by venue zone (e.g., lower bowl, upper deck, floor/GA, concourse, VIP areas). Stored as a delimited key-value string (zone_code:max_persons) since complex types are not permitted. Drives real-time crowd density monitoring and gate hold decisions.',
    CONSTRAINT pk_crowd_management_plan PRIMARY KEY(`crowd_management_plan_id`)
) COMMENT 'Master record for crowd management and ingress/egress operational plans developed for each event or venue configuration. Captures plan version, event reference, venue configuration, crowd flow strategy, entry gate activation schedule, expected peak ingress time, maximum safe occupancy thresholds by zone, emergency evacuation routes, and approval sign-off by venue security director. Serves as the operational blueprint for event-day crowd control.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`occupancy_snapshot` (
    `occupancy_snapshot_id` BIGINT COMMENT 'Unique surrogate identifier for each periodic occupancy snapshot record captured during a live event. Primary key for the occupancy_snapshot data product in the security domain.',
    `access_zone_id` BIGINT COMMENT 'Reference to the specific access control zone within the venue (e.g., GA floor, VIP suite level, concourse section) for which this snapshot records occupancy. Sourced from Archtics venue seating and inventory management.',
    `emergency_response_plan_id` BIGINT COMMENT 'Reference to the active emergency response plan governing this zone during the event. Links to the pre-approved evacuation and incident response procedures applicable to the current security level and event type.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the live event (game, concert, match) for which this occupancy snapshot was captured. Links the snapshot to the event scheduling and planning context.',
    `fixture_id` BIGINT COMMENT 'Reference to the live event (game, concert, match) for which this occupancy snapshot was captured. Links the snapshot to the event scheduling and planning context.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Occupancy snapshots at franchise home games feed franchise-level capacity compliance reporting, league safety audits, and insurance risk assessments. League operations benchmarks franchise capacity ma',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped occupancy data supports league annual capacity compliance reporting, franchise safety benchmarking, and regulatory submissions covering fan safety across the full season lifecycle.',
    `previous_snapshot_occupancy_snapshot_id` BIGINT COMMENT 'Reference to the immediately preceding occupancy snapshot record for the same event and zone. Enables delta calculation of occupancy changes between intervals without requiring a self-join on sequence number.',
    `venue_id` BIGINT COMMENT 'Reference to the venue where the event is being held. Enables venue-level occupancy aggregation and capacity benchmarking across facilities.',
    `previous_occupancy_snapshot_id` BIGINT COMMENT 'Self-referencing FK on occupancy_snapshot (previous_occupancy_snapshot_id)',
    `ada_accessible_zone` BOOLEAN COMMENT 'Indicates whether this zone is designated as ADA (Americans with Disabilities Act) accessible, with compliant pathways, seating, and egress routes. Relevant for emergency evacuation planning and accessibility compliance reporting.',
    `alert_severity` STRING COMMENT 'Categorical severity classification of the capacity alert for this snapshot. none = below threshold; advisory = approaching threshold; warning = at threshold; critical = at or exceeding maximum capacity. Informs escalation protocols for security and emergency response teams.. Valid values are `none|advisory|warning|critical`',
    `alert_threshold_pct` DECIMAL(18,2) COMMENT 'The occupancy percentage at which the capacity_alert_flag is set to True for this zone. Configurable per zone and event type to reflect different risk tolerances (e.g., 85% for GA floor, 95% for seated sections).',
    `available_capacity` STRING COMMENT 'The remaining number of persons that can be admitted to the zone before reaching maximum capacity (max_capacity minus current_occupancy_count). Used by gate staff and security supervisors for real-time admission control decisions.',
    `capacity_alert_flag` BOOLEAN COMMENT 'Indicates whether this snapshot has triggered a capacity threshold alert (True) because occupancy is approaching or exceeding the defined alert threshold percentage. Drives real-time notifications to security operations and venue management.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this occupancy snapshot record was first written to the Silver Layer data product. Serves as the audit creation timestamp for data lineage and pipeline monitoring purposes.',
    `credentialed_staff_count` STRING COMMENT 'The number of credentialed staff (security personnel, event staff, medical, law enforcement) present within the zone at the time of the snapshot. Used to calculate staff-to-patron ratios for crowd management compliance and post-event safety reporting.',
    `crowd_density_category` STRING COMMENT 'Qualitative classification of crowd density in the zone based on occupancy percentage thresholds. low (<50%), moderate (50–74%), high (75–84%), very_high (85–94%), critical (95%+). Used by security operations for rapid situational awareness without requiring numeric interpretation.. Valid values are `low|moderate|high|very_high|critical`',
    `current_occupancy_count` STRING COMMENT 'The number of persons physically present within the access zone at the time of the snapshot. Derived from gate scan aggregation, manual count, or sensor feed as indicated by the data_source field.',
    `data_quality_flag` STRING COMMENT 'Indicates the reliability status of the occupancy count in this snapshot. valid = confirmed accurate reading; estimated = interpolated due to sensor gap; suspect = anomalous reading under review; missing = no data received; corrected = manually adjusted post-capture. Critical for emergency response decision-making confidence.. Valid values are `valid|estimated|suspect|missing|corrected`',
    `data_source` STRING COMMENT 'The method or system used to collect the occupancy count for this snapshot. Values include gate_scan (Ticketmaster/AXS barcode scan aggregation), manual_count (security staff tally), sensor_feed (IoT crowd density sensor), ticketing_system (Archtics scan data), or hybrid (combination of sources).. Valid values are `gate_scan|manual_count|sensor_feed|ticketing_system|hybrid`',
    `egress_count` STRING COMMENT 'The number of persons who exited the access zone since the previous snapshot interval. Sourced from gate scan aggregation or sensor directional flow data. Critical for monitoring evacuation progress during emergency response scenarios.',
    `event_phase` STRING COMMENT 'The operational phase of the event at the time of the snapshot. Enables phase-specific crowd density analysis and comparison of occupancy patterns across pre_event, ingress, in_progress, halftime, egress, and post_event periods.. Valid values are `pre_event|ingress|in_progress|halftime|egress|post_event`',
    `gate_scan_count` STRING COMMENT 'The number of valid ticket scans recorded at access gates for this zone since the previous snapshot interval. Sourced directly from Ticketmaster/AXS access control systems. Used to cross-validate sensor-based occupancy readings.',
    `incident_flag` BOOLEAN COMMENT 'Indicates whether a security or safety incident is actively in progress within or adjacent to this zone at the time of the snapshot. When True, the snapshot is tagged for priority review by the security operations center and incident management teams.',
    `incident_type` STRING COMMENT 'Classification of the active incident type when incident_flag is True. Drives specific emergency response protocol activation: medical, crowd_crush, fire, evacuation, disturbance, suspicious_item, or none. [ENUM-REF-CANDIDATE: medical|crowd_crush|fire|evacuation|disturbance|suspicious_item|none — promote to reference product]',
    `ingress_count` STRING COMMENT 'The number of persons who entered the access zone since the previous snapshot interval. Sourced from gate scan aggregation (Ticketmaster/AXS) or sensor directional flow data. Supports ingress rate monitoring during peak entry periods.',
    `law_enforcement_present` BOOLEAN COMMENT 'Indicates whether sworn law enforcement officers (police, sheriff, federal agents) are physically deployed in or immediately adjacent to this zone at the time of the snapshot. Relevant for incident response coordination and post-event security reporting.',
    `manual_override` BOOLEAN COMMENT 'Indicates whether the occupancy count in this snapshot was manually entered or adjusted by a security supervisor, overriding the automated system reading. When True, manual_override_reason should be populated.',
    `manual_override_reason` STRING COMMENT 'Free-text explanation provided by the security supervisor when manual_override is True. Documents the justification for overriding automated occupancy data (e.g., sensor malfunction in north corridor, gate scanner offline). Required for audit trail compliance.',
    `max_capacity` STRING COMMENT 'The licensed or operationally approved maximum number of persons permitted in the access zone simultaneously. Established by venue fire code, local authority, and ADA compliance requirements. Sourced from Archtics venue inventory.',
    `occupancy_pct` DECIMAL(18,2) COMMENT 'The ratio of current occupancy count to maximum zone capacity expressed as a percentage (0.00–100.00+). Used to trigger crowd density alerts and inform real-time security deployment decisions.',
    `occupancy_trend` STRING COMMENT 'Directional trend of occupancy compared to the previous snapshot for this zone: increasing (net ingress), stable (minimal change within ±2%), or decreasing (net egress). Provides rapid situational awareness for security supervisors without requiring numeric comparison.. Valid values are `increasing|stable|decreasing`',
    `security_level` STRING COMMENT 'The operational security posture in effect for the zone at the time of the snapshot. Reflects threat assessment and law enforcement coordination status: standard, elevated, high, or critical. Aligned with DHS National Terrorism Advisory System levels adapted for venue operations.. Valid values are `standard|elevated|high|critical`',
    `sensor_device_code` STRING COMMENT 'The unique identifier of the IoT sensor, gate scanner, or counting device that provided the primary occupancy reading for this snapshot. Enables device-level data quality auditing and fault isolation when readings are anomalous.',
    `snapshot_interval_seconds` STRING COMMENT 'The configured polling interval in seconds between successive occupancy snapshots for this zone during the event. Typical values: 30, 60, 120, 300. Shorter intervals are used during high-risk periods such as event ingress and egress.',
    `snapshot_sequence_number` STRING COMMENT 'Sequential ordinal number of this snapshot within the event and zone combination, starting at 1. Enables ordered time-series reconstruction of occupancy trends for a specific zone throughout the event lifecycle.',
    `snapshot_timestamp` TIMESTAMP COMMENT 'The precise date and time (yyyy-MM-ddTHH:mm:ss.SSSXXX) at which this occupancy count was recorded. Serves as the principal business event timestamp for time-series crowd density analysis and emergency response timelines.',
    `source_system` STRING COMMENT 'The operational system of record from which this occupancy snapshot was originated. Enables data lineage tracing and source-specific data quality assessment across Ticketmaster/AXS, Archtics, IoT sensor platforms, manual entry, or Adobe Experience Platform integrations.. Valid values are `ticketmaster_axs|archtics|iot_sensor_platform|manual_entry|adobe_experience_platform`',
    `surveillance_active` BOOLEAN COMMENT 'Indicates whether CCTV or other surveillance systems are actively monitoring this zone at the time of the snapshot. A False value may indicate a system outage requiring manual security coverage escalation.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this occupancy snapshot record was last modified in the Silver Layer, for example following a manual override correction or data quality reclassification. Supports audit trail and data lineage requirements.',
    `weather_condition` STRING COMMENT 'Prevailing weather condition at the venue at the time of the snapshot, applicable for outdoor or partially outdoor venues. Influences crowd behavior, ingress/egress rates, and emergency response planning. [ENUM-REF-CANDIDATE: clear|cloudy|rain|storm|extreme_heat|extreme_cold|fog — promote to reference product]',
    `zone_name` STRING COMMENT 'Human-readable name of the access control zone at the time of the snapshot (e.g., GA Floor North, VIP Club Level, Section 101-110). Denormalized from Archtics for operational reporting without requiring a join.',
    `zone_type` STRING COMMENT 'Classification of the access zone by operational category. GA (General Admission), VIP (Very Important Person), seated, standing (SRO - Standing Room Only), concourse, restricted (staff/credential-only), or emergency_exit. Drives zone-specific crowd management protocols. [ENUM-REF-CANDIDATE: ga|vip|seated|standing|concourse|restricted|emergency_exit — promote to reference product]',
    CONSTRAINT pk_occupancy_snapshot PRIMARY KEY(`occupancy_snapshot_id`)
) COMMENT 'Periodic transactional record capturing real-time venue occupancy counts by access zone during an event. Captures event reference, zone ID, snapshot timestamp, current occupancy count, maximum capacity, occupancy percentage, data source (gate scan aggregation, manual count, sensor feed), and alert flag when approaching capacity thresholds. Enables live crowd density monitoring and supports emergency response decision-making.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`surveillance_camera` (
    `surveillance_camera_id` BIGINT COMMENT 'Unique system-generated identifier for each surveillance camera asset in the Sports Entertainment venue infrastructure inventory. Primary key for the surveillance_camera master resource.',
    `data_processing_record_id` BIGINT COMMENT 'Foreign key linking to compliance.data_processing_record. Business justification: GDPR Article 30 requires a Record of Processing Activities for every surveillance system. Each camera must be linked to its data_processing_record to document retention periods, legal basis, and cross',
    `pia_assessment_id` BIGINT COMMENT 'Foreign key linking to compliance.pia_assessment. Business justification: GDPR and CCPA require Privacy Impact Assessments for surveillance camera systems before deployment. The surveillance_camera already tracks gdpr_privacy_notice_posted and data_controller_entity as plai',
    `venue_id` BIGINT COMMENT 'Reference to the venue where this surveillance camera is physically installed. Links to the venue master product.',
    `replaced_surveillance_camera_id` BIGINT COMMENT 'Self-referencing FK on surveillance_camera (replaced_surveillance_camera_id)',
    `analytics_integration_enabled` BOOLEAN COMMENT 'Indicates whether this cameras feed is integrated with the video analytics platform for AI-powered capabilities such as crowd density monitoring, object detection, perimeter breach detection, or facial recognition. Distinct from basic recording.',
    `analytics_platform_code` BIGINT COMMENT 'Reference to the specific video analytics platform instance processing this cameras feed (e.g., crowd analytics engine, facial recognition system). Populated only when analytics_integration_enabled is True.',
    `asset_tag` STRING COMMENT 'Externally-known unique asset tag or barcode label physically affixed to the camera unit, used for physical inventory audits and field identification. Serves as the BUSINESS_IDENTIFIER for this master resource. Sourced from SAP S/4HANA Fixed Asset module.. Valid values are `^SE-CAM-[A-Z0-9]{6,12}$`',
    `audio_recording_enabled` BOOLEAN COMMENT 'Indicates whether the camera captures audio in addition to video. Audio recording has specific legal and regulatory implications under wiretapping laws and GDPR, requiring explicit signage and consent notices at the venue.',
    `camera_name` STRING COMMENT 'Human-readable descriptive name or label assigned to the camera for operational identification (e.g., North Concourse Gate 4 PTZ, Field Level South Fixed). Serves as the IDENTITY_LABEL for this master resource.',
    `camera_type` STRING COMMENT 'Classification of the camera by its physical form factor and operational capability. Fixed cameras are stationary; PTZ (Pan-Tilt-Zoom) cameras are remotely controllable; body-worn cameras are carried by security personnel; drone cameras are aerial; thermal cameras detect heat signatures; 360-degree cameras provide panoramic coverage. Serves as the CLASSIFICATION_OR_TYPE for this master resource. [ENUM-REF-CANDIDATE: fixed|ptz|body_worn|drone|thermal|360_degree|fisheye|covert — promote to reference product]. Valid values are `fixed|ptz|body_worn|drone|thermal|360_degree`',
    `coverage_area_sqm` DECIMAL(18,2) COMMENT 'Approximate physical area in square metres that the cameras field of view covers under normal operating conditions. Used for security coverage gap analysis and venue safety compliance reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this surveillance camera asset record was first created in the system. Serves as the RECORD_AUDIT_CREATED field for this master resource. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `crowd_management_flag` BOOLEAN COMMENT 'Indicates whether this camera is designated as a primary asset for crowd management and density monitoring operations during events. Cameras flagged for crowd management are prioritised in the security operations centre (SOC) dashboard and integrated with emergency response plans.',
    `decommission_date` DATE COMMENT 'Date on which the camera was formally decommissioned and removed from active service. Null for cameras still in service. Used for asset lifecycle reporting and GDPR data deletion compliance.',
    `emergency_response_flag` BOOLEAN COMMENT 'Indicates whether this camera is designated as a critical asset in the venues emergency response plan (e.g., covering evacuation routes, emergency exits, first aid stations). These cameras receive priority maintenance and are monitored continuously during events.',
    `field_of_view_degrees` DECIMAL(18,2) COMMENT 'Horizontal field of view angle of the camera lens expressed in degrees. Used for coverage gap analysis, camera placement optimisation, and security zone mapping.',
    `firmware_version` STRING COMMENT 'Current firmware version installed on the camera unit. Critical for cybersecurity vulnerability management, patch compliance tracking, and ensuring compatibility with the video analytics platform.. Valid values are `^[0-9]+.[0-9]+.[0-9]+(.[0-9]+)?$`',
    `floor_level` STRING COMMENT 'Floor or level designation within the venue where the camera is installed (e.g., L1, L2, Concourse, Field Level, Roof). Used for spatial mapping and incident location triangulation.',
    `frame_rate_fps` STRING COMMENT 'Recording frame rate of the camera expressed in frames per second (FPS). Standard values: 15 FPS (general surveillance), 25/30 FPS (standard motion), 60 FPS (high-speed event capture). Affects storage consumption and suitability for video analytics such as crowd counting and facial recognition.',
    `gdpr_privacy_notice_posted` BOOLEAN COMMENT 'Indicates whether a GDPR-compliant privacy notice (informing individuals of video surveillance) is posted in the area covered by this camera. Mandatory for venues operating in EU jurisdictions under GDPR Article 13. Supports regulatory compliance audit evidence.',
    `gps_latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate of the camera installation point in decimal degrees (WGS84). Enables precise geospatial mapping of surveillance coverage and integration with venue GIS systems.',
    `gps_longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate of the camera installation point in decimal degrees (WGS84). Enables precise geospatial mapping of surveillance coverage and integration with venue GIS systems.',
    `installation_date` DATE COMMENT 'Date on which the camera was physically installed and commissioned at the venue. Used for asset age tracking, warranty period calculation, and planned replacement scheduling.',
    `ip_address` STRING COMMENT 'Network IP address assigned to the camera on the venues security network. Used for network management, remote access, and integration with the video management system (VMS). Classified confidential as a network identifier.',
    `last_maintenance_date` DATE COMMENT 'Date of the most recent preventive or corrective maintenance performed on the camera. Used to track maintenance compliance, schedule next service, and assess operational reliability.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this surveillance camera asset record. Used for data lineage tracking, change management auditing, and Silver layer incremental processing in the Databricks Lakehouse.',
    `law_enforcement_accessible` BOOLEAN COMMENT 'Indicates whether footage from this camera is accessible to law enforcement agencies under a pre-agreed data sharing agreement or upon lawful request. Governs data governance workflows for footage disclosure and chain-of-custody documentation.',
    `mac_address` STRING COMMENT 'Hardware MAC (Media Access Control) address of the cameras network interface. Used for network access control (NAC) policy enforcement and device authentication on the venue security network.. Valid values are `^([0-9A-Fa-f]{2}:){5}[0-9A-Fa-f]{2}$`',
    `manufacturer` STRING COMMENT 'Name of the original equipment manufacturer (OEM) of the camera hardware (e.g., Axis Communications, Bosch, Hanwha, Hikvision, Pelco). Used for warranty management, vendor SLA tracking, and procurement decisions.',
    `model_number` STRING COMMENT 'Manufacturers model number or product SKU for the camera hardware. Used for spare parts procurement, firmware compatibility tracking, and technical support escalation.',
    `mounting_location` STRING COMMENT 'Physical mounting configuration of the camera unit indicating how and where it is installed. Informs maintenance access procedures and field-of-view calculations. [ENUM-REF-CANDIDATE: ceiling|wall|pole|mast|mobile|body|aerial — 7 candidates stripped; promote to reference product]',
    `next_maintenance_date` DATE COMMENT 'Date on which the next scheduled preventive maintenance for this camera is due. Drives maintenance work order generation and ensures continuous operational coverage during events.',
    `night_vision_enabled` BOOLEAN COMMENT 'Indicates whether the camera is equipped with infrared (IR) or low-light night vision capability. Critical for 24/7 venue security coverage during evening events and overnight facility monitoring.',
    `operational_status` STRING COMMENT 'Current lifecycle state of the surveillance camera asset indicating whether it is actively recording, offline, undergoing maintenance, in fault condition, decommissioned, or awaiting installation. Serves as the LIFECYCLE_STATUS for this master resource.. Valid values are `active|inactive|maintenance|fault|decommissioned|pending_install`',
    `power_source` STRING COMMENT 'Method by which the camera receives electrical power. PoE (Power over Ethernet) and PoE+ are common for networked cameras; AC mains for high-power units; battery for temporary/mobile deployments; solar for outdoor remote locations. Affects maintenance scheduling and resilience planning.. Valid values are `poe|ac_mains|battery|solar|poe_plus`',
    `ptz_controllable` BOOLEAN COMMENT 'Indicates whether the camera supports remote Pan-Tilt-Zoom (PTZ) control by security operators. PTZ cameras can be directed to track incidents in real time, providing dynamic coverage beyond fixed camera limitations.',
    `recording_system_code` BIGINT COMMENT 'Reference to the video management system (VMS) or network video recorder (NVR) that this camera streams to and stores footage on. Links to the recording system master product.',
    `resolution_pixels` STRING COMMENT 'Numeric resolution of the camera sensor expressed in megapixels (e.g., 2 for 1080p, 8 for 4K). Used for precise technical specification, storage capacity planning, and video analytics platform configuration.',
    `resolution_tier` STRING COMMENT 'Standardized resolution classification of the cameras video output. SD = Standard Definition (480p or below), HD = High Definition (720p), FHD = Full High Definition (1080p), 4K = Ultra High Definition (2160p), 8K = Super Ultra High Definition (4320p). Drives storage capacity planning and video analytics platform compatibility. Serves as the principal MEASUREMENT_OR_VALUE classification for this resource.. Valid values are `SD|HD|FHD|4K|8K`',
    `retention_period_days` STRING COMMENT 'Number of days that recorded footage from this camera is retained before automatic deletion or overwrite. Driven by regulatory requirements, venue policy, and storage capacity. Typical ranges: 30 days (general areas), 90 days (entry/exit points), 365 days (high-security zones). Compliance with GDPR Article 5 data minimisation principle.',
    `security_zone_classification` STRING COMMENT 'Security access classification of the venue zone monitored by this camera. Drives access control policies, footage access permissions, and law enforcement data sharing protocols. VIP zones have enhanced privacy considerations; high-security zones may have extended retention periods.. Valid values are `public|restricted|high_security|vip|back_of_house|perimeter`',
    `serial_number` STRING COMMENT 'Manufacturer-assigned unique serial number for the physical camera unit. Used for warranty claims, insurance documentation, and theft/loss reporting. Classified confidential as a device identifier.',
    `storage_bandwidth_mbps` DECIMAL(18,2) COMMENT 'Network bandwidth consumed by this cameras video stream in megabits per second (Mbps) under normal recording conditions. Used for network capacity planning and recording system infrastructure sizing.',
    `venue_zone` STRING COMMENT 'Descriptive label of the specific venue zone or area covered by this camera (e.g., Main Entrance, North Concourse Level 2, Field of Play, VIP Suite Corridor, Parking Lot C). Used for crowd management, incident response, and zone-based security reporting.',
    `warranty_expiry_date` DATE COMMENT 'Date on which the manufacturers hardware warranty for this camera expires. Used to trigger procurement decisions for extended warranty or replacement, and to determine whether repair costs are covered.',
    CONSTRAINT pk_surveillance_camera PRIMARY KEY(`surveillance_camera_id`)
) COMMENT 'Master catalog of all CCTV and surveillance camera assets deployed across Sports Entertainment venues. Captures camera ID, venue zone coverage, camera type (fixed, PTZ, body-worn, drone), resolution tier, recording system reference, retention period (days), operational status, last maintenance date, and integration with video analytics platform. SSOT for surveillance infrastructure inventory distinct from venue.bms_system which covers broader building systems.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`surveillance_footage_request` (
    `surveillance_footage_request_id` BIGINT COMMENT 'Unique system-generated identifier for each surveillance footage request record. Primary key for this transactional entity.',
    `breach_notification_id` BIGINT COMMENT 'Foreign key linking to compliance.breach_notification. Business justification: When a data breach is notified to regulators, compliance teams request surveillance footage as evidence for the breach investigation and to satisfy GDPR Article 33 documentation requirements. This lin',
    `employee_id` BIGINT COMMENT 'Identifier of the internal security officer or staff member who initiated the footage request. Represents the PARTY_REFERENCE for internal requestors.',
    `event_fixture_id` BIGINT COMMENT 'Identifier of the specific sports or entertainment event associated with the footage request, if applicable. Nullable for non-event-specific requests.',
    `fixture_id` BIGINT COMMENT 'Identifier of the specific sports or entertainment event associated with the footage request, if applicable. Nullable for non-event-specific requests.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Footage requests related to franchise home game incidents require franchise attribution for league compliance tracking, legal hold management, and franchise-level chain-of-custody reporting required b',
    `asset_id` BIGINT COMMENT 'Foreign key linking to content.asset. Business justification: When a surveillance footage request is fulfilled, the footage is ingested into the DAM as a content asset. Chain-of-custody tracking, legal hold compliance, and law enforcement disclosure processes re',
    `hold_id` BIGINT COMMENT 'Foreign key linking to legal.legal_hold. Business justification: Legal holds on surveillance footage are a direct operational requirement when litigation is anticipated or active. Linking the footage request to the triggering legal hold ensures chain-of-custody int',
    `ingest_job_id` BIGINT COMMENT 'Foreign key linking to content.ingest_job. Business justification: Fulfilling a surveillance footage request triggers a content ingest job to bring footage into the DAM. Legal hold and chain-of-custody audit trails require tracing which ingest job processed the foota',
    `integrity_alert_id` BIGINT COMMENT 'Foreign key linking to gaming.integrity_alert. Business justification: Sports integrity investigations: when a gaming integrity alert flags suspicious activity at a fixture, security teams submit surveillance footage requests to confirm presence of known fixers or correl',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped footage request records support league annual legal compliance reporting and franchise-level footage retention policy management aligned to season lifecycle and data retention regulation',
    `litigation_case_id` BIGINT COMMENT 'Foreign key linking to legal.litigation_case. Business justification: Surveillance footage requests are frequently issued under court order or subpoena in active litigation. Legal teams managing discovery obligations must link footage requests to the litigation case dri',
    `privacy_request_id` BIGINT COMMENT 'Foreign key linking to compliance.privacy_request. Business justification: Fan GDPR/CCPA data subject access requests (DSARs) or erasure requests frequently require reviewing and potentially providing or deleting surveillance footage. The compliance privacy_request triggers ',
    `requesting_officer_employee_id` BIGINT COMMENT 'Identifier of the internal security officer or staff member who initiated the footage request. Represents the PARTY_REFERENCE for internal requestors.',
    `security_incident_id` BIGINT COMMENT 'Foreign key linking to security.security_incident. Business justification: Surveillance footage requests are most commonly triggered by security incidents — law enforcement, legal teams, or security management request footage to investigate or document an incident. The exist',
    `venue_id` BIGINT COMMENT 'Identifier of the venue where the requested surveillance footage was captured. Links to the venue master record.',
    `follow_up_surveillance_footage_request_id` BIGINT COMMENT 'Self-referencing FK on surveillance_footage_request (follow_up_surveillance_footage_request_id)',
    `access_zone` STRING COMMENT 'Venue access control zone or area designation (e.g., GA concourse, VIP suite level, player tunnel, backstage) where the requested cameras are located.',
    `chain_of_custody_log` STRING COMMENT 'Sequential narrative log documenting every individual who accessed, transferred, or handled the footage from extraction through delivery, maintaining evidentiary integrity.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this record was first created in the system. Used for audit trail and data lineage purposes.',
    `delivery_method` STRING COMMENT 'Method used to deliver the extracted footage to the requesting party, ensuring appropriate security controls are applied based on the sensitivity of the content.. Valid values are `secure_portal|encrypted_usb|email|physical_handoff|sftp`',
    `delivery_receipt_reference` STRING COMMENT 'Reference number or acknowledgment identifier confirming receipt of the footage by the requesting party.',
    `delivery_recipient_name` STRING COMMENT 'Full name of the individual who received the delivered footage package, used for chain-of-custody confirmation.',
    `denial_reason` STRING COMMENT 'Explanation of why the footage request was denied, including legal, operational, or policy grounds. Populated only when request_status is denied.',
    `disclosure_authorized` BOOLEAN COMMENT 'Indicates whether formal authorization has been granted to disclose the requested footage to the requesting party, particularly for external law enforcement or legal proceedings.',
    `disclosure_authorized_by` STRING COMMENT 'Name or identifier of the internal authority (e.g., Chief Security Officer, Legal Counsel, VP of Operations) who granted authorization for footage disclosure.',
    `disclosure_authorized_timestamp` TIMESTAMP COMMENT 'Date and time when disclosure authorization was formally granted for this footage request.',
    `footage_end_timestamp` TIMESTAMP COMMENT 'End date and time of the surveillance footage window being requested. Defines the conclusion of the temporal range for footage retrieval.',
    `footage_file_size_gb` DECIMAL(18,2) COMMENT 'Total size in gigabytes of the extracted surveillance footage package delivered to the requesting party.',
    `footage_format` STRING COMMENT 'Digital file format of the extracted surveillance footage provided to the requesting party.. Valid values are `MP4|AVI|MKV|H264|H265|RAW`',
    `footage_hash` STRING COMMENT 'SHA-256 cryptographic hash of the extracted footage file used to verify integrity and detect tampering throughout the chain of custody.. Valid values are `^[a-fA-F0-9]{64}$`',
    `footage_purpose` STRING COMMENT 'Detailed narrative description of the business or legal purpose for which the surveillance footage is being requested, including incident description or investigation context.',
    `footage_retention_expiry_date` DATE COMMENT 'Date on which the extracted footage copy associated with this request is scheduled for deletion per data retention policy, unless a legal hold is active.',
    `footage_start_timestamp` TIMESTAMP COMMENT 'Start date and time of the surveillance footage window being requested. Defines the beginning of the temporal range for footage retrieval.',
    `fulfilled_timestamp` TIMESTAMP COMMENT 'Date and time when the footage was successfully extracted, packaged, and delivered to the requesting party.',
    `fulfillment_status` STRING COMMENT 'Operational status of the physical footage retrieval and delivery process, distinct from the overall request approval status.. Valid values are `not_started|in_progress|footage_extracted|delivered|failed`',
    `incident_date` DATE COMMENT 'Calendar date on which the underlying incident, event, or occurrence that prompted the footage request took place.',
    `legal_hold_flag` BOOLEAN COMMENT 'Indicates whether the requested footage is subject to a legal hold order, preventing deletion or modification pending litigation or regulatory investigation.',
    `legal_hold_reference` STRING COMMENT 'Reference number or identifier of the legal hold order applied to this footage request, issued by legal counsel or court authority.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, special handling instructions, or supplementary context provided by the security team or legal counsel regarding this footage request.',
    `privacy_impact_assessed` BOOLEAN COMMENT 'Indicates whether a privacy impact assessment was conducted for this footage request to evaluate risks to individuals captured in the footage, as required under GDPR and CCPA.',
    `redaction_completed` BOOLEAN COMMENT 'Indicates whether required redaction of the footage has been completed prior to delivery.',
    `redaction_required` BOOLEAN COMMENT 'Indicates whether portions of the footage must be redacted (e.g., to protect uninvolved individuals privacy) before disclosure to the requesting party.',
    `request_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to this footage request, used for tracking and chain-of-custody documentation. Format: SFR-YYYY-NNNNNN.. Valid values are `^SFR-[0-9]{4}-[0-9]{6}$`',
    `request_status` STRING COMMENT 'Current lifecycle state of the surveillance footage request, tracking workflow progression from submission through fulfillment or denial.. Valid values are `pending|in_review|approved|fulfilled|denied|cancelled`',
    `request_type` STRING COMMENT 'Classification of the footage request by its business purpose: internal security investigation, law enforcement agency request, legal proceeding support, insurance claim evidence, or post-incident operational review.. Valid values are `internal_investigation|law_enforcement|legal_proceeding|insurance_claim|incident_review`',
    `requesting_agency_case_number` STRING COMMENT 'External case, docket, or reference number assigned by the requesting law enforcement agency or legal body to cross-reference with their own records.',
    `requesting_agency_name` STRING COMMENT 'Name of the external law enforcement agency, legal firm, or insurance company submitting the request. Populated when requesting_party_type is external.',
    `requesting_party_name` STRING COMMENT 'Full name of the individual or organization requesting the footage. May be an internal security officer, law enforcement officer, legal counsel, or insurance adjuster.',
    `requesting_party_type` STRING COMMENT 'Classification of the entity submitting the footage request, distinguishing between internal staff, external law enforcement agencies, legal representatives, and other authorized parties.. Valid values are `internal_security|law_enforcement|legal_counsel|insurance_adjuster|venue_management`',
    `sla_due_date` DATE COMMENT 'Target date by which the footage request must be fulfilled per internal SLA or law enforcement response time requirements.',
    `submitted_timestamp` TIMESTAMP COMMENT 'Date and time when the surveillance footage request was formally submitted into the evidence management system. Represents the principal business event timestamp.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this record was most recently modified. Supports audit trail and change tracking requirements.',
    CONSTRAINT pk_surveillance_footage_request PRIMARY KEY(`surveillance_footage_request_id`)
) COMMENT 'Transactional record of requests to retrieve, preserve, or share surveillance footage for security investigations, law enforcement requests, or legal proceedings. Captures requesting party (internal officer, law enforcement agency, legal counsel), event or date/time range, camera IDs requested, footage purpose, chain-of-custody log, legal hold flag, disclosure authorization, and fulfillment status. Supports evidence management and legal compliance.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`emergency_response_plan` (
    `emergency_response_plan_id` BIGINT COMMENT 'Unique surrogate identifier for each emergency response plan record in the Sports Entertainment security domain.',
    `event_fixture_id` BIGINT COMMENT 'Reference to a specific Sports Entertainment event for which this plan is activated or scoped. Null when the plan applies to the venue generally rather than a single event.',
    `fixture_id` BIGINT COMMENT 'Reference to a specific Sports Entertainment event for which this plan is activated or scoped. Null when the plan applies to the venue generally rather than a single event.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Emergency response plans are developed per franchise home venue context. Franchise linkage enables franchise-specific plan compliance tracking, league safety audits, and regulatory submissions tied to',
    `governing_body_id` BIGINT COMMENT 'Foreign key linking to compliance.governing_body. Business justification: Emergency response plans at sports venues require approval from governing bodies (DHS, league authorities, local fire marshal authorities tracked in compliance). The ERP already tracks dhs_approval_st',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped emergency plans are required for league annual safety compliance and DHS coordination. Season tagging enables plan version management aligned to league season lifecycle and CBA safety pr',
    `regulatory_license_id` BIGINT COMMENT 'Foreign key linking to legal.regulatory_license. Business justification: Emergency response plans are mandated by venue operating licenses (DHS, fire marshal, local authority). Legal teams must link approved ERPs to the regulatory license that requires them for compliance ',
    `superseded_by_plan_emergency_response_plan_id` BIGINT COMMENT 'Reference to the newer emergency response plan that has replaced this version. Null if this is the current active version. Enables version chain traceability for audit and regulatory review.',
    `venue_id` BIGINT COMMENT 'Reference to the Sports Entertainment venue to which this emergency response plan applies. A plan may be venue-specific or cover multiple venues (see multi_venue_flag).',
    `superseded_emergency_response_plan_id` BIGINT COMMENT 'Self-referencing FK on emergency_response_plan (superseded_emergency_response_plan_id)',
    `activation_trigger` STRING COMMENT 'Narrative description of the specific conditions or thresholds that trigger activation of this emergency response plan (e.g., Confirmed armed individual on premises, NWS Tornado Warning issued within 10-mile radius). Critical for incident command decision-making.',
    `ada_accommodation_provisions` STRING COMMENT 'Description of specific provisions within this plan for evacuating and sheltering guests and staff with disabilities, including wheelchair-accessible evacuation routes, Areas of Rescue Assistance (ARA), and mobility assistance protocols.',
    `communication_protocol` STRING COMMENT 'Description of the communication systems and protocols used during plan activation, including radio frequencies, PA system codes, mass notification system triggers, and social media blackout procedures.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this emergency response plan record was first created in the Sports Entertainment security data platform. Supports audit trail and regulatory document control requirements.',
    `crowd_capacity_threshold` STRING COMMENT 'Minimum crowd attendance count at which this plans enhanced protocols are activated (e.g., plans may have tiered activation based on event size). Supports DHS Special Event Assessment Rating (SEAR) classification.',
    `dhs_approval_date` DATE COMMENT 'Date on which DHS formally approved this emergency response plan. Null if approval is pending, not required, or rejected.',
    `dhs_approval_status` STRING COMMENT 'Regulatory approval status of this plan with the U.S. Department of Homeland Security. Required for events classified under DHS Special Event Assessment Rating (SEAR) Tier I-III.. Valid values are `pending|submitted|approved|rejected|not_required`',
    `effective_date` DATE COMMENT 'Calendar date on which this version of the emergency response plan becomes operationally binding. Used to determine which plan version is active for a given event date.',
    `evacuation_route_description` STRING COMMENT 'Narrative description of primary and secondary evacuation routes for this plan, including ADA-accessible routes, assembly points, and crowd flow management corridors. Aligned with venue floor plan and ADA compliance requirements.',
    `expiry_date` DATE COMMENT 'Calendar date on which this emergency response plan version expires and must be reviewed or renewed. Null for open-ended plans. Drives regulatory renewal workflows and compliance alerts.',
    `fire_marshal_approval_date` DATE COMMENT 'Date on which the local fire marshal formally approved this emergency response plan. Null if approval is pending, not required, or rejected.',
    `fire_marshal_approval_status` STRING COMMENT 'Regulatory approval status of this plan with the local fire marshal authority. Required for all venue events under NFPA 101 and local fire codes. Drives event permit issuance.. Valid values are `pending|submitted|approved|rejected|not_required`',
    `fire_marshal_contact` STRING COMMENT 'Primary contact phone number for the local fire marshal office responsible for approving and coordinating fire evacuation components of this plan. Required for regulatory compliance.',
    `incident_command_structure` STRING COMMENT 'Description of the Incident Command System (ICS) hierarchy governing this plan, including Incident Commander role, Operations Section Chief, Safety Officer, and Public Information Officer designations per NIMS ICS standards.',
    `incident_commander_name` STRING COMMENT 'Full name of the designated Incident Commander responsible for directing emergency response operations under this plan. Confidential operational security information.',
    `incident_commander_title` STRING COMMENT 'Official job title of the designated Incident Commander (e.g., Director of Event Security, VP Venue Operations). Used in regulatory filings and law enforcement coordination documents.',
    `last_drill_date` DATE COMMENT 'Date of the most recent tabletop exercise or full-scale drill conducted to validate this emergency response plan. Required for OSHA compliance and DHS preparedness certification.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this emergency response plan record. Used for change tracking, regulatory audit trails, and Silver Layer data lineage in the Databricks Lakehouse.',
    `law_enforcement_agency` STRING COMMENT 'Name of the primary law enforcement agency coordinating with Sports Entertainment under this plan (e.g., Las Vegas Metropolitan Police Department, NYPD Special Events Unit). Required for DHS Special Event Assessment Rating (SEAR) submissions.',
    `law_enforcement_contact` STRING COMMENT 'Primary contact phone number or radio channel for law enforcement coordination during activation of this plan. Confidential operational security data restricted to authorized security personnel.',
    `media_blackout_flag` BOOLEAN COMMENT 'Indicates whether this plan includes a media and social media blackout protocol during initial activation to prevent panic, protect operational security, and manage public communications through official channels only.',
    `medical_triage_zone_count` STRING COMMENT 'Number of designated medical triage zones established under this plan for mass casualty incident (MCI) response. Drives medical resource pre-positioning and EMS coordination planning.',
    `multi_venue_flag` BOOLEAN COMMENT 'Indicates whether this emergency response plan applies to multiple venues simultaneously (e.g., a league-wide severe weather protocol). When True, venue_id represents the primary venue and additional venues are linked in a separate association table.',
    `mutual_aid_agreement_ref` STRING COMMENT 'Reference number or name of the mutual aid agreement with external agencies (neighboring jurisdictions, hospitals, EMS providers) that supports this plan. Enables cross-agency resource sharing during large-scale incidents.',
    `next_review_date` DATE COMMENT 'Scheduled date for the next mandatory review and update of this emergency response plan. Drives compliance calendar alerts and ensures plans remain current with regulatory changes and venue modifications.',
    `plan_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this emergency response plan across venues and regulatory submissions (e.g., ERP-FIRE-2024-001). Used in DHS filings, local fire marshal submissions, and law enforcement coordination documents.. Valid values are `^ERP-[A-Z]{2,6}-[0-9]{4}-[0-9]{3}$`',
    `plan_document_url` STRING COMMENT 'Secure URL to the full emergency response plan document stored in the Sports Entertainment Digital Asset Management (DAM) system. Access restricted to authorized security and compliance personnel. Confidential operational security document.',
    `plan_name` STRING COMMENT 'Human-readable title of the emergency response plan (e.g., Active Shooter Response Plan – Allegiant Stadium 2024). Used in operational briefings, staff training materials, and regulatory filings.',
    `plan_owner_department` STRING COMMENT 'Organizational department responsible for this emergency response plan (e.g., Venue Security Operations, Event Safety and Compliance, Facilities Management).',
    `plan_owner_name` STRING COMMENT 'Full name of the Sports Entertainment staff member accountable for maintaining, updating, and submitting this emergency response plan. Confidential internal personnel data.',
    `plan_status` STRING COMMENT 'Current lifecycle state of the emergency response plan. Active indicates the plan is operationally deployed; superseded indicates a newer version has replaced it; retired indicates the plan is no longer applicable.. Valid values are `draft|under_review|approved|active|superseded|retired`',
    `plan_type` STRING COMMENT 'Classification of the emergency scenario this plan governs. Drives protocol selection, command structure, and law enforcement coordination requirements. [ENUM-REF-CANDIDATE: active_shooter|bomb_threat|mass_casualty|fire_evacuation|severe_weather|medical_emergency — promote to reference product if additional types are needed]. Valid values are `active_shooter|bomb_threat|mass_casualty|fire_evacuation|severe_weather|medical_emergency`',
    `primary_triage_zone_location` STRING COMMENT 'Physical location description of the primary medical triage zone within the venue (e.g., Gate A Concourse Level 1, Field Level South End Zone). Used by EMS and medical staff during MCI activation.',
    `public_address_code` STRING COMMENT 'Standardized code word or phrase used in venue public address announcements to signal activation of this plan without causing public panic (e.g., Code Alpha for medical emergency, Code Bravo for security threat).',
    `regulatory_jurisdiction` STRING COMMENT 'Geographic and regulatory jurisdiction governing this plan (e.g., Clark County, Nevada, City of New York, NY, Federal – DHS Tier 1). Determines which regulatory bodies must approve the plan.',
    `sear_tier` STRING COMMENT 'DHS Special Event Assessment Rating tier assigned to events covered by this plan. Tier 1 represents the highest national significance (e.g., Super Bowl, Olympics); Tier 3 represents significant regional events. Determines federal resource allocation and coordination requirements.. Valid values are `tier_1|tier_2|tier_3|not_classified`',
    `shelter_in_place_zone` STRING COMMENT 'Designated venue area(s) for shelter-in-place protocols, applicable for severe weather, active threat, or hazmat scenarios. Includes interior hardened areas, concourse corridors, and below-grade spaces.',
    `threat_level` STRING COMMENT 'Severity classification of the emergency scenario addressed by this plan, aligned with DHS threat level taxonomy. Drives resource pre-positioning, law enforcement notification thresholds, and public communication protocols.. Valid values are `low|moderate|high|critical`',
    `version_number` STRING COMMENT 'Semantic version identifier for this iteration of the emergency response plan (e.g., 2.1.0). Enables tracking of plan revisions, regulatory re-submissions, and audit trails across plan lifecycle.. Valid values are `^[0-9]+.[0-9]+(.[0-9]+)?$`',
    CONSTRAINT pk_emergency_response_plan PRIMARY KEY(`emergency_response_plan_id`)
) COMMENT 'Master record for all emergency response plans governing Sports Entertainment venues and events — active shooter protocols, bomb threat procedures, mass casualty incident (MCI) response, fire evacuation, severe weather shelter-in-place, and medical emergency escalation. Captures plan type, venue scope, version, activation triggers, command structure, law enforcement coordination contacts, medical triage zone assignments, and regulatory approval status (DHS, local fire marshal).';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`emergency_activation` (
    `emergency_activation_id` BIGINT COMMENT 'Unique surrogate identifier for each emergency response plan activation record. Primary key for the emergency_activation data product. Entity role: TRANSACTION_HEADER — discrete business event with a clear lifecycle.',
    `activating_authority_employee_id` BIGINT COMMENT 'Reference to the individual (security officer, venue director, incident commander) who formally authorized and triggered the emergency plan activation. Serves as the PARTY_REFERENCE category for TRANSACTION_HEADER role.',
    `production_id` BIGINT COMMENT 'Foreign key linking to broadcast.production. Business justification: Emergency activations that interrupt live broadcasts must reference the specific broadcast production for incident command coordination, insurance claims, and regulatory reporting. emergency_activatio',
    `incident_report_id` BIGINT COMMENT 'Foreign key linking to compliance.incident_report. Business justification: Emergency activations (bomb threats, mass casualty events, evacuations) at sports venues trigger mandatory OSHA recordable incident reports and league governing body notifications. Compliance teams mu',
    `emergency_response_plan_id` BIGINT COMMENT 'Reference to the specific emergency response plan document that was activated. Links to the plan registry for version control and compliance tracking.',
    `employee_id` BIGINT COMMENT 'Reference to the individual (security officer, venue director, incident commander) who formally authorized and triggered the emergency plan activation. Serves as the PARTY_REFERENCE category for TRANSACTION_HEADER role.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event (game, concert, match, etc.) during which this emergency activation occurred. Links activation to the event scheduling and ticketing context.',
    `fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event (game, concert, match, etc.) during which this emergency activation occurred. Links activation to the event scheduling and ticketing context.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Emergency activations at franchise home games must be franchise-attributed for league incident reporting, insurance claims, and CBA player safety compliance reviews. League tracks activations by franc',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-level emergency activation records are required for league annual safety reports, regulatory filings, and CBA compliance reviews covering player and fan safety provisions across the full season',
    `litigation_case_id` BIGINT COMMENT 'Foreign key linking to legal.litigation_case. Business justification: Emergency activations resulting in injuries, deaths, or mass evacuations generate negligence and wrongful death litigation. Legal teams need to link the activation record to the resulting case for dis',
    `live_feed_id` BIGINT COMMENT 'Foreign key linking to broadcast.live_feed. Business justification: When an emergency interrupts a live broadcast, the specific live feed that was suspended must be recorded for after-action reports, broadcaster notification obligations, and insurance claims. emergenc',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Emergency activations require direct regulatory filings to DHS, FEMA, and league authorities (separate from the incident report). The emergency_activation already tracks regulatory_report_filed and re',
    `security_incident_id` BIGINT COMMENT 'Foreign key linking to security.security_incident. Business justification: An emergency activation is often triggered by a specific security incident — a bomb threat, mass casualty event, or severe altercation that escalates to emergency response plan activation. The existin',
    `venue_id` BIGINT COMMENT 'Reference to the Sports Entertainment venue where the emergency activation was executed. Supports venue-level safety compliance reporting and ADA/OSHA audit trails.',
    `escalated_emergency_activation_id` BIGINT COMMENT 'Self-referencing FK on emergency_activation (escalated_emergency_activation_id)',
    `activation_number` STRING COMMENT 'Externally-known, human-readable business identifier for this emergency activation event (e.g., EMA-2024-000123). Used in after-action reports, law enforcement coordination, and regulatory filings. Serves as the BUSINESS_IDENTIFIER category for TRANSACTION_HEADER role.. Valid values are `^EMA-[0-9]{4}-[0-9]{6}$`',
    `activation_source` STRING COMMENT 'Identifies how the emergency activation was triggered: manually by an authorized officer, automatically by an alarm or surveillance system, or reported by law enforcement, staff, or fans. Supports root cause analysis and system effectiveness evaluation.. Valid values are `manual|automated_alarm|surveillance_system|law_enforcement|staff_report|fan_report`',
    `activation_status` STRING COMMENT 'Current lifecycle state of the emergency activation. Tracks progression from initial activation through resolution or transfer to external authority. Serves as the LIFECYCLE_STATUS category for TRANSACTION_HEADER role. [ENUM-REF-CANDIDATE: active|contained|resolved|cancelled|escalated|transferred — promote to reference product if additional states are required]. Valid values are `active|contained|resolved|cancelled|escalated|transferred`',
    `activation_timestamp` TIMESTAMP COMMENT 'The precise date and time when the emergency response plan was formally activated. This is the principal real-world business event timestamp (BUSINESS_EVENT_TIMESTAMP category). Recorded in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX).',
    `after_action_report_reference` STRING COMMENT 'Document reference number or URL linking to the formal After-Action Report (AAR) completed following this emergency activation. The AAR documents lessons learned, response effectiveness, and corrective actions. Required for OSHA, ISO 20121, and league governance compliance.',
    `after_action_report_status` STRING COMMENT 'Current completion status of the After-Action Report (AAR) for this emergency activation. Tracks compliance with mandatory post-incident review requirements.. Valid values are `pending|in_progress|completed|approved|waived`',
    `all_clear_timestamp` TIMESTAMP COMMENT 'The date and time when the all-clear signal was officially issued, indicating the emergency has been resolved and normal operations may resume. Null if the activation has not yet been resolved. Used to calculate response duration.',
    `broadcast_interrupted` BOOLEAN COMMENT 'Indicates whether live broadcast operations (TV, OTT, radio) were interrupted or suspended as a result of this emergency activation. Relevant for media rights compliance, FCC reporting, and broadcast partner SLA management.',
    `command_post_location` STRING COMMENT 'Physical location description of the Incident Command Post (ICP) established for this emergency activation (e.g., Gate C Security Office, Parking Lot B Mobile Command Unit). Critical for coordinating multi-agency response and documenting ICS compliance.',
    `confirmed_fatalities_count` STRING COMMENT 'Total number of confirmed fatalities recorded as a direct result of the emergency incident. Triggers mandatory OSHA fatality reporting within 8 hours, executive notification, and regulatory investigation protocols.',
    `confirmed_injuries_count` STRING COMMENT 'Total number of confirmed injuries (non-fatal) recorded as a direct result of the emergency incident. Used for OSHA 300 log reporting, insurance claims, and after-action analysis.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this emergency activation record was first created in the system. Serves as the RECORD_AUDIT_CREATED category for TRANSACTION_HEADER role. Supports data lineage and audit trail requirements.',
    `drill_exercise` BOOLEAN COMMENT 'Indicates whether this activation record represents a planned emergency drill or tabletop exercise rather than an actual emergency event. Allows filtering of drill records from operational incident analytics and regulatory reporting.',
    `ems_notified` BOOLEAN COMMENT 'Indicates whether Emergency Medical Services (EMS) was formally notified as part of this emergency activation. Mandatory documentation for mass casualty and medical emergency plan types.',
    `estimated_occupancy_at_activation` STRING COMMENT 'Estimated number of persons (fans, staff, athletes, media) present in the venue at the time of emergency activation. Critical for resource allocation, casualty ratio calculations, and post-event safety analysis. Serves as the QUANTITATIVE_RESULT category for this non-monetary TRANSACTION_HEADER.',
    `evacuation_initiated` BOOLEAN COMMENT 'Indicates whether a full or partial venue evacuation was initiated as part of this emergency activation. Drives crowd management protocol tracking and post-event safety audit requirements.',
    `evacuation_type` STRING COMMENT 'Specifies the scope of evacuation executed during this emergency activation: full venue, partial (specific sections), sector-specific (single zone), or none. Applicable only when evacuation_initiated is True.. Valid values are `full|partial|sector_specific|none`',
    `event_cancelled` BOOLEAN COMMENT 'Indicates whether the Sports Entertainment event was fully cancelled (not resumed) as a result of this emergency activation. Triggers ticketing refund workflows, force majeure clauses, and insurance claim processes.',
    `event_suspended` BOOLEAN COMMENT 'Indicates whether the Sports Entertainment event (game, concert, match) was formally suspended or halted as a result of this emergency activation. Impacts ticketing refund obligations, broadcast rights, and league governance reporting.',
    `false_alarm` BOOLEAN COMMENT 'Indicates whether this emergency activation was subsequently determined to be a false alarm (no actual emergency existed). Critical for tracking false alarm rates, system calibration, and regulatory reporting to fire/police authorities.',
    `fbi_notified` BOOLEAN COMMENT 'Indicates whether the Federal Bureau of Investigation (FBI) was formally notified as part of this emergency activation. Required for terrorism, active shooter, and bomb threat plan types per federal reporting obligations.',
    `fire_department_notified` BOOLEAN COMMENT 'Indicates whether the fire department was formally notified as part of this emergency activation. Required for NFPA 101 and OSHA compliance documentation.',
    `incident_commander_name` STRING COMMENT 'Full name of the designated Incident Commander (IC) who assumed operational control of the emergency response under the Incident Command System (ICS). May differ from the activating authority if command was transferred.',
    `incident_severity_level` STRING COMMENT 'Standardized severity classification of the emergency incident at time of activation (Level 1 = minor/localized to Level 5 = catastrophic/mass casualty). Drives resource mobilization, agency notification requirements, and executive escalation protocols.. Valid values are `level_1|level_2|level_3|level_4|level_5`',
    `incident_trigger_description` STRING COMMENT 'Narrative description of the specific incident, condition, or threat that triggered the emergency plan activation. Captures the initiating event details for after-action review and regulatory reporting.',
    `insurance_claim_filed` BOOLEAN COMMENT 'Indicates whether an insurance claim has been filed in connection with this emergency activation. Triggers financial reporting workflows and links to the finance domain for claim tracking.',
    `lockdown_initiated` BOOLEAN COMMENT 'Indicates whether a venue lockdown (perimeter secured, no entry/exit permitted) was initiated as part of this emergency activation. Critical for active shooter and terrorism threat plan types.',
    `medical_transports_count` STRING COMMENT 'Number of individuals transported by EMS or other medical transport to off-site medical facilities during or immediately following the emergency activation. Supports EMS coordination reporting and insurance documentation.',
    `other_agencies_notified` STRING COMMENT 'Free-text or comma-separated list of additional agencies notified beyond police, fire, EMS, and FBI (e.g., DHS, ATF, Local Emergency Management, Red Cross, FEMA). Captures full notification scope for compliance and after-action review.',
    `plan_type` STRING COMMENT 'Classification of the type of emergency response plan activated. Determines the response protocol, agencies notified, and command structure engaged. [ENUM-REF-CANDIDATE: evacuation|shelter_in_place|medical_emergency|fire|security_threat|natural_disaster|crowd_crush|bomb_threat|active_shooter — promote to reference product]',
    `police_notified` BOOLEAN COMMENT 'Indicates whether law enforcement (police) was formally notified as part of this emergency activation. Required for regulatory compliance documentation and after-action reporting.',
    `regulatory_report_filed` BOOLEAN COMMENT 'Indicates whether a mandatory regulatory report (e.g., OSHA fatality/hospitalization report, FCC emergency alert report, local authority notification) has been filed for this emergency activation.',
    `regulatory_report_reference` STRING COMMENT 'Reference number or tracking identifier for the regulatory report filed with the applicable authority (OSHA, FCC, local emergency management). Populated only when regulatory_report_filed is True.',
    `response_duration_minutes` STRING COMMENT 'Total elapsed time in minutes from activation_timestamp to all_clear_timestamp. Captured as a stored business metric (not derived at query time) to support SLA compliance reporting and benchmarking against emergency response KPI targets.',
    `shelter_in_place_initiated` BOOLEAN COMMENT 'Indicates whether a shelter-in-place directive was issued to venue occupants as part of this emergency activation. Mutually exclusive with full evacuation in most scenarios.',
    `threat_category` STRING COMMENT 'Broad category of the threat or hazard that prompted the emergency activation. Used for trend analysis, risk modeling, and compliance reporting across venue and event portfolios. [ENUM-REF-CANDIDATE: physical|medical|environmental|structural|cyber|crowd|weather|terrorism — 8 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this emergency activation record was most recently modified. Serves as the RECORD_AUDIT_UPDATED category for TRANSACTION_HEADER role. Supports change tracking and Silver Layer data freshness monitoring.',
    CONSTRAINT pk_emergency_activation PRIMARY KEY(`emergency_activation_id`)
) COMMENT 'Transactional record of each emergency response plan activation at a Sports Entertainment venue or event. Captures activation timestamp, plan activated, activating authority, event reference, incident trigger description, command post location, agencies notified (police, fire, EMS, FBI), evacuation initiated flag, all-clear timestamp, after-action report reference, and casualties/injuries count. SSOT for emergency response execution history.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`law_enforcement_deployment` (
    `law_enforcement_deployment_id` BIGINT COMMENT 'Unique surrogate identifier for each law enforcement deployment record within the Sports Entertainment security domain. Primary key for this transactional entity. Role: TRANSACTION_HEADER.',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: Law enforcement deployments for high-profile broadcast events (championship PPV, international feeds) are scaled based on broadcast significance and expected audience. Linking deployment to the broadc',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Law enforcement deployments carry estimated_cost_usd and actual_cost_usd fields requiring cost center allocation for event P&L and budget variance reporting. Sports entertainment finance teams track l',
    `event_fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event for which this law enforcement deployment is coordinated. Links deployment to the specific game, concert, or live experience.',
    `fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event for which this law enforcement deployment is coordinated. Links deployment to the specific game, concert, or live experience.',
    `forecast_output_id` BIGINT COMMENT 'Foreign key linking to analytics.forecast_output. Business justification: Law Enforcement Resource Planning process: officer_count_planned in law_enforcement_deployment is determined by attendance forecasts. Linking to forecast_output provides audit traceability for mutual ',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Law enforcement deployments are tied to franchise home games. Franchise-level deployment records support cost allocation between franchise and league, league safety audits, and mutual aid agreement tr',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-level law enforcement deployment aggregation is required for league annual safety budget reporting, CBA compliance covering player safety provisions, and regulatory submissions to local and fed',
    `matter_id` BIGINT COMMENT 'Foreign key linking to legal.legal_matter. Business justification: Law enforcement deployment cost recovery disputes, mutual aid agreement breaches, and indemnification claims generate legal matters. Legal teams managing agency disputes and contract enforcement requi',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to partner.purchase_order. Business justification: Law enforcement deployments at sports events are billed via purchase orders for cost reimbursement. Linking to partner.purchase_order enables three-way match (PO/GR/invoice) for law enforcement cost p',
    `venue_id` BIGINT COMMENT 'Reference to the venue where the deployment is executed. Supports venue-level security planning, capacity analysis, and ADA compliance reporting.',
    `augmented_law_enforcement_deployment_id` BIGINT COMMENT 'Self-referencing FK on law_enforcement_deployment (augmented_law_enforcement_deployment_id)',
    `actual_cost_usd` DECIMAL(18,2) COMMENT 'Actual invoiced or billed cost in US Dollars for this law enforcement deployment following event completion. Reconciled against estimated_cost_usd for financial reporting and mutual aid cost recovery.',
    `agency_name` STRING COMMENT 'Full official name of the law enforcement agency or private security contractor deployed (e.g., Los Angeles Police Department, Federal Bureau of Investigation, Allied Universal Security).',
    `agency_type` STRING COMMENT 'Classification of the deploying agency by jurisdictional level and organizational type. Drives mutual aid agreement requirements and command hierarchy protocols.. Valid values are `local_police|state_police|federal_agency|private_contractor|military_support`',
    `armed_officers_count` STRING COMMENT 'Number of armed officers within this deployment. Supports weapons accountability, insurance reporting, and compliance with venue firearms policies and local ordinances.',
    `arrests_made_count` STRING COMMENT 'Number of arrests made by law enforcement during this deployment. Required for league compliance reporting (NFL, NBA, FIFA), venue licensing, and public safety analytics.',
    `command_liaison_badge_number` STRING COMMENT 'Official badge or identification number of the command liaison officer. Used for identity verification, official documentation, and post-event debrief records.',
    `command_liaison_name` STRING COMMENT 'Full name of the senior law enforcement officer or agency representative serving as the primary command liaison for this deployment. Used for inter-agency coordination and incident escalation.',
    `command_liaison_phone` STRING COMMENT 'Direct contact phone number for the command liaison officer during the event. Critical for real-time incident coordination and emergency escalation.. Valid values are `^+?[1-9]d{1,14}$`',
    `contract_reference` STRING COMMENT 'Reference number of the private security contractor agreement or law enforcement services contract governing this deployment. Applicable for private contractor deployments; null for public agency deployments under mutual aid.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this law enforcement deployment record was first created in the system. Supports audit trail, data lineage, and SOX financial controls compliance.',
    `debrief_completed_flag` BOOLEAN COMMENT 'Indicates whether the post-event debrief session with the law enforcement agency has been completed. Drives workflow completion and compliance closure in the security operations process.',
    `debrief_date` DATE COMMENT 'Date on which the post-event debrief session was conducted with the law enforcement agency command liaison. Required for after-action reporting and continuous improvement of security protocols.',
    `debrief_notes` STRING COMMENT 'Narrative notes captured during the post-event debrief session documenting observations, incidents, lessons learned, and recommendations for future deployments. Supports continuous improvement of security operations.',
    `deployment_end_timestamp` TIMESTAMP COMMENT 'The actual date and time when the law enforcement unit concluded deployment and was released from the event. Used for billing reconciliation, mutual aid cost recovery, and post-event debrief scheduling.',
    `deployment_number` STRING COMMENT 'Externally-known business identifier for the deployment, used in mutual aid agreements, post-event debrief reports, and inter-agency communications. Format: LED-{YYYY}-{NNNNNN}.. Valid values are `^LED-[0-9]{4}-[0-9]{6}$`',
    `deployment_start_timestamp` TIMESTAMP COMMENT 'The actual date and time when the law enforcement unit commenced deployment at the venue or event perimeter. Principal real-world business event timestamp per TRANSACTION_HEADER role.',
    `deployment_status` STRING COMMENT 'Current lifecycle state of the law enforcement deployment from initial planning through post-event completion or cancellation.. Valid values are `planned|confirmed|active|completed|cancelled|stood_down`',
    `deployment_type` STRING COMMENT 'Operational classification of the deployment describing the tactical role and positioning of the law enforcement unit. [ENUM-REF-CANDIDATE: perimeter|inside_venue|mounted|k9|plainclothes|aerial|water_patrol — promote to reference product if additional types are added]',
    `deployment_zone_assignment` STRING COMMENT 'Description of the specific venue zone(s), perimeter sectors, or operational areas assigned to this deployment unit. Complements the access_zone reference for multi-zone or perimeter deployments not mapped to a single zone.',
    `ejections_count` STRING COMMENT 'Number of fan or attendee ejections from the venue facilitated by law enforcement during this deployment. Supports crowd management analytics and league compliance reporting.',
    `estimated_cost_usd` DECIMAL(18,2) COMMENT 'Estimated total cost in US Dollars for this law enforcement deployment as projected during event planning. Used for budget planning in Workday Adaptive Planning and cost center allocation in SAP S/4HANA CO.',
    `federal_agency_code` STRING COMMENT 'Standardized code identifying the specific federal agency when agency_type is federal_agency. Null or N/A for non-federal deployments. Supports federal coordination and reporting obligations. [ENUM-REF-CANDIDATE: FBI|DHS|SECRET_SERVICE|ATF|DEA|TSA|USMS|OTHER|N/A — 9 candidates stripped; promote to reference product]',
    `incident_command_post_location` STRING COMMENT 'Physical location description of the Incident Command Post (ICP) established for this deployment within or adjacent to the venue. Used for emergency response coordination and post-event documentation.',
    `incidents_reported_count` STRING COMMENT 'Number of security incidents formally reported by the law enforcement unit during this deployment. Used for post-event analysis, insurance reporting, and league compliance reporting.',
    `k9_unit_flag` BOOLEAN COMMENT 'Indicates whether this deployment includes a K9 (canine) unit for explosive detection, crowd control, or narcotics screening. Drives specific venue access and handler coordination requirements.',
    `medical_assists_count` STRING COMMENT 'Number of medical assistance events where law enforcement provided first response support during this deployment. Supports OSHA compliance reporting and venue safety analytics.',
    `mounted_unit_flag` BOOLEAN COMMENT 'Indicates whether this deployment includes a mounted (equestrian) unit for crowd management and perimeter control. Drives specific venue access, staging area, and animal welfare coordination requirements.',
    `mutual_aid_agreement_ref` STRING COMMENT 'Reference number or identifier of the mutual aid agreement governing this law enforcement deployment. Links to the formal inter-agency agreement authorizing resource sharing and cost recovery.',
    `officer_count_actual` STRING COMMENT 'Actual number of law enforcement officers or security personnel who reported for and executed this deployment. Used for billing, compliance verification, and post-event debrief analysis.',
    `officer_count_planned` STRING COMMENT 'Number of law enforcement officers or security personnel originally planned for this deployment as specified in the security operations plan or mutual aid agreement.',
    `overtime_authorized_flag` BOOLEAN COMMENT 'Indicates whether overtime hours have been pre-authorized for this deployment. Drives cost accrual in SAP S/4HANA FI/CO and mutual aid cost recovery calculations.',
    `radio_channel_assignment` STRING COMMENT 'Designated radio frequency channel or talkgroup assigned to this law enforcement deployment for inter-agency communications during the event. Critical for incident command coordination.',
    `scheduled_end_timestamp` TIMESTAMP COMMENT 'Planned date and time for the deployment to conclude as agreed in the security operations plan. Compared against deployment_end_timestamp for post-event cost and resource reconciliation.',
    `scheduled_start_timestamp` TIMESTAMP COMMENT 'Planned date and time for the deployment to begin as agreed in the security operations plan. Compared against deployment_start_timestamp to measure adherence to security timelines.',
    `sear_rating` STRING COMMENT 'DHS Special Event Assessment Rating assigned to the event, determining the level of federal law enforcement coordination and resource deployment required. SEAR-1 is the highest federal interest; SEAR-5 is local-only.. Valid values are `SEAR-1|SEAR-2|SEAR-3|SEAR-4|SEAR-5`',
    `threat_level` STRING COMMENT 'DHS-aligned threat assessment level assigned to this event that drove the deployment scale and type. Aligns with the DHS National Terrorism Advisory System (NTAS) and Special Event Assessment Rating (SEAR) classifications.. Valid values are `low|guarded|elevated|high|severe`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this law enforcement deployment record was last modified. Supports audit trail, change tracking, and data quality monitoring in the Databricks Silver Layer.',
    `vehicles_assigned_count` STRING COMMENT 'Number of law enforcement vehicles (patrol cars, motorcycles, command vehicles) assigned to this deployment. Used for venue parking allocation, staging logistics, and cost reconciliation.',
    CONSTRAINT pk_law_enforcement_deployment PRIMARY KEY(`law_enforcement_deployment_id`)
) COMMENT 'Transactional record of law enforcement agency deployments coordinated for Sports Entertainment events — local police, state police, federal agencies (FBI, DHS, Secret Service), and private security contractors. Captures agency name, deployment type (perimeter, inside venue, mounted, K9, plainclothes), officer count, deployment start/end times, command liaison contact, mutual aid agreement reference, and post-event debrief notes.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`threat_assessment` (
    `threat_assessment_id` BIGINT COMMENT 'Unique system-generated identifier for each formal threat assessment record within the Sports Entertainment security domain.',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: Threat assessments are calibrated to broadcast significance — PPV events, international feeds, and high-profile broadcasts attract elevated threat profiles. threat_assessment.broadcast_event_flag (pla',
    `emergency_response_plan_id` BIGINT COMMENT 'Foreign key linking to security.emergency_response_plan. Business justification: A threat assessment identifies the applicable emergency response plan that should be activated if the assessed threat materializes. The existing emergency_response_plan_reference (STRING) is a denorma',
    `employee_id` BIGINT COMMENT 'Reference to the security officer or analyst who authored and submitted this threat assessment. Used for accountability, chain-of-custody, and law enforcement briefing attribution.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event (game, concert, match, PPV broadcast event) for which this threat assessment was conducted. Null if assessment is venue-level or person-of-interest only.',
    `fan_profile_id` BIGINT COMMENT 'Reference to the individual identified as a person of interest in this threat assessment. Populated only when assessment_type is person-of-interest. Classified as restricted PII due to law enforcement sensitivity.',
    `fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event (game, concert, match, PPV broadcast event) for which this threat assessment was conducted. Null if assessment is venue-level or person-of-interest only.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Threat assessments are conducted for specific franchise home games. Franchise-level threat history tracking feeds league competitive integrity reviews, insurance risk profiling, and DHS coordination t',
    `integrity_alert_id` BIGINT COMMENT 'Foreign key linking to gaming.integrity_alert. Business justification: Pre-event threat assessments for high-risk fixtures incorporate active gaming integrity alerts (e.g., unusual betting volumes signaling match-fixing). Security analysts reference the integrity alert w',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped threat assessments are required for league-level security planning, DHS coordination, and year-over-year threat trend reporting submitted to league governing bodies and federal agencies.',
    `matter_id` BIGINT COMMENT 'Foreign key linking to legal.legal_matter. Business justification: Threat assessments involving named subjects generate legal matters for restraining orders, trespass proceedings, and regulatory notifications to law enforcement. Legal teams opening matters for credib',
    `primary_threat_employee_id` BIGINT COMMENT 'Reference to the security officer or analyst who authored and submitted this threat assessment. Used for accountability, chain-of-custody, and law enforcement briefing attribution.',
    `security_incident_id` BIGINT COMMENT 'Foreign key linking to security.security_incident. Business justification: Threat assessments frequently reference prior security incidents as intelligence inputs — a prior_incident_flag and prior_incident_reference (STRING) already exist on the table, indicating this relati',
    `reviewing_officer_employee_id` BIGINT COMMENT 'Reference to the senior security officer or supervisor who reviewed and approved this threat assessment. Supports dual-control and chain-of-command validation.',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Threat assessments are conducted for specific athletes — either threats directed at athletes (requiring protective detail) or athlete conduct risks. Role prefix subject_ is required as threat_assess',
    `suspension_record_id` BIGINT COMMENT 'Foreign key linking to athlete.suspension_record. Business justification: Security threat assessment teams incorporate athlete suspension history — especially violence-related or conduct violations — into venue risk evaluations. Role prefix subject_ distinguishes this fro',
    `venue_ban_id` BIGINT COMMENT 'Foreign key linking to security.venue_ban. Business justification: A threat assessment may result in or reference a venue ban issued against the assessed subject. The existing ban_reference_number (STRING) is a denormalized text reference to the ban record; replacing',
    `venue_id` BIGINT COMMENT 'Reference to the Sports Entertainment venue (stadium, arena, concert hall) that is the subject of or host for this threat assessment.',
    `updated_threat_assessment_id` BIGINT COMMENT 'Self-referencing FK on threat_assessment (updated_threat_assessment_id)',
    `assessment_narrative` STRING COMMENT 'Full narrative description of the threat assessment findings, including threat actor behavior indicators, intelligence corroboration, vulnerability analysis, and contextual factors. Core content of law enforcement briefing packages.',
    `assessment_number` STRING COMMENT 'Externally-referenced alphanumeric identifier for the threat assessment, used in law enforcement briefing packages, DHS/FBI coordination, and inter-agency communications. Format: TA-{YYYY}-{NNNNNN}.. Valid values are `^TA-[0-9]{4}-[0-9]{6}$`',
    `assessment_status` STRING COMMENT 'Current lifecycle state of the threat assessment record: draft (initial capture), under-review (being evaluated by security leadership), approved (formally endorsed), active (countermeasures in effect), closed (threat resolved or mitigated), archived (retained for historical record).. Valid values are `draft|under-review|approved|active|closed|archived`',
    `assessment_timestamp` TIMESTAMP COMMENT 'The precise date and time at which the formal threat assessment was conducted and documented. This is the principal real-world event time, distinct from record creation audit timestamps.',
    `assessment_type` STRING COMMENT 'Classification of the scope of the threat assessment: event-level (specific event), venue-level (facility-wide), person-of-interest (individual subject), regional (geographic area), or cyber-physical (combined digital and physical threat). [ENUM-REF-CANDIDATE: event-level|venue-level|person-of-interest|regional|cyber-physical — promote to reference product]. Valid values are `event-level|venue-level|person-of-interest|regional|cyber-physical`',
    `consequence_rating` STRING COMMENT 'Assessment of the potential impact severity if the threat materializes, covering life safety, operational disruption, reputational damage, and financial loss. Aligned with ISO 31000 and DHS THIRA consequence descriptors.. Valid values are `catastrophic|major|moderate|minor|negligible`',
    `countermeasures_status` STRING COMMENT 'Current implementation status of the recommended countermeasures: not-initiated, in-planning, partially-implemented, fully-implemented, or not-required (threat resolved before implementation).. Valid values are `not-initiated|in-planning|partially-implemented|fully-implemented|not-required`',
    `countermeasures_summary` STRING COMMENT 'Narrative summary of recommended security countermeasures derived from this threat assessment, including enhanced screening protocols, access zone restrictions, surveillance augmentation, law enforcement deployment, and crowd management adjustments.',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this threat assessment record was first captured in the system. Used for data lineage, compliance auditing, and SLA tracking.',
    `crowd_size_estimate` STRING COMMENT 'Estimated attendance or crowd size for the associated event or venue at the time of the threat assessment. A key input to consequence rating and crowd management countermeasure planning.',
    `data_source_system` STRING COMMENT 'Name of the operational system of record from which this threat assessment record originated or was ingested (e.g., internal security management platform, DHS HSIN portal, law enforcement information sharing system). Supports data lineage in the Databricks Silver Layer.',
    `dhs_coordination_flag` BOOLEAN COMMENT 'Indicates whether this threat assessment has been shared with or coordinated through the Department of Homeland Security (DHS). True when DHS has been formally notified or is actively involved.',
    `disposition` STRING COMMENT 'Final or current disposition decision for this threat assessment: monitor (ongoing surveillance), escalate (elevated response), refer-to-law-enforcement (formal handoff), ban-issued (venue or event ban applied), no-action (threat not substantiated), resolved (threat neutralized or mitigated).. Valid values are `monitor|escalate|refer-to-law-enforcement|ban-issued|no-action|resolved`',
    `evacuation_plan_flag` BOOLEAN COMMENT 'Indicates whether this threat assessment has triggered a review or activation of the venue or event evacuation plan.',
    `expiry_date` DATE COMMENT 'Date after which this threat assessment is considered expired and must be formally re-evaluated or archived. Ensures assessments do not remain active beyond their valid intelligence window.',
    `fbi_coordination_flag` BOOLEAN COMMENT 'Indicates whether this threat assessment has been shared with or coordinated through the Federal Bureau of Investigation (FBI). True when FBI has been formally notified or is actively involved in the threat response.',
    `intelligence_classification` STRING COMMENT 'Handling classification of the underlying intelligence that supports this threat assessment, governing distribution and access controls within Sports Entertainment and partner agencies.. Valid values are `unclassified|law-enforcement-sensitive|confidential|secret`',
    `intelligence_source_types` STRING COMMENT 'Pipe-delimited list of intelligence source categories that informed this assessment (e.g., HUMINT|OSINT|SIGINT|law-enforcement-tip|social-media-monitoring|venue-staff-report). Supports source attribution and analytical confidence scoring.',
    `law_enforcement_case_number` STRING COMMENT 'Official case or incident number assigned by the coordinating law enforcement agency (FBI, DHS, local police) for cross-referencing this threat assessment with external agency records.',
    `likelihood_rating` STRING COMMENT 'Assessment of the probability that the identified threat will materialize, using a standardized five-point scale aligned with ISO 31000 risk likelihood descriptors.. Valid values are `almost-certain|likely|possible|unlikely|rare`',
    `local_law_enforcement_flag` BOOLEAN COMMENT 'Indicates whether local law enforcement agencies (municipal police, county sheriff) have been briefed on or are coordinating response to this threat assessment.',
    `prior_incident_flag` BOOLEAN COMMENT 'Indicates whether the subject or threat actor has a documented prior security incident history within Sports Entertainment venues or events. Supports recidivism risk scoring and escalation decisions.',
    `review_date` DATE COMMENT 'Scheduled date for the next formal review of this threat assessment to determine whether the threat level, countermeasures, or disposition require updating. Drives security planning calendar.',
    `sear_level` STRING COMMENT 'DHS Special Event Assessment Rating (SEAR) level assigned to the associated event, ranging from SEAR I (highest national significance) to SEAR V (local significance). Drives federal resource allocation and security planning requirements.. Valid values are `I|II|III|IV|V`',
    `subject_affiliation` STRING COMMENT 'Known organizational, group, or ideological affiliation of the person of interest or threat actor (e.g., extremist group, rival organization, disgruntled former employee). Informs threat context and law enforcement briefings.',
    `threat_category` STRING COMMENT 'Primary classification of the threat type being assessed: terrorism (organized attack), targeted-violence (individual or group directed violence), cyber-physical (combined digital and physical attack vector), civil-unrest (crowd disorder, protest escalation), natural-hazard (weather, seismic), insider-threat (credentialed individual). [ENUM-REF-CANDIDATE: terrorism|targeted-violence|cyber-physical|civil-unrest|natural-hazard|insider-threat — promote to reference product]. Valid values are `terrorism|targeted-violence|cyber-physical|civil-unrest|natural-hazard|insider-threat`',
    `threat_level` STRING COMMENT 'Formal threat level rating assigned by the assessing officer, aligned with DHS National Terrorism Advisory System (NTAS) and internal Sports Entertainment security protocols: critical (imminent, credible threat), high (elevated, specific indicators), medium (general indicators), low (baseline), informational (intelligence note only).. Valid values are `critical|high|medium|low|informational`',
    `threat_level_score` STRING COMMENT 'Numeric risk score (typically 1–100) derived from the formal threat assessment methodology, enabling quantitative comparison, trending, and AI/ML model inputs across assessments.',
    `threat_subcategory` STRING COMMENT 'Secondary classification providing granular detail within the threat category (e.g., vehicle-ramming, active-shooter, IED, ransomware, crowd-crush, stalking). Free-text to accommodate evolving threat typologies.',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this threat assessment record was last modified. Supports change tracking, version control, and compliance audit trails.',
    `vip_presence_flag` BOOLEAN COMMENT 'Indicates whether a VIP (Very Important Person) — such as a head of state, celebrity athlete, or high-profile sponsor — is expected to be present at the assessed event or venue, elevating the threat profile and security requirements.',
    `vulnerability_summary` STRING COMMENT 'Summary of identified physical, operational, or cyber-physical vulnerabilities at the venue or event that are relevant to this threat assessment. Informs countermeasure prioritization.',
    CONSTRAINT pk_threat_assessment PRIMARY KEY(`threat_assessment_id`)
) COMMENT 'Master record for formal threat assessments conducted for Sports Entertainment events, venues, or individuals of concern. Captures assessment type (event-level, venue-level, person-of-interest), threat category (terrorism, targeted violence, cyber-physical), threat level rating, intelligence sources, recommended countermeasures, DHS/FBI coordination flag, assessment author, review date, and disposition. Feeds event security planning and law enforcement briefing packages.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`prohibited_item` (
    `prohibited_item_id` BIGINT COMMENT 'Unique surrogate identifier for each prohibited item record in the venue security reference catalog. Primary key for the prohibited_item data product.',
    `league_id` BIGINT COMMENT 'Foreign key linking to league.league. Business justification: Prohibited items policies are league-specific (NFL, NBA, MLS have different lists). Linking prohibited_item to league enables league-specific policy management and compliance reporting. league_policy_',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Prohibited items lists are formally governed by compliance policies (venue policy, league policy, ADA policy). The prohibited_item already has league_policy_reference and regulatory_citation as plain ',
    `parent_prohibited_item_id` BIGINT COMMENT 'Self-referencing FK on prohibited_item (parent_prohibited_item_id)',
    `ada_consideration_notes` STRING COMMENT 'Notes documenting any ADA accommodation exceptions or special handling procedures for this prohibited item category (e.g., medical devices, mobility aids, prescribed medications that may resemble prohibited items). Ensures compliance with ADA accessibility requirements.',
    `applicable_event_types` STRING COMMENT 'Comma-separated list of event type codes for which this prohibition is enforced (e.g., NFL_GAME, NBA_GAME, CONCERT, PPV_EVENT, CHAMPIONSHIP). Supports event-specific restriction configuration distinct from venue-level rules.',
    `applicable_venue_types` STRING COMMENT 'Comma-separated list of venue type codes to which this prohibition applies (e.g., STADIUM, ARENA, AMPHITHEATER, CONCERT_HALL, OUTDOOR_FESTIVAL). Enables venue-specific policy enforcement and checkpoint configuration. [ENUM-REF-CANDIDATE: stadium|arena|amphitheater|concert_hall|outdoor_festival|training_facility|broadcast_studio|all — promote to reference product]',
    `approved_by` STRING COMMENT 'Name or employee identifier of the security policy authority (e.g., Chief Security Officer, VP of Venue Operations) who formally approved this prohibited item policy record for enforcement.',
    `approved_date` DATE COMMENT 'Date on which this prohibited item policy record received formal approval from the designated security policy authority. Supports governance audit trail and SOX compliance documentation.',
    `broadcast_interference_flag` BOOLEAN COMMENT 'Indicates whether this item poses a risk of interfering with broadcast operations, OB (Outside Broadcast) equipment, or IPTV/CDN signal distribution (e.g., laser pointers, unauthorized RF transmitters, drones). Supports coordination with broadcast production teams.',
    `confiscation_action` STRING COMMENT 'Standardized action code indicating the disposition of the prohibited item upon confiscation. Used to drive automated workflow routing in screening event records and incident management systems.. Valid values are `surrender_at_gate|law_enforcement_handoff|secure_storage|destruction|denial_of_entry`',
    `confiscation_protocol` STRING COMMENT 'Standardized procedure code or narrative describing the required officer action upon detection of this prohibited item at a screening checkpoint (e.g., voluntary surrender at gate, law enforcement handoff, secure storage for retrieval, destruction). Drives officer training and incident documentation.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this prohibited item policy record was first created in the security reference catalog. Supports data lineage, audit trail, and Silver Layer lakehouse governance requirements.',
    `denial_of_entry_required` BOOLEAN COMMENT 'Indicates whether possession of this item at a screening checkpoint mandates denial of venue entry to the bearer, even if the item is surrendered. Applies to items posing ongoing safety risk.',
    `detection_method` STRING COMMENT 'Primary screening method(s) used to detect this prohibited item at checkpoints (e.g., magnetometer, walk-through metal detector, X-ray, physical pat-down, canine unit, visual inspection). Informs checkpoint equipment configuration and officer training. [ENUM-REF-CANDIDATE: magnetometer|xray|physical_pat_down|canine_unit|visual_inspection|millimeter_wave|explosive_trace_detection|multi_method — promote to reference product]',
    `effective_date` DATE COMMENT 'The date from which this prohibited item policy record becomes enforceable at venue screening checkpoints. Used to activate the record in checkpoint configuration systems.',
    `escalation_required` BOOLEAN COMMENT 'Indicates whether detection of this item requires escalation to a security supervisor or incident command beyond standard officer response. Supports tiered response protocol enforcement.',
    `exemption_credential_types` STRING COMMENT 'Comma-separated list of credential types that may be granted an exemption from this prohibition (e.g., LAW_ENFORCEMENT, MEDICAL_STAFF, BROADCAST_CREW, VIP_CREDENTIAL). Supports conditional enforcement logic at access checkpoints.',
    `expiry_date` DATE COMMENT 'The date on which this prohibited item policy record ceases to be enforceable. Null indicates an open-ended policy with no scheduled expiration. Supports time-bound event-specific restrictions.',
    `fan_communication_text` STRING COMMENT 'Public-facing text used in fan communications, ticketing platforms (Ticketmaster/AXS), venue signage, and digital channels to inform attendees of this prohibition. Supports consistent messaging across Adobe Experience Platform and DTC fan engagement channels.',
    `incident_report_required` BOOLEAN COMMENT 'Indicates whether every detection of this prohibited item must generate a formal incident report regardless of confiscation outcome. Supports compliance audit trails and regulatory reporting.',
    `ip_rights_risk_flag` BOOLEAN COMMENT 'Indicates whether this item poses a risk to intellectual property (IP) or digital rights management (DRM) protections, such as unauthorized recording devices, professional camera equipment, or streaming devices that could enable unauthorized content distribution.',
    `item_category` STRING COMMENT 'High-level classification grouping the prohibited item into a security threat or policy category (e.g., Weapons, Prohibited Containers, Surveillance Equipment, Pyrotechnics, Drones, Professional Camera Equipment, Hazardous Materials, Alcohol). [ENUM-REF-CANDIDATE: weapons|prohibited_containers|surveillance_equipment|pyrotechnics|drones|professional_camera_equipment|hazardous_materials|alcohol|laser_devices|signage|animals|other — promote to reference product]',
    `item_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the prohibited item within the security policy catalog. Used as the business key for cross-system reference and checkpoint enforcement documentation.. Valid values are `^[A-Z]{2,6}-[0-9]{4,8}$`',
    `item_description` STRING COMMENT 'Detailed narrative description of the prohibited item including physical characteristics, size thresholds, material composition, and distinguishing features to assist security officers in identification during screening.',
    `item_name` STRING COMMENT 'Short, human-readable name of the prohibited item as it appears on public-facing signage, fan communications, and screening checkpoint reference cards (e.g., Laser Pointer, Unmanned Aerial Vehicle / Drone, Oversized Bag).',
    `item_subcategory` STRING COMMENT 'Secondary classification providing finer granularity within the item category (e.g., within Weapons: Firearms, Edged Weapons, Blunt Instruments, Projectile Devices; within Containers: Glass Bottles, Metal Cans, Hard-Sided Coolers). Supports tiered enforcement protocols.',
    `last_review_date` DATE COMMENT 'Date on which this prohibited item policy record was last reviewed and validated by the security policy governance team. Supports periodic compliance review cycles mandated by DHS and league governing bodies.',
    `law_enforcement_notification_required` BOOLEAN COMMENT 'Indicates whether detection of this prohibited item mandates immediate notification of on-site law enforcement personnel. True for weapons, explosives, and other items posing imminent public safety risk.',
    `next_review_date` DATE COMMENT 'Date on which the next mandatory review of this prohibited item policy record is scheduled. Drives compliance calendar and governance workflow triggers.',
    `policy_status` STRING COMMENT 'Current lifecycle status of this prohibited item policy record. Active records are enforced at screening checkpoints. Inactive or superseded records are retained for historical audit and compliance purposes.. Valid values are `active|inactive|pending_review|superseded`',
    `prohibition_basis` STRING COMMENT 'The regulatory, legal, or policy authority that mandates or authorizes the prohibition of this item (e.g., DHS Venue Security Guidelines, NFL Security Policy, Local Ordinance, State Law, WADA, FCC Regulation). Supports compliance documentation and legal defensibility. [ENUM-REF-CANDIDATE: dhs_venue_security|league_policy|local_ordinance|state_law|federal_law|wada|fcc|osha|ada|iso_20121|internal_policy — promote to reference product]',
    `prohibition_type` STRING COMMENT 'Indicates whether the item is absolutely prohibited at all times (absolute), prohibited only under specific conditions such as size or quantity thresholds (conditional), or restricted only for designated event types such as PPV or championship events (event_specific). Drives checkpoint officer decision logic.. Valid values are `absolute|conditional|event_specific`',
    `receipt_required_flag` BOOLEAN COMMENT 'Indicates whether a confiscation receipt must be issued to the bearer when this item is surrendered or seized at a screening checkpoint. Supports chain-of-custody documentation and legal defensibility.',
    `size_threshold_description` STRING COMMENT 'Narrative description of any size, dimension, or capacity threshold that triggers the prohibition for conditional items (e.g., Bags exceeding 12x6x12 inches, Containers larger than 1 liter, Camera lenses longer than 6 inches). Applicable when prohibition_type is conditional.',
    `source_policy_document` STRING COMMENT 'Reference to the source security policy document, version, and section from which this prohibited item definition was derived (e.g., Sports Entertainment Venue Security Policy v4.2, Section 3.1). Supports traceability and policy version management.',
    `storage_available_flag` BOOLEAN COMMENT 'Indicates whether the venue offers secure storage or check-in facilities where fans may voluntarily surrender and retrieve this item rather than being denied entry. Supports fan experience and ADA accommodation considerations.',
    `superseded_by_item_code` STRING COMMENT 'The item_code of the newer prohibited item record that replaces this record when policy_status is superseded. Enables forward navigation in the policy version chain for compliance audit purposes.',
    `threat_level` STRING COMMENT 'Assessed security threat severity associated with this prohibited item, used to prioritize officer response, resource allocation, and escalation protocols. Aligned with DHS threat classification framework.. Valid values are `critical|high|medium|low`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this prohibited item policy record was most recently modified. Supports incremental data processing in the Databricks Lakehouse Silver Layer and change data capture workflows.',
    `version_number` STRING COMMENT 'Version number of this prohibited item policy record, incremented each time the record is materially updated. Supports policy change management and audit trail requirements.. Valid values are `^[0-9]+.[0-9]+(.[0-9]+)?$`',
    `wada_related_flag` BOOLEAN COMMENT 'Indicates whether this prohibited item is related to performance-enhancing drug (PED) paraphernalia or substances governed by WADA regulations. Relevant for events under IOC, FIFA, or other WADA-signatory governing bodies.',
    CONSTRAINT pk_prohibited_item PRIMARY KEY(`prohibited_item_id`)
) COMMENT 'Reference catalog of all prohibited items defined in Sports Entertainment venue security policies — weapons categories, prohibited containers, laser pointers, drones, professional camera equipment, and event-specific restrictions. Captures item category, item description, prohibition type (absolute/conditional), applicable venue types, regulatory basis (DHS, league policy, local ordinance), confiscation protocol, and effective date. Used to standardize screening checkpoint enforcement.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`confiscation_record` (
    `confiscation_record_id` BIGINT COMMENT 'Unique surrogate identifier for each confiscation record in the Sports Entertainment security domain. Primary key for the confiscation_record data product. Entity role: TRANSACTION_HEADER — represents a discrete security enforcement event with its own lifecycle.',
    `access_zone_id` BIGINT COMMENT 'Reference to the access zone within the venue where the confiscation occurred (e.g., perimeter, concourse, field-level). Supports zone-level security density analysis and resource allocation.',
    `contingent_worker_id` BIGINT COMMENT 'Foreign key linking to workforce.contingent_worker. Business justification: Vendor-supplied security officers (contingent workers) perform confiscations at screening checkpoints. The confiscation_record.employee_id covers staff employees only. Linking to contingent_worker ena',
    `employee_id` BIGINT COMMENT 'Reference to the security officer or law enforcement personnel who physically performed the confiscation. Satisfies TRANSACTION_HEADER PARTY_REFERENCE category. Links to the workforce/security officer master record.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event (game, concert, match) during which the confiscation occurred. Enables post-event prohibited item trend reporting by event type, league, or venue.',
    `fan_profile_id` BIGINT COMMENT 'Foreign key linking to fan.fan_profile. Business justification: Repeat prohibited-item offender tracking and CRM case escalation require linking confiscation records to the fan identity record. owner_full_name and owner_id_number are denormalized fan identity attr',
    `fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event (game, concert, match) during which the confiscation occurred. Enables post-event prohibited item trend reporting by event type, league, or venue.',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-level confiscation aggregation supports league prohibited items policy reviews, CBA compliance reporting, and annual fan safety submissions to league governing bodies covering all franchise hom',
    `litigation_case_id` BIGINT COMMENT 'Foreign key linking to legal.litigation_case. Business justification: Confiscation of weapons or controlled substances generates criminal proceedings and civil litigation. Legal teams need to link confiscation records to resulting cases for evidence chain-of-custody, di',
    `primary_confiscation_employee_id` BIGINT COMMENT 'Reference to the security officer or law enforcement personnel who physically performed the confiscation. Satisfies TRANSACTION_HEADER PARTY_REFERENCE category. Links to the workforce/security officer master record.',
    `prohibited_item_id` BIGINT COMMENT 'Reference to the prohibited_item reference product that classifies the type of item confiscated (e.g., weapon, alcohol, laser pointer, drone). Drives policy calibration and trend reporting by item category.',
    `screening_checkpoint_id` BIGINT COMMENT 'Reference to the specific screening checkpoint (entry gate, perimeter post, or in-venue security station) where the confiscation occurred. Enables checkpoint-level throughput and confiscation rate analysis.',
    `screening_event_id` BIGINT COMMENT 'Reference to the parent screening_event record that triggered this confiscation, enabling full traceability from the screening interaction to the confiscation outcome. Supports chain-of-custody linkage.',
    `security_incident_id` BIGINT COMMENT 'Foreign key linking to security.security_incident. Business justification: A confiscation of a prohibited item may escalate to or be associated with a security incident — particularly when the item is a weapon, controlled substance, or triggers an arrest. The existing incide',
    `shift_assignment_id` BIGINT COMMENT 'Reference to the security shift schedule record during which the confiscation occurred. Enables shift-level confiscation volume analysis and officer workload reporting.',
    `shift_shift_assignment_id` BIGINT COMMENT 'Reference to the security shift schedule record during which the confiscation occurred. Enables shift-level confiscation volume analysis and officer workload reporting.',
    `supervisor_employee_id` BIGINT COMMENT 'Reference to the security supervisor who oversaw or approved the confiscation action, particularly when escalation_flag is True. Supports chain-of-custody accountability and supervisory review workflows.',
    `venue_id` BIGINT COMMENT 'Reference to the Sports Entertainment venue where the confiscation took place. Supports venue-level prohibited item trend analysis and policy calibration across the facility portfolio.',
    `related_confiscation_record_id` BIGINT COMMENT 'Self-referencing FK on confiscation_record (related_confiscation_record_id)',
    `arrest_made_flag` BOOLEAN COMMENT 'Indicates whether the individual from whom the item was confiscated was arrested in connection with this confiscation event. True = arrest made; False = no arrest. Critical for law enforcement coordination reporting and venue safety KPI dashboards.',
    `chain_of_custody_notes` STRING COMMENT 'Free-text log of all custody transfers, handling events, and disposition actions for the confiscated item from point of seizure through final resolution. Supports legal defensibility, law enforcement handover documentation, and post-event audit reviews.',
    `confiscation_location_detail` STRING COMMENT 'Specific physical location description within the venue where the confiscation occurred (e.g., Gate C North Entry Lane 3, Section 112 Row 5, Concourse Level 2 near restrooms). Complements the access_zone_id with granular location data for incident mapping.',
    `confiscation_method` STRING COMMENT 'The method or trigger by which the prohibited item was identified and confiscated. Supports analysis of detection effectiveness across different security methods and informs resource deployment strategy.. Valid values are `screening_checkpoint|in_venue_patrol|tip_off|k9_detection|surveillance_referral|officer_observation`',
    `confiscation_number` STRING COMMENT 'Externally-known, human-readable reference number assigned to this confiscation event at the point of occurrence (e.g., CONF-2024-000123). Used on physical receipts issued to the item owner and in law enforcement handover documentation. Satisfies TRANSACTION_HEADER BUSINESS_IDENTIFIER category.. Valid values are `^CONF-[0-9]{4}-[0-9]{6}$`',
    `confiscation_status` STRING COMMENT 'Current lifecycle state of the confiscation record, tracking the disposition workflow from initial seizure through final resolution. open = newly recorded; held = item in secure storage; turned_over_to_law_enforcement = transferred to police/agency; destroyed = item disposed per policy; retrieved_by_owner = owner reclaimed item post-event; closed = record fully resolved. Satisfies TRANSACTION_HEADER LIFECYCLE_STATUS category.. Valid values are `open|held|turned_over_to_law_enforcement|destroyed|retrieved_by_owner|closed`',
    `confiscation_timestamp` TIMESTAMP COMMENT 'Precise date and time (ISO 8601 with timezone offset) when the prohibited item was physically confiscated from the individual. This is the principal real-world event time, distinct from record creation. Satisfies TRANSACTION_HEADER BUSINESS_EVENT_TIMESTAMP category. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this confiscation record was first entered into the system, which may differ from the confiscation_timestamp if data entry was delayed. Satisfies TRANSACTION_HEADER RECORD_AUDIT_CREATED category. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `data_retention_expiry_date` DATE COMMENT 'Date after which this confiscation record and any associated personal data must be reviewed for deletion or anonymization per GDPR, CCPA, and internal data retention policies. Supports automated data lifecycle management in the Databricks Lakehouse. Format: yyyy-MM-dd.',
    `data_source_system` STRING COMMENT 'Identifies the operational system or method through which this confiscation record was originally captured (e.g., venue security platform, manual officer entry, integrated screening system, mobile officer application). Supports data lineage and Silver layer provenance tracking in the Databricks Lakehouse.. Valid values are `venue_security_platform|manual_entry|screening_system|mobile_officer_app`',
    `destruction_date` DATE COMMENT 'Date on which the confiscated item was destroyed per venue security policy. Populated only when disposition_type is destroyed. Supports compliance documentation for prohibited item disposal procedures. Format: yyyy-MM-dd.',
    `disposition_type` STRING COMMENT 'The final or intended disposition of the confiscated item. Drives storage, destruction, and law enforcement handover workflows. held_for_retrieval = stored for owner pickup post-event; destroyed = disposed per prohibited item policy; turned_over_to_law_enforcement = transferred to police/agency custody.. Valid values are `held_for_retrieval|destroyed|turned_over_to_law_enforcement|returned_to_owner|donated|other`',
    `entry_denied_flag` BOOLEAN COMMENT 'Indicates whether the individual from whom the item was confiscated was denied entry to the venue as a result of the confiscation. True = entry denied; False = individual permitted entry after confiscation. Supports access control outcome reporting.',
    `escalation_flag` BOOLEAN COMMENT 'Indicates whether this confiscation event was escalated beyond the initial confiscating officer (e.g., to a supervisor, law enforcement, or emergency response team). True = escalated; False = handled at officer level. Supports escalation rate KPI reporting.',
    `gate_number` STRING COMMENT 'Identifier of the entry gate or security lane at which the confiscation occurred during the screening process. Used for gate-level throughput and confiscation rate benchmarking.',
    `gdpr_data_subject_flag` BOOLEAN COMMENT 'Indicates whether the item owner whose personal data is captured in this record is a data subject under GDPR (i.e., an EU/EEA resident). True = GDPR applies; False = GDPR does not apply. Governs data retention, erasure rights, and processing lawfulness for owner identity fields.',
    `item_category` STRING COMMENT 'High-level classification of the confiscated item used for rapid trend reporting and policy calibration without requiring a join to the prohibited_item reference product. [ENUM-REF-CANDIDATE: weapon|alcohol|drug|pyrotechnic|laser_device|drone|oversized_bag|recording_device|food_beverage|other — promote to reference product]',
    `item_description` STRING COMMENT 'Free-text description of the specific confiscated item as recorded by the confiscating officer (e.g., 6-inch folding knife, black handle, half-full bottle of spirits). Provides granular detail beyond the category classification for incident reporting and law enforcement handover.',
    `item_quantity` STRING COMMENT 'Number of individual units of the prohibited item confiscated in this single confiscation event (e.g., 3 bottles of alcohol, 2 flares). Supports volume-based trend analysis and storage capacity planning. Satisfies TRANSACTION_HEADER QUANTITATIVE_RESULT category (non-monetary transaction).',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency (e.g., NYPD, FBI, Local Police Department) to which the confiscated item was turned over or that was notified. Populated when law_enforcement_notified_flag is True.',
    `law_enforcement_case_number` STRING COMMENT 'Official case or incident number assigned by the responding law enforcement agency when the confiscated item is turned over to police custody. Populated only when law_enforcement_notified_flag is True. Enables cross-reference with external law enforcement records.',
    `law_enforcement_notified_flag` BOOLEAN COMMENT 'Indicates whether law enforcement was notified as a result of this confiscation event. True = law enforcement contacted; False = handled internally. Triggers law enforcement handover workflow when True.',
    `owner_provided_flag` BOOLEAN COMMENT 'Indicates whether the individual from whom the item was confiscated voluntarily provided their identity information. True = identity provided; False = identity not provided or refused. Governs whether owner identity fields are populated and affects retrieval eligibility.',
    `owner_ticket_barcode` STRING COMMENT 'Barcode or ticket reference number from the ticket held by the individual from whom the item was confiscated. Links the confiscation event to the ticketing system (Ticketmaster/AXS) for fan identity resolution and post-event ban enforcement.',
    `receipt_issued_flag` BOOLEAN COMMENT 'Indicates whether a physical or digital confiscation receipt was issued to the item owner at the time of confiscation. True = receipt issued; False = no receipt issued (e.g., item immediately destroyed or owner refused). Supports retrieval claim validation.',
    `receipt_number` STRING COMMENT 'Unique receipt number printed on the confiscation receipt issued to the item owner. Used by the owner to claim the item post-event if disposition is held for retrieval. Populated only when receipt_issued_flag is True.. Valid values are `^RCP-[0-9]{4}-[0-9]{6}$`',
    `retrieval_date` DATE COMMENT 'Date on which the confiscated item was retrieved by its owner from secure storage post-event. Populated only when confiscation_status transitions to retrieved_by_owner. Format: yyyy-MM-dd.',
    `storage_location_code` STRING COMMENT 'Code identifying the secure storage location (locker, cage, evidence room) where the confiscated item is held when disposition_type is held_for_retrieval. Supports chain-of-custody tracking and retrieval operations.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this confiscation record, supporting audit trail and chain-of-custody integrity. Satisfies TRANSACTION_HEADER RECORD_AUDIT_UPDATED category. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `wada_substance_flag` BOOLEAN COMMENT 'Indicates whether the confiscated item is classified as a prohibited substance under the World Anti-Doping Agency (WADA) prohibited list. True = WADA-listed substance; False = not a WADA substance. Triggers mandatory reporting to league compliance and anti-doping authorities.',
    CONSTRAINT pk_confiscation_record PRIMARY KEY(`confiscation_record_id`)
) COMMENT 'Transactional record of every prohibited item confiscated at a Sports Entertainment venue screening checkpoint or during an in-venue security response. Captures item type (prohibited_item reference), confiscation location, confiscating officer, event reference, owner identity (if provided), storage disposition (destroyed, held for retrieval, turned over to law enforcement), and chain-of-custody log. Supports post-event prohibited item trend reporting and policy calibration.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`briefing` (
    `briefing_id` BIGINT COMMENT 'Unique surrogate identifier for the security briefing record. Primary key for the security_briefing data product in the Databricks Silver Layer.',
    `production_id` BIGINT COMMENT 'Foreign key linking to broadcast.production. Business justification: Pre-event security briefings include media credential protocols (media_credential_protocol_briefed_flag exists on security_briefing). Linking to the broadcast production enables security commanders to',
    `contingent_worker_id` BIGINT COMMENT 'Foreign key linking to workforce.contingent_worker. Business justification: Pre-event security briefings are attended by both staff employees and contingent security officers. Tracking contingent worker attendance at briefings is required for SLA compliance with security_cont',
    `emergency_response_plan_id` BIGINT COMMENT 'Reference to the specific versioned emergency response plan reviewed and communicated during this briefing. Ensures traceability to the operative plan version.',
    `employee_id` BIGINT COMMENT 'Reference to the security officer or supervisor who conducted and led the pre-event briefing. Establishes accountability for briefing delivery.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event for which this pre-event security briefing was conducted. Links the briefing to the specific game, concert, or live event.',
    `fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event for which this pre-event security briefing was conducted. Links the briefing to the specific game, concert, or live event.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Pre-game security briefings are organized around franchise home game operations. Franchise linkage enables franchise-level briefing compliance tracking and league-mandated safety protocol audit trails',
    `integrity_alert_id` BIGINT COMMENT 'Foreign key linking to gaming.integrity_alert. Business justification: Pre-event security briefings for fixtures with active integrity alerts must reference the specific alert so briefing officers can communicate threat context (suspicious betting, known fixers) to secur',
    `officer_employee_id` BIGINT COMMENT 'Reference to the security officer or supervisor who conducted and led the pre-event briefing. Establishes accountability for briefing delivery.',
    `venue_id` BIGINT COMMENT 'Reference to the venue at which the briefing and associated event are taking place. Supports venue-level security operations reporting.',
    `updated_briefing_id` BIGINT COMMENT 'Self-referencing FK on briefing (updated_briefing_id)',
    `acknowledgment_sign_off_status` STRING COMMENT 'Status of the formal acknowledgment sign-off process confirming that attendees received and understood the briefing. Partial indicates some but not all attendees have signed off.. Valid values are `pending|partial|complete|waived`',
    `acknowledgment_timestamp` TIMESTAMP COMMENT 'Date and time when the final acknowledgment sign-off was completed, confirming all required attendees acknowledged the briefing content.',
    `ada_protocol_briefed_flag` BOOLEAN COMMENT 'Indicates whether Americans with Disabilities Act accommodation and evacuation assistance protocols were reviewed during the briefing. Required for ADA compliance at all venues.',
    `briefing_status` STRING COMMENT 'Current lifecycle status of the security briefing record. Tracks whether the briefing has been scheduled, is underway, has been completed, or was cancelled/postponed.. Valid values are `scheduled|in_progress|completed|cancelled|postponed`',
    `briefing_timestamp` TIMESTAMP COMMENT 'The precise date and time at which the security briefing commenced. Principal real-world event timestamp for this transaction. Stored in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX).',
    `briefing_type` STRING COMMENT 'Classification of the briefing by operational purpose. Pre-event briefings are the primary type; shift-change and emergency types support ongoing event operations.. Valid values are `pre_event|post_event|shift_change|emergency|tabletop_exercise`',
    `communication_channels_briefed` STRING COMMENT 'Description of radio channels, frequencies, and communication protocols (e.g., command net, tactical net) communicated to security staff during the briefing. Critical for inter-team coordination.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the security briefing record was first created in the system. Audit trail field for data governance and compliance.',
    `crowd_management_protocol` STRING COMMENT 'Identifier or name of the crowd management protocol communicated during the briefing (e.g., Standard GA Protocol, SRO High-Density Protocol). Aligns with venue capacity and event type.',
    `delivery_method` STRING COMMENT 'Method by which the security briefing was delivered to attendees. In-person is standard; virtual and hybrid methods may be used for remote staff or multi-site events.. Valid values are `in_person|virtual|hybrid|recorded`',
    `digital_sign_off_flag` BOOLEAN COMMENT 'Indicates whether the acknowledgment sign-off was captured digitally (True) or via physical paper signature (False). Supports audit trail and records management.',
    `emergency_plan_version` STRING COMMENT 'Version identifier of the emergency response plan referenced and communicated during the briefing (e.g., v2.1). Ensures staff are briefed on the current operative plan version.. Valid values are `^v[0-9]+.[0-9]+$`',
    `end_timestamp` TIMESTAMP COMMENT 'The date and time at which the security briefing concluded. Used to calculate briefing duration and confirm adequate time was allocated for operational directives.',
    `evacuation_routes_reviewed_flag` BOOLEAN COMMENT 'Indicates whether evacuation routes and assembly points were reviewed with attendees during the briefing. True = reviewed; False = not reviewed. Required for ADA and OSHA compliance.',
    `event_day_number` STRING COMMENT 'Day number within a multi-day event or tournament for which this briefing applies (e.g., Day 1 of a 3-day festival). Value is 1 for single-day events.',
    `incident_reporting_protocol_briefed_flag` BOOLEAN COMMENT 'Indicates whether incident reporting procedures, escalation paths, and documentation requirements were communicated during the briefing.',
    `key_directives_summary` STRING COMMENT 'Narrative summary of the primary operational directives, protocols, and instructions issued during the briefing. Captures the substantive content communicated to attendees for compliance documentation.',
    `law_enforcement_agency_name` STRING COMMENT 'Name of the primary law enforcement agency represented at the briefing (e.g., NYPD, FBI Field Office). Supports inter-agency coordination documentation.',
    `law_enforcement_count` STRING COMMENT 'Number of law enforcement liaison officers (police, federal agents, etc.) who attended the briefing. Tracks inter-agency coordination compliance.',
    `law_enforcement_liaison_name` STRING COMMENT 'Name of the designated law enforcement liaison officer present at the briefing. Business-confidential operational contact information for security coordination.',
    `location` STRING COMMENT 'Physical location within the venue where the briefing was held (e.g., Command Center Room 1A, Gate B Staging Area). Supports venue operations coordination.',
    `media_credential_protocol_briefed_flag` BOOLEAN COMMENT 'Indicates whether media credentialing and broadcast zone access protocols were reviewed during the briefing. Supports broadcast operations security coordination.',
    `medical_staff_count` STRING COMMENT 'Number of on-site medical and emergency medical services (EMS) personnel who attended the briefing. Supports emergency response coordination.',
    `post_assignment_count` STRING COMMENT 'Number of distinct security post assignments reviewed during the briefing. Provides a quantitative measure of operational coverage confirmed.',
    `post_assignments_reviewed_flag` BOOLEAN COMMENT 'Indicates whether all security post assignments were reviewed and confirmed with attendees during the briefing. True = post assignments reviewed; False = not reviewed.',
    `prohibited_items_briefed_flag` BOOLEAN COMMENT 'Indicates whether the list of prohibited items and confiscation procedures was reviewed with security staff during the briefing. True = briefed; False = not briefed.',
    `reference_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to this briefing for operational tracking, compliance documentation, and law enforcement coordination. Format: SB-YYYY-NNNNNN.. Valid values are `^SB-[0-9]{4}-[0-9]{6}$`',
    `security_staff_count` STRING COMMENT 'Number of contracted or in-house security staff personnel who attended the briefing. Supports staffing compliance verification.',
    `sign_off_document_reference` STRING COMMENT 'Reference number or URL to the stored acknowledgment sign-off document (physical scan or digital record). Supports compliance audit and records retention.',
    `special_event_considerations` STRING COMMENT 'Free-text field capturing any unique security considerations specific to this event briefing, such as high-profile athlete appearances, political dignitaries, protest activity advisories, or elevated media presence.',
    `supervisor_count` STRING COMMENT 'Number of security supervisors and team leads who attended the briefing. Supervisors are responsible for cascading directives to their respective teams.',
    `threat_level` STRING COMMENT 'Standardized threat level communicated to security staff during the briefing, reflecting intelligence assessments, event profile, and law enforcement advisories. Drives staffing and protocol decisions.. Valid values are `low|moderate|elevated|high|critical`',
    `threat_level_justification` STRING COMMENT 'Narrative explanation of the factors and intelligence inputs that informed the communicated threat level. Provides audit trail for threat assessment decisions.',
    `total_attendee_count` STRING COMMENT 'Total number of individuals who attended the security briefing across all role categories. Quantitative result confirming briefing reach and compliance.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the security briefing record was most recently modified. Supports change tracking, audit trail, and data lineage in the Databricks Silver Layer.',
    `venue_operations_count` STRING COMMENT 'Number of venue operations team members (facility management, event staff) who attended the briefing. Ensures cross-functional awareness of security protocols.',
    `vip_protocol_briefed_flag` BOOLEAN COMMENT 'Indicates whether VIP access protocols, escort procedures, and special handling requirements were communicated during the briefing. True = briefed; False = not briefed.',
    CONSTRAINT pk_briefing PRIMARY KEY(`briefing_id`)
) COMMENT 'Master record for pre-event security briefings conducted with security staff, law enforcement liaisons, and venue operations teams. Captures event reference, briefing date/time, briefing officer, attendee count by role category, threat level communicated, key operational directives issued, post assignments reviewed, emergency plan version referenced, and acknowledgment sign-off status. Ensures documented pre-event security coordination and briefing compliance.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`after_action_report` (
    `after_action_report_id` BIGINT COMMENT 'Unique surrogate identifier for the after-action security report record in the Sports Entertainment lakehouse silver layer.',
    `approving_director_employee_id` BIGINT COMMENT 'Reference to the venue security director who reviewed and signed off on this after-action report.',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: Post-event security after-action reports are submitted to league governing bodies and regulators who cross-reference them with broadcast records. Linking to the broadcast schedule enables correlation ',
    `employee_id` BIGINT COMMENT 'Reference to the security officer or analyst who authored and submitted this after-action report.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event for which this after-action security report was produced.',
    `fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event for which this after-action security report was produced.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: After-action reports are produced per game and must be franchise-attributed for league-mandated safety reporting, insurance underwriting, and franchise safety performance benchmarking required by leag',
    `integrity_alert_id` BIGINT COMMENT 'Foreign key linking to gaming.integrity_alert. Business justification: Post-event after-action reports for fixtures with active integrity concerns must document and reference the gaming integrity alerts that were in play. League governing bodies and regulators require th',
    `kpi_definition_id` BIGINT COMMENT 'Foreign key linking to analytics.kpi_definition. Business justification: Security Performance Reporting process: after-action reports measure structured security KPIs (incidents per 1000 attendees, avg screening wait, response time). Linking to kpi_definition enables leagu',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: After-action reports must be season-tagged for league annual safety compliance submissions, CBA-mandated safety reviews, and multi-season trend analysis required by league operations and governing bod',
    `litigation_case_id` BIGINT COMMENT 'Foreign key linking to legal.litigation_case. Business justification: After-action reports are primary discovery documents in venue security litigation. Legal holds frequently cover AARs; linking them to the litigation case enables privilege review, production tracking,',
    `primary_after_employee_id` BIGINT COMMENT 'Reference to the security officer or analyst who authored and submitted this after-action report.',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: After-action reports for major security events (emergency activations, mass incidents) trigger mandatory regulatory filings to DHS, league governing bodies, and local authorities. The after_action_rep',
    `venue_id` BIGINT COMMENT 'Reference to the venue at which the event was held and this security debrief applies.',
    `revised_after_action_report_id` BIGINT COMMENT 'Self-referencing FK on after_action_report (revised_after_action_report_id)',
    `arrests_made` STRING COMMENT 'Number of individuals arrested by law enforcement during or immediately following the event at the venue.',
    `avg_screening_wait_minutes` DECIMAL(18,2) COMMENT 'Average patron wait time in minutes at security screening checkpoints during peak ingress, used to assess fan experience impact and staffing adequacy.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this after-action report record was first created in the Sports Entertainment lakehouse, supporting audit trail and data lineage requirements.',
    `crowd_management_notes` STRING COMMENT 'Narrative description of crowd management observations, including notable congestion points, flow issues, zone capacity breaches, or exemplary crowd control actions during the event.',
    `crowd_management_rating` STRING COMMENT 'Qualitative rating of overall crowd management performance during the event as assessed by the venue security director, used for continuous improvement tracking.. Valid values are `excellent|satisfactory|needs_improvement|unsatisfactory`',
    `director_signoff_timestamp` TIMESTAMP COMMENT 'Date and time at which the venue security director formally reviewed and signed off on this after-action report, completing the approval lifecycle.',
    `ejection_count` STRING COMMENT 'Total number of patrons formally ejected from the venue during the event for code-of-conduct violations, intoxication, or security threats.',
    `emergency_response_activated` BOOLEAN COMMENT 'Indicates whether the venue emergency response plan (ERP) was formally activated during the event, requiring post-event regulatory documentation.',
    `equipment_failure_notes` STRING COMMENT 'Narrative description of specific equipment failures encountered during the event, including affected systems, duration of outage, and interim mitigation measures applied.',
    `equipment_failures` STRING COMMENT 'Number of security equipment failures (magnetometers, CCTV cameras, access control readers, radio systems) recorded during the event that impacted security operations.',
    `evacuation_activated` BOOLEAN COMMENT 'Indicates whether a full or partial venue evacuation protocol was activated during the event. True triggers mandatory regulatory notification and escalated review.',
    `evacuation_type` STRING COMMENT 'Classification of the evacuation protocol activated during the event. Not applicable when evacuation_activated is False.. Valid values are `full|partial|shelter_in_place|not_applicable`',
    `event_date` DATE COMMENT 'Calendar date on which the Sports Entertainment event occurred, providing temporal context for all security metrics captured in this report.',
    `event_name` STRING COMMENT 'Human-readable name of the Sports Entertainment event (e.g., NBA Finals Game 4, UFC 300) as it appears in scheduling and broadcast systems, denormalized for reporting convenience.',
    `law_enforcement_agency` STRING COMMENT 'Name of the primary law enforcement agency (e.g., LAPD, FBI, State Police) that provided on-site support or was engaged during the event.',
    `law_enforcement_assists` STRING COMMENT 'Number of discrete instances where venue security requested or received assistance from on-site or external law enforcement agencies during the event.',
    `lessons_learned` STRING COMMENT 'Structured narrative capturing key lessons learned from the event security operation, including what worked well, what failed, and actionable improvements for future events.',
    `medical_incidents` STRING COMMENT 'Count of medical emergency incidents requiring first aid, EMS response, or hospital transport during the event. Reported separately per OSHA venue safety requirements.',
    `patrons_screened` STRING COMMENT 'Total number of patrons processed through security screening checkpoints during event ingress, used to calculate screening throughput rate.',
    `peak_ingress_rate_per_hour` STRING COMMENT 'Maximum number of patrons processed through all screening checkpoints in any single hour during the event ingress window, used for capacity planning benchmarking.',
    `physical_altercations` STRING COMMENT 'Count of physical altercations or fights between patrons requiring security intervention during the event.',
    `policy_change_recommendations` STRING COMMENT 'Narrative description of recommended changes to security policies, screening protocols, staffing levels, equipment, or coordination procedures identified through the post-event debrief.',
    `policy_change_recommended` BOOLEAN COMMENT 'Indicates whether the after-action review identified one or more recommended changes to security policy, procedures, or staffing models requiring management review.',
    `prohibited_items_confiscated` STRING COMMENT 'Total number of prohibited items (weapons, contraband, restricted substances) confiscated at screening checkpoints or during the event.',
    `regulatory_notification_required` BOOLEAN COMMENT 'Indicates whether this after-action report triggers a mandatory notification to a regulatory body (e.g., OSHA, local fire marshal, law enforcement agency) based on incident severity thresholds.',
    `report_date` DATE COMMENT 'Calendar date on which the after-action report was formally authored and submitted, typically within 24–72 hours of the event conclusion.',
    `report_number` STRING COMMENT 'Externally-known unique business identifier for this after-action report, formatted as AAR-YYYY-NNNNNN. Used for regulatory filing, law enforcement coordination, and cross-reference with incident management systems.. Valid values are `^AAR-[0-9]{4}-[0-9]{6}$`',
    `report_status` STRING COMMENT 'Current lifecycle state of the after-action report from initial draft through director sign-off and regulatory archival.. Valid values are `draft|under_review|approved|submitted|archived`',
    `report_type` STRING COMMENT 'Classification of the after-action report based on the severity and nature of security events encountered. Major incident and mass casualty types trigger escalated regulatory notification workflows. [ENUM-REF-CANDIDATE: standard|major_incident|mass_casualty|evacuation|law_enforcement_assist — promote to reference product]. Valid values are `standard|major_incident|mass_casualty|evacuation|law_enforcement_assist`',
    `screening_lanes_deployed` STRING COMMENT 'Total number of patron screening lanes (magnetometers, walk-through scanners, wand stations) that were operational during the event ingress period.',
    `security_staff_deployed` STRING COMMENT 'Total number of security personnel (in-house and contracted) deployed across all posts and zones for the event.',
    `source_system` STRING COMMENT 'Name of the operational system of record from which this after-action report data was ingested (e.g., internal security management platform, manual entry portal).',
    `threat_level_assessed` STRING COMMENT 'Security threat level assessed by the venue security director for the event, based on pre-event intelligence, incident activity, and law enforcement advisories.. Valid values are `low|moderate|elevated|high|critical`',
    `total_attendance` STRING COMMENT 'Total number of patrons, staff, and credentialed personnel present at the event, used as the denominator for per-capita security metric calculations.',
    `total_incidents` STRING COMMENT 'Aggregate count of all security incidents recorded during the event across all categories, serving as the primary headline KPI for security performance benchmarking.',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp recording the most recent modification to this after-action report record, used for change tracking and incremental data pipeline processing.',
    CONSTRAINT pk_after_action_report PRIMARY KEY(`after_action_report_id`)
) COMMENT 'Post-event security review and after-action report record capturing the formal security debrief for each Sports Entertainment event. Captures event reference, report author, total incidents by category, ejection count, law enforcement assists, screening throughput statistics, crowd management performance notes, equipment failures, recommended policy changes, and sign-off by venue security director. Feeds continuous improvement of security operations and regulatory compliance documentation.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`security_contract` (
    `security_contract_id` BIGINT COMMENT 'Unique surrogate identifier for the security service contract record. Primary key for the security_contract data product.',
    `approved_by_employee_id` BIGINT COMMENT 'Internal employee identifier for the authorized approver (e.g., VP of Security, Chief Operating Officer) who signed off on this contract. Supports SOX financial controls and procurement audit trails.',
    `audit_engagement_id` BIGINT COMMENT 'Foreign key linking to compliance.audit_engagement. Business justification: Security vendor contracts are subject to compliance audit engagements (vendor due diligence, SLA compliance audits, background check program audits). Compliance teams need to link audit findings direc',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Security contracts are legal agreements executed by a specific legal entity (company code) for tax, liability, and financial reporting purposes. Multi-entity sports entertainment organizations must id',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Security service contracts are financial commitments requiring cost center assignment for budget planning, accruals, and spend allocation. Finance teams in sports entertainment allocate contracted sec',
    `employee_id` BIGINT COMMENT 'Internal employee identifier for the Sports Entertainment security manager or procurement officer who owns and is accountable for this contract. Used for escalation and renewal workflows.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Security contracts are primarily franchise-specific (franchise hires security vendor for home games). Franchise linkage enables franchise-level contract management, cost allocation, vendor performance',
    `insurance_policy_id` BIGINT COMMENT 'Foreign key linking to legal.insurance_policy. Business justification: Security contracts require vendors to maintain specific insurance policies (general liability, workers comp). Risk and legal teams verify vendor insurance compliance by linking the contract to the re',
    `league_id` BIGINT COMMENT 'Foreign key linking to league.league. Business justification: Security contracts may be league-mandated (league-wide vendor agreements) or franchise-specific. Linking security_contract to league enables league-level vendor compliance oversight, contract portfoli',
    `matter_id` BIGINT COMMENT 'Foreign key linking to legal.legal_matter. Business justification: Security vendor contracts generate legal matters for SLA breach disputes, indemnification claims, and vendor termination proceedings. Legal operations teams managing vendor disputes require this link ',
    `primary_security_employee_id` BIGINT COMMENT 'Internal employee identifier for the Sports Entertainment security manager or procurement officer who owns and is accountable for this contract. Used for escalation and renewal workflows.',
    `sla_definition_id` BIGINT COMMENT 'Foreign key linking to partner.sla_definition. Business justification: Security contracts define SLA terms (response time, fill rate) that must reference the canonical SLA definition in the partner domain. This link enables SLA breach tracking via sla_measurement and pen',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to partner.vendor_contract. Business justification: Security contracts are domain-specific specializations of master vendor contracts. Linking security_contract to partner.vendor_contract enables unified contract lifecycle management, AP payment proces',
    `vendor_id` BIGINT COMMENT 'Reference to the private security service provider or guard company in the vendor master. Links to the partner or vendor master record.',
    `venue_id` BIGINT COMMENT 'Reference to the primary venue covered under this security contract. Null for enterprise-wide or multi-venue master service agreements.',
    `renewed_security_contract_id` BIGINT COMMENT 'Self-referencing FK on security_contract (renewed_security_contract_id)',
    `approval_date` DATE COMMENT 'Date on which the contract received final internal approval and was authorized for execution. Distinct from effective_date which is the contractual start date.',
    `armed_services_flag` BOOLEAN COMMENT 'Indicates whether this contract authorizes the deployment of armed security personnel. Triggers additional licensing verification, law enforcement coordination, and regulatory compliance checks.',
    `auto_renewal_flag` BOOLEAN COMMENT 'Indicates whether this contract automatically renews at expiry unless cancelled within the notice period. Drives contract lifecycle management and budget planning workflows.',
    `background_check_required_flag` BOOLEAN COMMENT 'Indicates whether all security personnel deployed under this contract must pass a background check prior to deployment. Supports compliance with venue security protocols and law enforcement coordination requirements.',
    `billing_rate_structure` STRING COMMENT 'The commercial billing model governing how the vendor invoices Sports Entertainment for security services. Hourly and daily rates apply per officer; flat fee and per-event rates apply to the full deployment; retainer is a fixed periodic payment; milestone-based ties payment to deliverables.. Valid values are `hourly|daily|flat_fee|per_event|retainer|milestone`',
    `contract_number` STRING COMMENT 'Externally-known alphanumeric contract reference number used in procurement, legal, and vendor communications. Format: SC-{VENDOR_CODE}-{YEAR}.. Valid values are `^SC-[A-Z0-9]{4,12}-[0-9]{4}$`',
    `contract_status` STRING COMMENT 'Current lifecycle state of the security contract. Draft indicates contract is being authored; pending_approval awaits legal or procurement sign-off; active means contract is in force; suspended indicates temporary hold; expired means the term has lapsed without renewal; terminated indicates early cancellation; renewed indicates a successor contract has been executed. [ENUM-REF-CANDIDATE: draft|pending_approval|active|suspended|expired|terminated|renewed — promote to reference product]',
    `contract_type` STRING COMMENT 'Classification of the contract engagement model. Event-specific contracts cover a single event; annual retainer provides ongoing staffing; master services agreements govern multiple task orders; seasonal covers a defined competition season; emergency standby provides on-call surge capacity; supplemental augments existing staff. [ENUM-REF-CANDIDATE: event_specific|annual_retainer|master_services|seasonal|emergency_standby|supplemental — promote to reference product]. Valid values are `event_specific|annual_retainer|master_services|seasonal|emergency_standby|supplemental`',
    `contract_value` DECIMAL(18,2) COMMENT 'Total maximum monetary value of the security contract over its full term in the contract currency. Used for budget planning, procurement approval thresholds, and financial reporting.',
    `contracted_headcount` STRING COMMENT 'Total number of security personnel contracted to be deployed under this agreement. Used for workforce planning, venue capacity compliance, and SLA monitoring.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this security contract record was first created in the data platform. Supports audit trail and data lineage requirements.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary values on this contract (e.g., USD, GBP, EUR). Supports multi-currency operations across global markets.. Valid values are `^[A-Z]{3}$`',
    `effective_date` DATE COMMENT 'Date on which the security contract becomes legally binding and services may commence. Aligns with the MASTER_AGREEMENT EFFECTIVE_FROM category.',
    `execution_date` DATE COMMENT 'Date on which the contract was formally signed by both parties. May differ from effective_date (when services begin) and approval_date (internal sign-off).',
    `executive_protection_flag` BOOLEAN COMMENT 'Indicates whether this contract includes executive protection (close protection) services for VIP athletes, executives, or dignitaries attending Sports Entertainment events.',
    `expiry_date` DATE COMMENT 'Date on which the security contract term ends and services are no longer authorized under this agreement. Null for open-ended master service agreements. Aligns with the MASTER_AGREEMENT EFFECTIVE_UNTIL category.',
    `governing_law_jurisdiction` STRING COMMENT 'ISO 3166-1 alpha-2 or alpha-3 country/state code identifying the legal jurisdiction whose laws govern this contract and under which disputes are resolved.. Valid values are `^[A-Z]{2,3}$`',
    `insurance_coverage_amount` DECIMAL(18,2) COMMENT 'Minimum insurance coverage amount in the contract currency that the vendor must maintain for general liability and workers compensation. Verified during contract onboarding and annual renewal.',
    `insurance_expiry_date` DATE COMMENT 'Date on which the vendors current insurance certificate expires. Used to trigger renewal reminders and compliance checks. Contract may be suspended if insurance lapses.',
    `insurance_required_flag` BOOLEAN COMMENT 'Indicates whether the vendor is contractually required to maintain specified insurance coverage (general liability, workers compensation, professional indemnity) as a condition of this contract.',
    `k9_services_flag` BOOLEAN COMMENT 'Indicates whether this contract includes K9 (canine) security unit services for explosive detection, crowd deterrence, or perimeter patrol.',
    `law_enforcement_coordination_flag` BOOLEAN COMMENT 'Indicates whether this contract includes provisions for coordinating with local law enforcement agencies during events. Relevant for large-scale events requiring off-duty officer deployment.',
    `minimum_headcount` STRING COMMENT 'Minimum number of security personnel the vendor is contractually obligated to provide at any given deployment. Falling below this threshold constitutes an SLA breach.',
    `overtime_hourly_rate` DECIMAL(18,2) COMMENT 'Contracted billing rate per officer per hour for overtime hours exceeding the standard shift duration. Used for invoice validation and event cost estimation.',
    `payment_terms` STRING COMMENT 'Contractually agreed payment terms governing when invoices from the security vendor must be settled. Aligns with SAP S/4HANA payment terms configuration for accounts payable processing.. Valid values are `net_15|net_30|net_45|net_60|immediate|milestone`',
    `penalty_clause_flag` BOOLEAN COMMENT 'Indicates whether this contract includes financial penalty clauses for SLA breaches, under-staffing, or non-performance. True enables automated penalty calculation workflows.',
    `penalty_rate_pct` DECIMAL(18,2) COMMENT 'Percentage of the invoice value deducted as a financial penalty for each confirmed SLA breach event. Applicable only when penalty_clause_flag is True.',
    `renewal_notice_days` STRING COMMENT 'Number of calendar days prior to expiry_date by which either party must provide written notice of intent not to renew. Applicable when auto_renewal_flag is True.',
    `service_categories` STRING COMMENT 'Pipe-delimited list of primary service category codes covered under this contract (e.g., staffing|k9|crowd_management). Enables multi-category filtering for analytics and procurement reporting. [ENUM-REF-CANDIDATE: staffing|k9|executive_protection|crowd_management|access_control|surveillance|armed_guard|cyber_security|event_security|patrol — promote to reference product]',
    `service_scope` STRING COMMENT 'Narrative description of the security services covered under this contract, including staffing, K9 units, executive protection, crowd management, access control, surveillance monitoring, or other specialized services. Free-text field capturing the full scope of work.',
    `source_system_reference` STRING COMMENT 'The originating system contract identifier (e.g., SAP S/4HANA purchasing contract document number) from which this record was sourced. Enables traceability back to the system of record.',
    `standard_hourly_rate` DECIMAL(18,2) COMMENT 'Contracted standard billing rate per officer per hour in the contract currency. Used for invoice validation and cost forecasting. Applicable when billing_rate_structure is hourly.',
    `termination_date` DATE COMMENT 'Actual date on which the contract was terminated early, if applicable. Null for contracts that run to their natural expiry. Populated when contract_status is terminated.',
    `termination_notice_days` STRING COMMENT 'Number of calendar days of written notice required by either party to terminate the contract for convenience prior to the expiry date.',
    `termination_reason` STRING COMMENT 'Reason code for early contract termination. Populated when contract_status is terminated. Used for vendor performance analytics and procurement lessons-learned reporting.. Valid values are `vendor_breach|mutual_agreement|budget_reduction|vendor_insolvency|regulatory_non_compliance|convenience`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this security contract record was last modified in the data platform. Used for change detection, incremental processing, and audit compliance.',
    `vendor_license_number` STRING COMMENT 'State or jurisdiction-issued private security company license number held by the vendor. Required for regulatory compliance verification prior to contract activation.',
    CONSTRAINT pk_security_contract PRIMARY KEY(`security_contract_id`)
) COMMENT 'Master record for commercial agreements with private security service providers and guard companies engaged by Sports Entertainment for venue and event security operations. Captures vendor reference, contract type (event-specific, annual retainer, master services), service scope (staffing, K9, executive protection, crowd management), contracted headcount, billing rate structure, performance SLA terms, insurance and licensing requirements, and contract status. Distinct from partner.vendor_contract which covers general vendor supply agreements.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`staffing_plan` (
    `staffing_plan_id` BIGINT COMMENT 'Unique surrogate identifier for the security staffing plan record. Primary key for the security_staffing_plan data product in the Silver Layer lakehouse.',
    `approved_by_officer_employee_id` BIGINT COMMENT 'Reference to the security officer or director who granted final approval for this staffing plan. Required for audit trail and accountability under venue safety regulations.',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: Security staffing plans are elevated for major broadcast events (PPV, international). Linking to the broadcast schedule enables budget allocation of security costs against broadcast revenue streams an',
    `budget_id` BIGINT COMMENT 'Reference to the approved security budget record associated with this staffing plan. Links to the financial planning record in SAP S/4HANA CO for cost tracking and variance analysis.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Security staffing costs are allocated to specific cost centers for event budget tracking and financial reporting. Sports entertainment finance teams require structured cost center allocation on staffi',
    `employee_id` BIGINT COMMENT 'Reference to the security officer or director who granted final approval for this staffing plan. Required for audit trail and accountability under venue safety regulations.',
    `event_fixture_id` BIGINT COMMENT 'Reference to the specific event for which this security staffing plan is authored. Drives downstream post_assignment and law_enforcement_deployment records.',
    `fixture_id` BIGINT COMMENT 'Reference to the specific event for which this security staffing plan is authored. Drives downstream post_assignment and law_enforcement_deployment records.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Security staffing plans are built around franchise home game requirements. Franchise linkage supports cost allocation between franchise and league, staffing ratio compliance reporting, and franchise-l',
    `kpi_definition_id` BIGINT COMMENT 'Foreign key linking to analytics.kpi_definition. Business justification: Security Operations KPI Management process: staffing plans are evaluated against approved KPIs (fill rate, staffing ratio, response time SLA). Linking to kpi_definition enables structured performance ',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-level staffing plan aggregation supports league budget planning, CBA player safety compliance reporting, and year-over-year staffing trend analysis required by league operations and governing b',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to partner.purchase_order. Business justification: Security staffing plans drive purchase orders for vendor headcount procurement. Linking the staffing plan to the governing PO enables budget reconciliation, invoice matching, and cost-per-event report',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Security staffing costs are reported against profit centers for event-level P&L and EBITDA analysis. Sports entertainment finance teams allocate security operating expenses to profit centers (e.g., by',
    `security_contract_id` BIGINT COMMENT 'Foreign key linking to security.security_contract. Business justification: A security staffing plan is executed under a formal security contract with a private security vendor. The existing vendor_contract_reference (STRING) is a denormalized text reference to the contract; ',
    `vendor_id` BIGINT COMMENT 'Reference to the primary contracted private security vendor responsible for supplying the majority of the security workforce for this event.',
    `venue_id` BIGINT COMMENT 'Reference to the venue at which the event is hosted. Determines zone layout, post configuration, and applicable venue-specific security protocols.',
    `revised_staffing_plan_id` BIGINT COMMENT 'Self-referencing FK on staffing_plan (revised_staffing_plan_id)',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the staffing plan received final approval from the designated approving authority. Marks the transition from pending_approval to approved status and authorizes vendor and law enforcement deployment.',
    `armed_officer_count` STRING COMMENT 'Number of armed security personnel (private or law enforcement) planned for deployment. Tracked separately for regulatory compliance, insurance requirements, and venue permitting.',
    `cancellation_reason` STRING COMMENT 'Free-text explanation for why the staffing plan was cancelled, if applicable. Required when plan_status transitions to cancelled for audit and post-event review purposes.',
    `command_post_location` STRING COMMENT 'Physical location description of the primary security command post for the event (e.g., Gate A Control Room, Level 2 Operations Center). Used for coordination and incident response routing.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the security staffing plan record was first created in the system. Audit trail field required for data lineage and compliance reporting.',
    `crowd_management_officer_count` STRING COMMENT 'Number of security personnel specifically designated for crowd management duties, including queue management, crowd flow direction, and surge prevention at high-density areas.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the estimated_cost and any monetary fields on this plan (e.g., USD, GBP, EUR). Supports multi-currency operations across global markets.. Valid values are `^[A-Z]{3}$`',
    `emergency_response_plan_reference` STRING COMMENT 'Document reference code or identifier for the emergency response plan (ERP) associated with this staffing plan. Links to the formal ERP document governing evacuation, medical emergency, and active threat protocols.',
    `estimated_cost` DECIMAL(18,2) COMMENT 'Total estimated cost for security staffing for this event, inclusive of private vendor fees, law enforcement reimbursement, and equipment costs. Expressed in the venues operating currency (USD). Used for budget variance analysis in SAP S/4HANA CO.',
    `event_date` DATE COMMENT 'Calendar date on which the event is scheduled to occur. Used for staffing scheduling, shift planning, and law enforcement coordination timelines.',
    `expected_attendance` STRING COMMENT 'Projected total number of attendees for the event, used as the primary input for calculating staffing ratios (e.g., guards per 1,000 attendees) and screening throughput requirements.',
    `k9_handler_count` STRING COMMENT 'Number of K9 (canine) handler teams planned for deployment. K9 units are used for explosive detection, crowd deterrence, and perimeter sweeps at high-security events.',
    `law_enforcement_agency_name` STRING COMMENT 'Name of the primary public law enforcement agency (e.g., Los Angeles Police Department, Metropolitan Police Service) coordinating with venue security for this event.',
    `law_enforcement_confirmed_count` STRING COMMENT 'Number of sworn law enforcement officers confirmed by the relevant public agency as available and committed for this event. May differ from requested count due to agency availability constraints.',
    `law_enforcement_contact_name` STRING COMMENT 'Name of the designated law enforcement point-of-contact for this events security coordination. Business-confidential operational information used for direct coordination.',
    `law_enforcement_liaison_count` STRING COMMENT 'Number of dedicated law enforcement liaison officers embedded within the private security command structure to facilitate real-time coordination between venue security and public law enforcement agencies.',
    `law_enforcement_requested_count` STRING COMMENT 'Total number of sworn law enforcement officers formally requested from public agencies (police, sheriff, state patrol) to supplement private security for this event. Drives law_enforcement_deployment records.',
    `medical_security_liaison_count` STRING COMMENT 'Number of security personnel assigned to coordinate with on-site medical teams, ensuring secure access for emergency medical responders and managing crowd clearance during medical incidents.',
    `plan_number` STRING COMMENT 'Externally-known business identifier for the staffing plan, used in communications with vendors, law enforcement agencies, and venue operations teams. Format: SSP-{YEAR}-{SEQUENCE}.. Valid values are `^SSP-[0-9]{4}-[0-9]{6}$`',
    `plan_status` STRING COMMENT 'Current lifecycle state of the security staffing plan. Drives workflow routing: draft plans are editable; approved plans authorize vendor and law enforcement deployment; active plans are in-force on event day; completed plans are archived post-event.. Valid values are `draft|pending_approval|approved|active|completed|cancelled`',
    `plan_type` STRING COMMENT 'Classification of the staffing plan based on the security threat level and event profile. Elevated and high-security plans trigger additional law enforcement coordination and vendor requirements.. Valid values are `standard|elevated|high_security|special_event|emergency`',
    `plan_version` STRING COMMENT 'Monotonically incrementing version number for the staffing plan. Incremented each time the plan is revised and re-approved, enabling full revision history tracking.',
    `post_guard_count` STRING COMMENT 'Number of security personnel assigned to fixed post positions throughout the venue, including concourse patrols, section guards, and perimeter posts.',
    `pre_event_briefing_scheduled` TIMESTAMP COMMENT 'Scheduled date and time for the mandatory pre-event security briefing where all deployed personnel receive role assignments, threat intelligence updates, and emergency protocol reviews.',
    `radio_channel_law_enforcement` STRING COMMENT 'Radio channel designation used for direct communications between venue security command and deployed law enforcement officers. Separate from the private security channel to maintain operational clarity.',
    `radio_channel_primary` STRING COMMENT 'Primary radio communications channel designation assigned to the security team for this event. Ensures all security personnel operate on a coordinated communications network.',
    `screening_officer_count` STRING COMMENT 'Number of security personnel assigned to entry screening checkpoints, responsible for bag checks, magnetometer operation, and prohibited item detection at venue access points.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this staffing plan record originated or was last updated. Supports data lineage tracking in the Silver Layer lakehouse.. Valid values are `SAP_S4HANA|MANUAL|SECURITY_OPS_PORTAL|WORKDAY`',
    `special_instructions` STRING COMMENT 'Free-text field capturing event-specific security instructions, VIP protection requirements, protest management protocols, or other non-standard directives that supplement the standard operating procedures for this event.',
    `staffing_ratio` DECIMAL(18,2) COMMENT 'Planned ratio of total security personnel to expected attendance (security officers per 1,000 attendees). Used to benchmark against industry standards and regulatory minimums for venue safety compliance.',
    `submitted_timestamp` TIMESTAMP COMMENT 'Date and time when the staffing plan was formally submitted for approval review. Enables SLA tracking for the approval workflow and audit trail compliance.',
    `supervisor_count` STRING COMMENT 'Number of security supervisors planned for the event, responsible for overseeing post guards, managing incident escalations, and coordinating with law enforcement liaisons.',
    `threat_level` STRING COMMENT 'Assessed threat level for the event as determined by the security planning team in consultation with law enforcement intelligence. Drives staffing ratios, K9 deployment, and emergency response posture.. Valid values are `low|moderate|elevated|high|critical`',
    `total_headcount` STRING COMMENT 'Total number of security personnel planned for deployment across all roles for this event. Equals the sum of all role-specific headcount fields and serves as the master workforce count for capacity planning.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when the security staffing plan record was most recently modified. Tracks plan revisions and supports version control alongside plan_version.',
    `vendor_allocated_count` STRING COMMENT 'Number of security personnel formally allocated by the contracted private security vendor for this event. Confirmed by the vendor against the staffing request and used for contract compliance tracking.',
    CONSTRAINT pk_staffing_plan PRIMARY KEY(`staffing_plan_id`)
) COMMENT 'Master record for event-level security staffing plans defining the total security workforce deployment for a specific event. Captures event reference, venue reference, total security headcount by role (screening officers, post guards, supervisors, K9 handlers, law enforcement liaisons), private security vendor allocation, law enforcement requested count, staffing approval status, and budget reference. Serves as the authoritative staffing blueprint used to drive post_assignment and law_enforcement_deployment records.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`footage_camera_scope` (
    `footage_camera_scope_id` BIGINT COMMENT 'Primary key for the footage_camera_scope association',
    `surveillance_camera_id` BIGINT COMMENT 'Foreign key linking to the specific surveillance camera whose footage is in scope for this request.',
    `surveillance_footage_request_id` BIGINT COMMENT 'Foreign key linking to the parent surveillance footage request that this camera scope record belongs to.',
    `camera_ids_requested` STRING COMMENT 'Comma-separated list of surveillance camera identifiers whose footage is being requested. References the physical camera inventory within the venue security system. [Moved from surveillance_footage_request: This comma-separated STRING field is a denormalized multi-valued FK that encodes the M:N relationship in an anti-pattern. It must be decomposed into individual footage_camera_scope records, one per camera per request. The field should be removed from surveillance_footage_request once the association table is populated.]',
    `footage_end_timestamp` TIMESTAMP COMMENT 'End date and time of the footage window requested from this specific camera. May differ per camera within the same request.',
    `footage_file_size_gb` DECIMAL(18,2) COMMENT 'Total size in gigabytes of the footage extracted from this specific camera for this request. Enables per-camera storage and delivery tracking.',
    `footage_format` STRING COMMENT 'Digital file format of the footage extracted from this specific camera. Format may vary per camera depending on the recording system it is connected to.',
    `footage_start_timestamp` TIMESTAMP COMMENT 'Start date and time of the footage window requested from this specific camera. May differ per camera within the same request if the incident scope varies by location.',
    `redaction_completed` BOOLEAN COMMENT 'Indicates whether redaction has been completed for the footage from this specific camera. Supports per-camera fulfillment tracking within a multi-camera request.',
    `redaction_required` BOOLEAN COMMENT 'Indicates whether the footage from this specific camera requires redaction (e.g., blurring of uninvolved individuals) before disclosure. Redaction requirements may differ per camera based on the areas captured.',
    `retrieval_status` STRING COMMENT 'Operational status of footage retrieval for this specific camera within the request. A request may be partially fulfilled if some cameras have been retrieved while others are still pending or failed (e.g., footage overwritten due to retention expiry).',
    CONSTRAINT pk_footage_camera_scope PRIMARY KEY(`footage_camera_scope_id`)
) COMMENT 'This association product represents the scoping event between a surveillance_footage_request and a surveillance_camera. It captures which specific cameras are included in a footage request and the per-camera retrieval details — time window, format, file size, and redaction status — that exist only in the context of a specific request-camera pairing. Each record links one surveillance_footage_request to one surveillance_camera and tracks the operational fulfillment state for that cameras footage within the request.. Existence Justification: In sports entertainment security operations, a single footage request routinely spans multiple cameras (e.g., an incident investigation covering entrance cameras, concourse cameras, and VIP area cameras simultaneously). Conversely, a single camera will be referenced by many different footage requests over time — law enforcement requests, internal investigations, insurance claims. The business actively manages which specific cameras are included in each request, with per-camera attributes such as the footage time window, file size, format, and redaction status that belong to neither the request nor the camera alone.';

